const http = require('http');

const ENDPOINTS = [
    '/api/graviton/metrics',
    '/api/graviton/deficit',
    '/api/graviton/all-products'
];

const BASE_URL = 'http://localhost:3001';

// Add headers to bypass authentication
const OPTIONS = {
    headers: {
        'Cookie': 'bypass_auth=true'
    }
};

async function fetchUrl(path) {
    const start = performance.now();
    return new Promise((resolve) => {
        http.get(BASE_URL + path, OPTIONS, (res) => { // Passed OPTIONS here
            let data = '';
            res.on('data', chunk => data += chunk);
            res.on('end', () => {
                const end = performance.now();
                resolve({
                    path,
                    status: res.statusCode,
                    time: end - start,
                    error: res.statusCode !== 200 ? `Status ${res.statusCode}` : null
                });
            });
        }).on('error', (err) => {
            resolve({ path, status: 'ERROR', time: 0, error: err.message });
        });
    });
}

async function runBenchmark() {
    console.log('🚀 Starting API Benchmark on ' + BASE_URL + ' (Auth Bypassed)');

    // 1. Warmup
    console.log('\n--- Warming up ---');
    for (const ep of ENDPOINTS) await fetchUrl(ep);

    // 2. Latency Test (Sequential)
    console.log('\n--- Sequential Latency Test (Average of 5 runs) ---');
    for (const ep of ENDPOINTS) {
        let totalTime = 0;
        const codes = [];
        for (let i = 0; i < 5; i++) {
            const res = await fetchUrl(ep);
            totalTime += res.time;
            codes.push(res.status);
        }
        const uniqueCodes = [...new Set(codes)];
        console.log(`${ep}: ${(totalTime / 5).toFixed(2)}ms [Status: ${uniqueCodes.join(', ')}]`);
    }

    // 3. Concurrency Test
    console.log('\n--- Concurrency Test (Load Simulation) ---');
    const CONCURRENCY_LEVELS = [10, 50, 100];
    const TARGET_ENDPOINT = '/api/graviton/metrics'; // Most critical

    for (const level of CONCURRENCY_LEVELS) {
        console.log(`\nSimulating ${level} concurrent requests to ${TARGET_ENDPOINT}...`);
        const promises = [];
        const start = performance.now();
        for (let i = 0; i < level; i++) promises.push(fetchUrl(TARGET_ENDPOINT));

        const results = await Promise.all(promises);
        const end = performance.now();
        const totalTime = end - start;

        const success = results.filter(r => r.status === 200).length;
        const failures = results.filter(r => r.status !== 200).length;
        const avgResponse = results.reduce((acc, r) => acc + r.time, 0) / level;

        console.log(`Total Time: ${totalTime.toFixed(2)}ms`);
        console.log(`Throughput: ${(level / (totalTime / 1000)).toFixed(2)} req/sec`);
        console.log(`Avg Request Time: ${avgResponse.toFixed(2)}ms`); // This is client-side perceived time per request
        console.log(`Success: ${success}, Failures: ${failures}`);

        if (failures > 0) {
            const err = results.find(r => r.status !== 200);
            console.log('🔴 Failure Reason (Sample):', err.error);
        }
    }
}

const { performance } = require('perf_hooks');

runBenchmark();

import { NextResponse } from 'next/server';
import { createClient } from '@/utils/supabase/server';
import { requireAuth } from '@/lib/auth-guard';

export async function GET() {
    const auth = await requireAuth();
    if (auth.error) return auth.error;

    try {
        const supabase = await createClient();
        const { data, error } = await supabase
            .from('dashboard_deficit')
            .select('*')
            .order('назва_магазину', { ascending: true })
            .order('category_name', { ascending: true })
            .order('назва_продукту', { ascending: true });

        if (error) {
            console.error('Supabase error:', error);
            return NextResponse.json({ error: error.message }, { status: 500 });
        }

        // Приводимо типи та нормалізуємо дані для фронтенду
        const mappedData = (data || []).map((row) => ({
            ...row,
            priority_label: row.priority_number === 1 ? 'critical' :
                row.priority_number === 2 ? 'high' :
                    row.priority_number === 3 ? 'reserve' : 'normal'
        }));

        return NextResponse.json(mappedData);
    } catch (err: any) {
        console.error('Critical API Error:', err);
        return NextResponse.json({
            error: 'Internal Server Error',
            message: err.message,
            stack: err.stack
        }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { serverAuditLog } from '@/lib/logger.server';
import { createClient } from '@/utils/supabase/server';
import { requireAuth } from '@/lib/auth-guard';

export async function GET(request: NextRequest) {
    const auth = await requireAuth();
    if (auth.error) return auth.error;

    const supabase = await createClient();

    // Логуємо звернення до API
    await serverAuditLog('VIEW_RESERVE_DEFICIT', '/api/graviton/deficit/reserve', request, {
        timestamp: new Date().toISOString()
    });

    const { data, error } = await supabase
        .from('dashboard_deficit')
        .select('*')
        .eq('priority_number', 3)  // Тільки РЕЗЕРВ
        .order('deficit_percent', { ascending: false });

    if (error) {
        console.error('Supabase error:', error);
        await serverAuditLog('ERROR', '/api/graviton/deficit/reserve', request, {
            error: error.message
        });
        return NextResponse.json({ error: error.message }, { status: 500 });
    }

    // Приводимо типи та нормалізуємо дані для фронтенду (Step 95)
    const mappedData = (data || []).map((row: any) => ({
        ...row,
        priority: 'reserve',
        priority_number: 3
    }));

    return NextResponse.json(mappedData);
}

import { createClient } from '@supabase/supabase-js';
import { NextResponse, NextRequest } from 'next/server';
import { requireAuth } from '@/lib/auth-guard';

export const maxDuration = 300; // 5 minutes timeout for Vercel/Next.js

export async function POST(request: NextRequest) {
    const auth = await requireAuth();
    if (auth.error) return auth.error;

    try {
        console.log('[Graviton] Starting distribution calculation...');

        // Initialize Supabase Client with Service Role Key
        // This gives us "admin" privileges and bypasses RLS
        const supabaseAdmin = createClient(
            process.env.NEXT_PUBLIC_SUPABASE_URL!,
            process.env.SUPABASE_SERVICE_ROLE_KEY!,
            {
                auth: {
                    persistSession: false,
                    autoRefreshToken: false,
                    detectSessionInUrl: false
                }
            }
        );

        // Call the RPC function
        // We use the admin client to ensure we have permission and better timeout handling
        const { data, error } = await supabaseAdmin.rpc('fn_run_graviton_calc');

        if (error) {
            console.error('[Graviton] RPC Error:', error);
            return NextResponse.json(
                { error: error.message, details: error },
                { status: 500 }
            );
        }

        console.log('[Graviton] Distribution completed successfully');
        return NextResponse.json({ success: true, message: 'Розподіл успішно завершено' });

    } catch (err: any) {
        console.error('[Graviton] Internal Server Error:', err);
        return NextResponse.json(
            { error: 'Internal Server Error', message: err.message },
            { status: 500 }
        );
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { serverAuditLog } from '@/lib/logger.server';
import { Logger } from '@/lib/logger';
import { createClient } from '@/utils/supabase/server';
import { requireAuth } from '@/lib/auth-guard';

export async function GET(request: NextRequest) {
    const auth = await requireAuth();
    if (auth.error) return auth.error;

    const supabase = await createClient();

    await serverAuditLog('VIEW_METRICS', '/api/graviton/metrics', request, {
        timestamp: new Date().toISOString()
    });

    // ✅ Одна агрегована VIEW замість обробки в Node.js
    const { data, error } = await supabase
        .from('dashboard_metrics')
        .select('*')
        .maybeSingle();

    if (error) {
        Logger.error('Supabase error', { error: error.message, path: '/api/graviton/metrics' });
        return NextResponse.json({ error: error.message }, { status: 500 });
    }

    if (!data) {
        return NextResponse.json({
            totalKg: 0,
            criticalSKU: 0,
            loadPercentage: 0,
            breakdown: {
                critical: 0,
                high: 0,
                reserve: 0
            }
        });
    }

    const totalKg = Number(data?.total_kg) || 0;
    const criticalSKU = Number(data?.critical_sku_count) || 0;
    const highSKU = Number(data?.high_sku_count) || 0;
    const loadPercentage = totalKg
        ? Math.min(100, Math.round((totalKg / 662) * 100))
        : 0;

    return NextResponse.json({
        shopLoad: Number(data?.total_kg) || 0,
        criticalSKU: Number(data?.critical_sku_count) || 0,
        highSKU: Number(data?.high_sku_count) || 0,
        reserveSKU: Number(data?.reserve_sku_count) || 0,
        criticalWeight: Number(data?.critical_kg) || 0,
        highWeight: Number(data?.high_kg) || 0,
        reserveWeight: Number(data?.reserve_kg) || 0,
        totalSKU: Number(data?.total_sku_count) || 0,
        loadPercentage: Math.min(100, Math.round((Number(data?.total_kg || 0) / 662) * 100)),
        staffCount: 0,
        aiEfficiency: 98,
        lastUpdate: new Date().toISOString(),
        breakdown: {
            critical: Number(data?.critical_kg) || 0,
            high: Number(data?.high_kg) || 0,
            reserve: Number(data?.reserve_kg) || 0
        }
    });
}

import { NextResponse } from 'next/server';
import { supabase } from '@/lib/supabase';
import { Logger } from '@/lib/logger';
import { requireAuth } from '@/lib/auth-guard';

export const dynamic = 'force-dynamic';

export async function GET() {
    const auth = await requireAuth();
    if (auth.error) return auth.error;

    try {
        // 1. KPI Data - Fetch from public.v_pub_analytics (expecting single row)
        const { data: kpi, error: kpiError } = await supabase
            .from('v_pub_analytics')
            .select('*')
            .select('*')
            .maybeSingle();

        if (kpiError) throw kpiError;

        // 2. Radar Data - Fetch from public.v_pub_radar for Critical Count and Top 5
        const { data: radar, error: radarError } = await supabase
            .from('v_pub_radar')
            .select('*');

        if (radarError) throw radarError;

        // --- CALCULATIONS ---

        // KPI values from v_pub_analytics
        // Expected columns: current_stock, total_need, total_target, fill_level
        const currentStock = Number(kpi?.current_stock) || 0;
        const totalNeed = Number(kpi?.total_need) || 0;     // Should be 423
        const totalTarget = Number(kpi?.total_target) || 0; // Should be 633

        // fill_level might be a string or number in view
        const fillLevelRaw = Number(kpi?.fill_level) || 0;
        const fillLevel = fillLevelRaw.toFixed(1);

        // KPI 3 Logic: Count items where shop_stock <= 0 from radar data
        const criticalPositions = radar?.filter((item: any) => (Number(item.shop_stock) || 0) <= 0).length || 0;

        // Top 5 Logic: Sort radar by risk_index desc and take top 5
        const top5 = radar
            ?.sort((a: any, b: any) => (b.risk_index || 0) - (a.risk_index || 0))
            .slice(0, 5)
            .map((item: any) => ({
                pizza_name: item.pizza_name,
                shop_stock: item.shop_stock,
                risk_index: item.risk_index
            })) || [];

        return NextResponse.json({
            kpi: {
                currentStock,
                totalNeed,
                totalTarget,
                criticalPositions, // Kept in data structure just in case, though UI might use totalTarget
                fillLevel
            },
            top5
        });

    } catch (error) {
        Logger.error('[Analytics API] Error', { error: String(error), path: '/api/pizza/analytics' });
        return NextResponse.json({ error: String(error) }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { supabase } from '@/lib/supabase';
import { requireAuth } from '@/lib/auth-guard';

interface DistributionRequest {
    productId: number;
    productionQuantity: number;
}

interface StoreStats {
    // New View Structure Mappings
    spot_id: number;      // Was store_id
    spot_name: string;    // Was store_name
    stock_now: number;    // Was current_stock
    norm_3_days: number;  // Was min_stock
    need_net: number;     // Was net_need
    priority: number;     // Was surplus_priority

    // Legacy support (optional, if view changes back)
    store_id?: number;
    current_stock?: number;
    min_stock?: number;
}

/**
 * POST /api/pizza/calculate-distribution
 * Calculates distribution plan based on 4-stage algorithm
 */
export async function POST(request: NextRequest) {
    const auth = await requireAuth();
    if (auth.error) return auth.error;

    try {
        const body: DistributionRequest = await request.json();
        const { productId, productionQuantity } = body;

        // Fetch stats for this product
        const { data: stores, error } = await supabase
            .from('v_pizza_distribution_stats')
            .select('*')
            .eq('product_id', productId);

        if (error || !stores) {
            throw new Error(error?.message || 'Failed to fetch distribution stats');
        }

        // Initialize result map
        const result: Record<number, number> = {};
        let remaining = productionQuantity;
        const storesData = stores as any[]; // Use any to be flexible with column names

        // Helper to accessor
        const getId = (s: any) => s.spot_id || s.store_id || 0;
        const getStock = (s: any) => Number(s.stock_now ?? s.current_stock ?? 0);
        const getMin = (s: any) => Number(s.norm_3_days ?? s.min_stock ?? 0);
        const getNeed = (s: any) => Number(s.need_net ?? s.net_need ?? 0);
        const getPriority = (s: any) => s.priority ?? s.surplus_priority ?? 999;

        // Initialize distribution for all stores to 0
        storesData.forEach(s => {
            const id = getId(s);
            if (id) result[id] = 0;
        });

        // --- STAGE 2: "Hygiene" (Fill Zeros) ---
        // Give 1 unit to stores with 0 stock
        const zeroStockStores = storesData.filter(s => getStock(s) === 0);
        for (const store of zeroStockStores) {
            if (remaining > 0) {
                const id = getId(store);
                if (id) {
                    result[id] += 1;
                    remaining -= 1;
                }
            }
        }

        // --- STAGE 3: Proportional Deficit ---
        if (remaining > 0) {
            let totalNetNeed = 0;
            const storeNeeds: { storeId: number; need: number }[] = [];

            storesData.forEach(s => {
                const id = getId(s);
                if (!id) return;

                const distributedSoFar = result[id];
                const effectiveStock = getStock(s) + distributedSoFar;
                // Recalculate need based on effective stock
                // If effective stock >= min (norm), need is 0
                // Otherwise need is min - effective

                // NOTE: logic was: if need_net > 0...
                // But need_net from view is static. We must account for Stage 2 distribution.
                const min = getMin(s);
                const need = Math.max(0, min - effectiveStock);

                if (need > 0) {
                    storeNeeds.push({ storeId: id, need });
                    totalNetNeed += need;
                }
            });

            if (totalNetNeed > 0) {
                if (remaining < totalNetNeed) {
                    // DEFICIT MODE: Proportional distribution
                    const K = remaining / totalNetNeed;

                    for (const item of storeNeeds) {
                        const qty = Math.floor(item.need * K);
                        if (qty > 0 && remaining >= qty) {
                            result[item.storeId] += qty;
                            remaining -= qty;
                        }
                    }
                } else {
                    // SURPLUS/ENOUGH MODE: Fill all needs to 100%
                    for (const item of storeNeeds) {
                        if (remaining >= item.need) {
                            result[item.storeId] += item.need;
                            remaining -= item.need;
                        } else {
                            // Should not happen if remaining >= totalNetNeed, but safety check
                            result[item.storeId] += remaining;
                            remaining = 0;
                        }
                    }
                }
            }
        }

        // --- STAGE 4: Surplus Distribution ---
        // If still remaining, distribute by priority
        if (remaining > 0) {
            const sortedByPriority = [...storesData].sort((a, b) => {
                const pA = getPriority(a);
                const pB = getPriority(b);
                return pA - pB;
            });

            while (remaining > 0) {
                let distributedInLoop = false;
                for (const store of sortedByPriority) {
                    if (remaining <= 0) break;
                    const id = getId(store);
                    if (id) {
                        result[id] += 1;
                        remaining -= 1;
                        distributedInLoop = true;
                    }
                }
                if (!distributedInLoop) break;
            }
        }

        return NextResponse.json({
            productId,
            originalQuantity: productionQuantity,
            distributed: result,
            remaining // Should be 0
        });

    } catch (error) {
        console.error('[Calculate Distribution] Error:', error);
        return NextResponse.json({ error: String(error) }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { supabase } from '@/lib/supabase';
import { requireAuth } from '@/lib/auth-guard';

interface DistributionConfirmation {
    distributions: Array<{
        storeId: number;
        productId: number;
        quantity: number;
    }>;
    userId?: string; // Optional for logging current user
}

// Fixed Warehouse ID for "Цех Пиццерия Гравитон"
const SOURCE_WAREHOUSE_ID = 15;

/**
 * POST /api/pizza/confirm-distribution
 * Executing distribution: creates movement documents in DB
 */
export async function POST(request: NextRequest) {
    const auth = await requireAuth();
    if (auth.error) return auth.error;

    try {
        const body: DistributionConfirmation = await request.json();
        const { distributions, userId } = body;

        if (!distributions || distributions.length === 0) {
            return NextResponse.json({ success: true, message: 'No distributions to process' });
        }

        const results = [];
        const errors = [];

        // In a real app, we might want to batch this or use a stored procedure / transaction.
        // For now, we'll process sequentially or in parallel batches.

        // We need mapping from storeId (spot_id) to storage_id (warehouse)
        // This mapping might come from `v_pizza_distribution_stats` or separate query.
        // Let's assume passed storeId IS the target storage_id or we fetch it.
        // Looking at context, usually specific stores have specific storage IDs.
        // TЗ says: "Accordig to mapping in view (spot_id -> storage_id)"

        // Let's fetch the mapping first to be safe
        const { data: mapping, error: mapError } = await supabase
            .from('v_pizza_distribution_stats')
            .select('store_id, storage_id') // Assuming view has storage_id
        // If view doesn't have storage_id, we might need another table (e.g. shops)
        // Let's check typical structure or just assume store_id passed from FE is correct ID to move TO.
        // Wait, TЗ explicitly mentions "mapping from view (spot_id -> storage_id)".
        // I'll query unique store mapping.

        if (mapError) {
            throw new Error('Failed to fetch storage mapping');
        }

        const storeToStorageMap = new Map<number, number>();
        mapping?.forEach((row: any) => {
            if (row.store_id && row.storage_id) {
                storeToStorageMap.set(row.store_id, row.storage_id);
            }
        });

        for (const dist of distributions) {
            const { storeId, productId, quantity } = dist;

            if (quantity <= 0) continue;

            const targetStorageId = storeToStorageMap.get(storeId);

            if (!targetStorageId) {
                errors.push(`No storage mapping for store ${storeId}`);
                continue;
            }

            // Create movement
            // NOTE: Table name and structure is assumed based on standard patterns (movements / operations)
            // I will use a generic 'movements' table structure, but this might need adjustment if schema differs.
            // "Система должна генерировать документы перемещения (movements)"

            const { data, error } = await supabase
                .from('movements')
                .insert({
                    source_storage_id: SOURCE_WAREHOUSE_ID,
                    target_storage_id: targetStorageId,
                    product_id: productId,
                    quantity: quantity,
                    status: 'pending', // or 'completed'
                    created_by: userId || 'system',
                    created_at: new Date().toISOString(),
                    type: 'distribution'
                })
                .select();

            if (error) {
                errors.push(`Failed to move product ${productId} to store ${storeId}: ${error.message}`);
            } else {
                results.push(data);
            }
        }

        if (errors.length > 0) {
            return NextResponse.json({
                success: false,
                message: 'Some distributions failed',
                errors,
                results
            }, { status: 207 }); // Multi-Status
        }

        return NextResponse.json({
            success: true,
            message: 'Distribution confirmed and movements created',
            count: results.length
        });

    } catch (error) {
        console.error('[Confirm Distribution] Error:', error);
        return NextResponse.json({ error: String(error) }, { status: 500 });
    }
}

