'use client';

import React, { useState, useMemo, useEffect } from 'react';
import { Trash2, Edit2, Package, ChevronDown, ChevronRight } from 'lucide-react';
import { OrderItem } from '@/types/order';
import { SKUCategory } from '@/types/bi';
import { cn } from '@/lib/utils';
import { Modal, ModalHeader, ModalBody, ModalFooter, ModalButton } from '@/components/ui/Modal';

interface OrderConfirmationModalProps {
    isOpen: boolean;
    items: OrderItem[];
    onClose: () => void;
    onConfirm: (items: OrderItem[]) => void;
}

const CATEGORY_EMOJI: Record<string, string> = {
    'ВАРЕНИКИ': '🥟',
    'ПЕЛЬМЕНІ': '🥢',
    'ХІНКАЛІ': '🥡',
    'ЧЕБУРЕКИ': '🌯',
    'КОВБАСКИ': '🌭',
    'ГОЛУБЦІ': '🥬',
    'КОТЛЕТИ': '🥩',
    'СИРНИКИ': '🥞',
    'ФРИКАДЕЛЬКИ': '🧆',
    'ЗРАЗИ': '🥔',
    'ПЕРЕЦЬ ФАРШИРОВАНИЙ': '🫑',
    'МЛИНЦІ': '🥞',
    'БЕНДЕРИКИ': '🌮'
};

const getEmoji = (category: string) => CATEGORY_EMOJI[category] || '📦';

export const OrderConfirmationModal = ({ isOpen, items, onClose, onConfirm }: OrderConfirmationModalProps) => {
    const [editedItems, setEditedItems] = useState<OrderItem[]>(items);
    const [editingId, setEditingId] = useState<string | null>(null);
    const [expandedCategories, setExpandedCategories] = useState<Set<SKUCategory>>(new Set());

    // Sync editedItems when items prop changes and filter out zero quantities
    useEffect(() => {
        const filtered = items.filter(item => item.quantity > 0);
        setEditedItems(filtered);

        // Auto-expand all initially
        const allCats = new Set(filtered.map(i => i.category));
        setExpandedCategories(allCats);
    }, [items]);

    const toggleAllCategories = () => {
        if (expandedCategories.size > 0) {
            setExpandedCategories(new Set());
        } else {
            const allCats = new Set(groupedItems.map(g => g.category));
            setExpandedCategories(allCats);
        }
    };

    const toggleCategory = (category: SKUCategory) => {
        setExpandedCategories(prev => {
            const next = new Set(prev);
            if (next.has(category)) next.delete(category);
            else next.add(category);
            return next;
        });
    };

    // Group by category
    const groupedItems = useMemo(() => {
        const groups = new Map<SKUCategory, OrderItem[]>();

        // Only include items with quantity > 0
        editedItems.filter(item => item.quantity > 0).forEach(item => {
            if (!groups.has(item.category)) {
                groups.set(item.category, []);
            }
            groups.get(item.category)!.push(item);
        });

        return Array.from(groups.entries()).map(([category, items]) => ({
            category,
            emoji: getEmoji(category),
            totalWeight: items.reduce((sum, item) => sum + item.quantity, 0),
            items: items.sort((a, b) => a.productName.localeCompare(b.productName))
        }));
    }, [editedItems]);

    const totalWeight = useMemo(() => {
        return editedItems.reduce((sum, item) => sum + item.quantity, 0);
    }, [editedItems]);

    const handleQuantityChange = (itemId: string, newQuantity: number) => {
        if (newQuantity <= 0) return;

        setEditedItems(prev =>
            prev.map(item =>
                item.id === itemId ? { ...item, quantity: newQuantity, kg: newQuantity } : item
            )
        );
    };

    const handleRemoveItem = (itemId: string) => {
        setEditedItems(prev => prev.filter(item => item.id !== itemId));
    };

    const handleConfirm = () => {
        if (editedItems.length === 0) {
            alert('Замовлення порожнє!');
            return;
        }
        onConfirm(editedItems);
    };

    return (
        <Modal isOpen={isOpen} onClose={onClose} size="xl" showCloseButton={false}>
            {/* Header */}
            <ModalHeader icon={<Package size={20} />}>
                <div className="flex items-center justify-between">
                    <div>
                        <h2 className="text-[14px] font-black uppercase tracking-[0.08em] text-white">
                            Попередній перегляд замовлення
                        </h2>
                        <div className="flex items-center gap-5 mt-2">
                            <div className="flex items-center gap-2">
                                <span className="text-[9px] text-white/30 uppercase font-bold tracking-widest">
                                    Вага:
                                </span>
                                <span className="text-[14px] font-black text-[#00D4FF]">
                                    {totalWeight.toFixed(1)} кг
                                </span>
                            </div>
                            <div className="h-4 w-[1px] bg-white/10" />
                            <div className="flex items-center gap-2">
                                <span className="text-[9px] text-white/30 uppercase font-bold tracking-widest">
                                    Позицій:
                                </span>
                                <span className="text-[12px] font-bold text-white/90">
                                    {editedItems.length}
                                </span>
                            </div>
                        </div>
                    </div>
                    <button
                        onClick={toggleAllCategories}
                        className="px-3 py-1.5 text-[9px] font-bold text-white/50 hover:text-white bg-white/5 hover:bg-white/10 rounded-lg border border-white/5 hover:border-white/10 transition-all"
                    >
                        {expandedCategories.size > 0 ? 'ЗГОРНУТИ ВСЕ' : 'РОЗГОРНУТИ ВСЕ'}
                    </button>
                </div>
            </ModalHeader>

            {/* Content */}
            <ModalBody className="space-y-3 bg-[#0A0E14]">
                {groupedItems.length === 0 ? (
                    <div className="text-center py-16 text-white/40">
                        <Package size={48} className="mx-auto mb-4 opacity-30" />
                        <p className="text-[14px] font-semibold">Замовлення порожнє</p>
                        <p className="text-[12px] mt-2 opacity-60">Додайте товари до замовлення</p>
                    </div>
                ) : (
                    groupedItems.map(group => (
                        <div
                            key={group.category}
                            className="bg-white/[0.02] rounded-xl border border-white/5 overflow-hidden hover:border-white/10 transition-colors"
                        >
                            {/* Category Header */}
                            <div
                                className="px-4 py-3 bg-white/[0.02] border-b border-white/5 cursor-pointer hover:bg-white/[0.04] transition-colors group"
                                onClick={() => toggleCategory(group.category)}
                            >
                                <div className="flex items-center justify-between">
                                    <div className="flex items-center gap-3">
                                        <div className="text-white/30 group-hover:text-white/50 transition-colors">
                                            {expandedCategories.has(group.category) ? (
                                                <ChevronDown size={14} />
                                            ) : (
                                                <ChevronRight size={14} />
                                            )}
                                        </div>
                                        <span className="text-[18px]">{group.emoji}</span>
                                        <span className="text-[13px] font-black uppercase text-white/90">
                                            {group.category}
                                        </span>
                                        <span className="text-[10px] text-white/30 font-medium">
                                            ({group.items.length})
                                        </span>
                                    </div>
                                    <span className="text-[14px] font-black text-[#00D4FF]">
                                        {group.totalWeight.toFixed(1)} кг
                                    </span>
                                </div>
                            </div>

                            {/* Items */}
                            {expandedCategories.has(group.category) && (
                                <div className="divide-y divide-white/[0.03]">
                                    {group.items.map(item => (
                                        <div
                                            key={item.id}
                                            className="px-4 py-3 hover:bg-white/[0.02] transition-colors group/item"
                                        >
                                            <div className="flex items-center justify-between gap-4">
                                                {/* Product Info */}
                                                <div className="flex-1 min-w-0">
                                                    <div className="text-[12px] font-bold text-white/80 truncate group-hover/item:text-white transition-colors">
                                                        {item.productName}
                                                    </div>
                                                    <div className="text-[10px] text-white/30 mt-0.5">
                                                        🏪 {item.storeName}
                                                    </div>
                                                </div>

                                                {/* Quantity Editor */}
                                                <div className="flex items-center gap-2">
                                                    {editingId === item.id ? (
                                                        <input
                                                            type="number"
                                                            min="0.1"
                                                            step="0.5"
                                                            value={item.quantity}
                                                            onChange={(e) => handleQuantityChange(item.id, parseFloat(e.target.value))}
                                                            onBlur={() => setEditingId(null)}
                                                            onKeyDown={(e) => e.key === 'Enter' && setEditingId(null)}
                                                            className="w-20 px-2 py-1.5 bg-black/50 border border-[#00D4FF] rounded-lg text-[12px] font-black text-[#00D4FF] text-center focus:outline-none focus:ring-2 focus:ring-[#00D4FF]/30"
                                                            autoFocus
                                                        />
                                                    ) : (
                                                        <button
                                                            onClick={() => setEditingId(item.id)}
                                                            className="flex items-center gap-2 px-3 py-1.5 bg-white/5 border border-white/10 rounded-lg hover:border-[#00D4FF]/50 hover:bg-[#00D4FF]/5 transition-all group/btn"
                                                        >
                                                            <span className="text-[13px] font-black text-[#00D4FF]">
                                                                {item.quantity.toFixed(1)}
                                                            </span>
                                                            <Edit2 size={12} className="text-white/20 group-hover/btn:text-[#00D4FF]/50 transition-colors" />
                                                        </button>
                                                    )}

                                                    <button
                                                        onClick={() => handleRemoveItem(item.id)}
                                                        className="p-2 text-white/20 hover:text-[#EF4444] hover:bg-[#EF4444]/10 rounded-lg transition-all"
                                                        title="Видалити"
                                                    >
                                                        <Trash2 size={14} />
                                                    </button>
                                                </div>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    ))
                )}
            </ModalBody>

            {/* Footer */}
            <ModalFooter>
                <div className="flex items-center justify-between gap-4">
                    <ModalButton variant="secondary" onClick={onClose}>
                        Назад
                    </ModalButton>

                    <ModalButton
                        variant="primary"
                        onClick={handleConfirm}
                        disabled={editedItems.length === 0}
                    >
                        Підтвердити та поділитися
                    </ModalButton>
                </div>
            </ModalFooter>
        </Modal>
    );
};

'use client';

import React, { useState } from 'react';
import { ChevronDown, ChevronRight, Users, Crown, User, Snowflake } from 'lucide-react';
import { SHIFTS, PRODUCTION_NORM_PER_PERSON, getShiftCapacity, getCurrentShift, Shift, Employee } from '@/lib/personnel';
import { cn } from '@/lib/utils';

interface Props {
    className?: string;
    isActive?: boolean;
    onSelect?: () => void;
}

const getPositionIcon = (position: Employee['position']) => {
    switch (position) {
        case 'Старший смени':
            return <Crown size={12} className="text-[#FFD700]" />;
        case 'Шокер':
            return <Snowflake size={12} className="text-[#00BCF2]" />;
        default:
            return <User size={12} className="text-gray-400" />;
    }
};

export const PersonnelCard = ({ className, isActive = false, onSelect }: Props) => {
    const [isExpanded, setIsExpanded] = useState(false);
    const [expandedShift, setExpandedShift] = useState<number | null>(null);

    const currentShift = getCurrentShift();
    const totalCapacity = SHIFTS.reduce((sum, s) => sum + getShiftCapacity(s), 0);
    const totalEmployees = SHIFTS.reduce((sum, s) => sum + s.employees.length, 0);

    const toggleShift = (shiftId: number, e: React.MouseEvent) => {
        e.stopPropagation();
        setExpandedShift(prev => prev === shiftId ? null : shiftId);
    };

    return (
        <div className={cn("", className)}>
            {/* Main Personnel Button - like store button */}
            <button
                onClick={() => {
                    onSelect?.();
                    setIsExpanded(!isExpanded);
                }}
                className={cn(
                    "w-full px-4 py-3.5 text-left rounded-xl transition-all duration-300 relative overflow-hidden group",
                    (isExpanded || isActive) && "scale-[1.02]"
                )}
                style={{
                    background: (isExpanded || isActive)
                        ? 'rgba(0, 212, 255, 0.1)'
                        : 'rgba(20, 27, 45, 0.7)',
                    backdropFilter: 'blur(20px)',
                    WebkitBackdropFilter: 'blur(20px)',
                    border: (isExpanded || isActive)
                        ? '1px solid rgba(0, 212, 255, 0.5)'
                        : '1px solid rgba(255, 255, 255, 0.08)',
                    boxShadow: (isExpanded || isActive)
                        ? '0 0 30px rgba(0, 212, 255, 0.3), 0 8px 32px rgba(0, 0, 0, 0.4), inset 0 1px 0 rgba(255, 255, 255, 0.1)'
                        : '0 4px 16px rgba(0, 0, 0, 0.2)',
                }}
            >
                {/* Shimmer effect on hover */}
                <div
                    className={cn(
                        "absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full transition-transform duration-700 group-hover:translate-x-full"
                    )}
                />

                {/* Active glow indicator */}
                {(isExpanded || isActive) && (
                    <div
                        className="absolute left-0 top-1/2 -translate-y-1/2 w-1 h-8 rounded-r-full"
                        style={{
                            background: 'linear-gradient(180deg, #00D4FF 0%, #0088FF 100%)',
                            boxShadow: '0 0 12px rgba(0, 212, 255, 0.8)',
                        }}
                    />
                )}

                <div className="flex items-center justify-between relative z-10">
                    <div className="flex items-center gap-3">
                        <div
                            className="w-8 h-8 rounded-lg flex items-center justify-center"
                            style={{
                                background: 'linear-gradient(135deg, #00D4FF 0%, #0088FF 100%)',
                                boxShadow: '0 0 12px rgba(0, 212, 255, 0.4)',
                            }}
                        >
                            <Users size={16} className="text-white" />
                        </div>
                        <div>
                            <span
                                className={cn(
                                    "text-[12px] font-semibold uppercase tracking-wide transition-all duration-300",
                                    (isExpanded || isActive) ? "text-[#00D4FF]" : "text-gray-400"
                                )}
                            >
                                Персонал
                            </span>
                            <div className="text-[9px] text-gray-500">
                                {totalEmployees} осіб • ~{totalCapacity} кг/день
                            </div>
                        </div>
                    </div>
                    {isExpanded ?
                        <ChevronDown size={16} className="text-[#00D4FF]" /> :
                        <ChevronRight size={16} className="text-gray-400" />
                    }
                </div>
            </button>

            {/* Expanded: Shifts (like categories) */}
            {isExpanded && (
                <div className="mt-2 space-y-1.5 ml-2">
                    {SHIFTS.map((shift) => {
                        const isShiftExpanded = expandedShift === shift.id;
                        const isCurrent = currentShift?.id === shift.id;
                        const capacity = getShiftCapacity(shift);

                        return (
                            <div key={shift.id}>
                                {/* Shift row (like category row) */}
                                <button
                                    onClick={(e) => toggleShift(shift.id, e)}
                                    className="w-full px-4 py-2.5 rounded-lg hover:bg-[#2a2f4a] flex items-center justify-between transition-all duration-200"
                                    style={{
                                        background: isShiftExpanded ? 'rgba(42, 47, 74, 0.8)' : 'transparent',
                                    }}
                                >
                                    <div className="flex items-center gap-2">
                                        {isShiftExpanded ?
                                            <ChevronDown size={14} className="text-[var(--text-muted)]" /> :
                                            <ChevronRight size={14} className="text-[var(--text-muted)]" />
                                        }
                                        <span className="text-[11px] font-bold text-[var(--foreground)]">
                                            {shift.name}
                                        </span>
                                        {isCurrent && (
                                            <span className="px-1.5 py-0.5 rounded text-[7px] font-bold bg-[#00D4FF]/20 text-[#00D4FF] uppercase">
                                                Зараз
                                            </span>
                                        )}
                                        <span className="text-[9px] text-[var(--text-muted)]">
                                            ({shift.employees.length} осіб)
                                        </span>
                                    </div>
                                    <span className="text-[11px] font-bold text-[#52E8FF]">
                                        ~{capacity} кг
                                    </span>
                                </button>

                                {/* Employees (like products) */}
                                {isShiftExpanded && (
                                    <div className="ml-6 mt-1 space-y-0.5 border-l border-[var(--border)]/30 pl-3">
                                        {shift.employees.map((employee) => (
                                            <div
                                                key={employee.id}
                                                className="px-3 py-1.5 rounded-md flex items-center justify-between hover:bg-white/[0.02] transition-colors"
                                            >
                                                <div className="flex items-center gap-2">
                                                    {getPositionIcon(employee.position)}
                                                    <span className={cn(
                                                        "text-[10px]",
                                                        employee.isLeader ? "font-bold text-[#FFD700]" : "text-gray-300"
                                                    )}>
                                                        {employee.name}
                                                    </span>
                                                </div>
                                                <span className="text-[8px] text-gray-500 uppercase">
                                                    {employee.position === 'Старший смени' ? '👑' :
                                                        employee.position === 'Шокер' ? '🧊' : ''}
                                                </span>
                                            </div>
                                        ))}

                                        {/* Shift summary */}
                                        <div className="mt-2 pt-2 border-t border-white/5 px-3">
                                            <div className="flex items-center justify-between text-[9px]">
                                                <span className="text-gray-500">Старша: {shift.leader}</span>
                                                <span className="text-[#00D4FF] font-bold">
                                                    {PRODUCTION_NORM_PER_PERSON} кг/особа
                                                </span>
                                            </div>
                                        </div>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            )}
        </div>
    );
};

'use client';

import React, { useState, useMemo, useEffect } from 'react';
import { ChevronDown, ChevronRight, Users, Crown, User, Snowflake, Check, X, AlertCircle } from 'lucide-react';
import { SHIFTS, PRODUCTION_NORM_PER_PERSON, Shift, Employee } from '@/lib/personnel';
import { cn } from '@/lib/utils';
import { useStore } from '@/context/StoreContext';

// Attendance status types
type AttendanceStatus = 'present' | 'absent' | 'sick';

interface EmployeeAttendance {
    employeeId: number;
    status: AttendanceStatus;
}

interface ShiftAttendance {
    shiftId: number;
    employees: EmployeeAttendance[];
}

const getPositionIcon = (position: Employee['position']) => {
    switch (position) {
        case 'Старший смени':
            return <Crown size={14} className="text-[#FFD700]" />;
        case 'Шокер':
            return <Snowflake size={14} className="text-[#00BCF2]" />;
        default:
            return <User size={14} className="text-gray-400" />;
    }
};

const getStatusColor = (status: AttendanceStatus) => {
    switch (status) {
        case 'present':
            return { bg: 'rgba(52, 211, 153, 0.2)', border: '#34D399', text: '#34D399' };
        case 'absent':
            return { bg: 'rgba(239, 68, 68, 0.2)', border: '#EF4444', text: '#EF4444' };
        case 'sick':
            return { bg: 'rgba(251, 191, 36, 0.2)', border: '#FBBF24', text: '#FBBF24' };
    }
};

const getStatusIcon = (status: AttendanceStatus) => {
    switch (status) {
        case 'present':
            return <Check size={12} className="text-[#34D399]" />;
        case 'absent':
            return <X size={12} className="text-[#EF4444]" />;
        case 'sick':
            return <AlertCircle size={12} className="text-[#FBBF24]" />;
    }
};

const getStatusLabel = (status: AttendanceStatus) => {
    switch (status) {
        case 'present':
            return 'На місці';
        case 'absent':
            return 'Відсутній';
        case 'sick':
            return 'Хворий';
    }
};

export const PersonnelView = () => {
    const { setCurrentCapacity } = useStore();

    // Active shift (1, 2, or null if not selected)
    const [activeShiftId, setActiveShiftId] = useState<1 | 2 | null>(null);

    // Attendance tracking for each shift
    const [attendance, setAttendance] = useState<ShiftAttendance[]>(() => {
        // Initialize all employees as present
        return SHIFTS.map(shift => ({
            shiftId: shift.id,
            employees: shift.employees.map(emp => ({
                employeeId: emp.id,
                status: 'present' as AttendanceStatus
            }))
        }));
    });

    // Load from localStorage on mount
    useEffect(() => {
        const saved = localStorage.getItem('personnel-attendance');
        if (saved) {
            try {
                const parsed = JSON.parse(saved);
                setAttendance(parsed.attendance);
                // Don't auto-restore active shift to force selection if desired, 
                // OR restore it. User asked for "Default not selected".
                // Let's NOT restore activeShiftId to force selection on fresh load/refresh
                // unless we want persistence. User said "By default shifts are not selected".
                // So we will ignore saved activeShiftId or explicitly set to null on load if we want strict behavior.
                // However, for better UX within session we might want to keep it? 
                // "Impossible to make order until operator selects shift".
                // Let's start with NULL always on mount to be safe as requested.
                setActiveShiftId(null);
            } catch (e) {
                console.error('Failed to load attendance:', e);
            }
        }
    }, []);

    // Save to localStorage on change
    useEffect(() => {
        localStorage.setItem('personnel-attendance', JSON.stringify({
            attendance,
            activeShiftId,
            updatedAt: new Date().toISOString()
        }));
    }, [attendance, activeShiftId]);

    // Get current shift attendance
    const currentShiftAttendance = useMemo(() => {
        if (!activeShiftId) return null;
        return attendance.find(a => a.shiftId === activeShiftId);
    }, [attendance, activeShiftId]);

    // Get active shift data
    const activeShift = useMemo(() => {
        if (!activeShiftId) return null;
        return SHIFTS.find(s => s.id === activeShiftId);
    }, [activeShiftId]);

    // Calculate capacity based on present employees
    const { presentCount, totalCapacity } = useMemo(() => {
        if (!currentShiftAttendance) return { presentCount: 0, totalCapacity: null }; // Return null capacity if no shift

        const present = currentShiftAttendance.employees.filter(e => e.status === 'present');
        return {
            presentCount: present.length,
            totalCapacity: present.length * PRODUCTION_NORM_PER_PERSON
        };
    }, [currentShiftAttendance]);

    // Sync total capacity to global context whenever it changes
    useEffect(() => {
        setCurrentCapacity(totalCapacity);
    }, [totalCapacity, setCurrentCapacity]);

    // Toggle employee status
    const cycleEmployeeStatus = (employeeId: number) => {
        if (!activeShiftId) return;
        setAttendance(prev => {
            return prev.map(shiftAtt => {
                if (shiftAtt.shiftId !== activeShiftId) return shiftAtt;

                return {
                    ...shiftAtt,
                    employees: shiftAtt.employees.map(emp => {
                        if (emp.employeeId !== employeeId) return emp;

                        // Cycle: present -> absent -> sick -> present
                        const nextStatus: AttendanceStatus =
                            emp.status === 'present' ? 'absent' :
                                emp.status === 'absent' ? 'sick' : 'present';

                        return { ...emp, status: nextStatus };
                    })
                };
            });
        });
    };

    // Set all employees to a status
    const setAllStatus = (status: AttendanceStatus) => {
        if (!activeShiftId) return;
        setAttendance(prev => {
            return prev.map(shiftAtt => {
                if (shiftAtt.shiftId !== activeShiftId) return shiftAtt;

                return {
                    ...shiftAtt,
                    employees: shiftAtt.employees.map(emp => ({
                        ...emp,
                        status
                    }))
                };
            });
        });
    };

    // Get employee attendance status
    const getEmployeeStatus = (employeeId: number): AttendanceStatus => {
        const emp = currentShiftAttendance?.employees.find(e => e.employeeId === employeeId);
        return emp?.status || 'present';
    };

    return (
        <div className="flex flex-col h-full bg-[#0D1117] rounded-xl border border-[#3A3A3A] overflow-hidden font-sans relative">

            {/* Overlay if no shift selected */}
            {!activeShiftId && (
                <div className="absolute inset-0 z-50 bg-[#0D1117]/80 backdrop-blur-sm flex flex-col items-center justify-center p-6 text-center animate-in fade-in duration-300">
                    <div className="w-16 h-16 rounded-2xl bg-[#161B22] border border-[#3A3A3A] flex items-center justify-center mb-4 shadow-[0_0_30px_rgba(0,212,255,0.1)]">
                        <Users size={32} className="text-[#00D4FF] animate-pulse" />
                    </div>
                    <h3 className="text-xl font-black uppercase text-white mb-2">Зміна не обрана</h3>
                    <p className="text-sm text-[#8B949E] max-w-[200px] leading-relaxed">
                        Щоб розпочати роботу та сформувати замовлення, оберіть активну зміну
                    </p>
                </div>
            )}

            {/* Header with shift selector (Always visible to allow selection) */}
            <div className="px-6 py-4 border-b border-[#3A3A3A] bg-[#111823] z-50">
                <div className="flex items-center justify-between mb-4">
                    <div className="flex items-center gap-3">
                        <div
                            className="w-10 h-10 rounded-xl flex items-center justify-center"
                            style={{
                                background: 'linear-gradient(135deg, #00D4FF 0%, #0088FF 100%)',
                                boxShadow: '0 0 20px rgba(0, 212, 255, 0.4)',
                            }}
                        >
                            <Users size={20} className="text-white" />
                        </div>
                        <div>
                            <h3 className="text-[14px] font-black uppercase tracking-tighter text-[#E6EDF3]">
                                Управління Персоналом
                            </h3>
                            <p className="text-[10px] text-[#8B949E]">
                                Оберіть зміну та позначте присутність
                            </p>
                        </div>
                    </div>

                    {/* Capacity indicator */}
                    <div className="text-right">
                        <div className="text-[10px] text-[#8B949E] uppercase font-bold tracking-widest">
                            Потужність зміни
                        </div>
                        <div className="flex items-baseline gap-1 justify-end">
                            {totalCapacity !== null ? (
                                <>
                                    <span className="text-2xl font-black text-[#52E8FF]">
                                        {totalCapacity}
                                    </span>
                                    <span className="text-[11px] text-[#8B949E] font-bold">кг</span>
                                </>
                            ) : (
                                <span className="text-xl font-bold text-gray-600">—</span>
                            )}
                        </div>
                        <div className="text-[9px] text-[#8B949E]">
                            {activeShift ? `${presentCount} з ${activeShift.employees.length} осіб` : 'Зміна не обрана'}
                        </div>
                    </div>
                </div>

                {/* Shift tabs */}
                <div className="flex gap-2 relative z-50">
                    {SHIFTS.map(shift => {
                        const isActive = shift.id === activeShiftId;
                        const shiftAttendance = attendance.find(a => a.shiftId === shift.id);
                        const shiftPresent = shiftAttendance?.employees.filter(e => e.status === 'present').length || 0;

                        return (
                            <button
                                key={shift.id}
                                onClick={() => setActiveShiftId(shift.id as 1 | 2)}
                                className={cn(
                                    "flex-1 px-4 py-3 rounded-lg transition-all duration-300 text-left relative overflow-hidden group",
                                    isActive ? "ring-2 ring-[#00D4FF]" : "hover:bg-white/[0.02]"
                                )}
                                style={{
                                    background: isActive
                                        ? 'rgba(0, 212, 255, 0.15)'
                                        : 'rgba(255, 255, 255, 0.03)',
                                    border: isActive
                                        ? '1px solid rgba(0, 212, 255, 0.5)'
                                        : '1px solid rgba(255, 255, 255, 0.08)',
                                }}
                            >
                                {isActive && (
                                    <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent skew-x-12 -translate-x-full group-hover:animate-shimmer" />
                                )}
                                <div className="flex items-center justify-between relative z-10">
                                    <div>
                                        <div className={cn(
                                            "text-[12px] font-bold uppercase",
                                            isActive ? "text-[#00D4FF]" : "text-gray-400"
                                        )}>
                                            {shift.name}
                                        </div>
                                        <div className="text-[9px] text-gray-500">
                                            Старша: {shift.leader.split(' ')[0]}
                                        </div>
                                    </div>
                                    <div className="text-right">
                                        <div className={cn(
                                            "text-[14px] font-bold",
                                            isActive ? "text-[#52E8FF]" : "text-gray-500"
                                        )}>
                                            {shiftPresent}/{shift.employees.length}
                                        </div>
                                        <div className="text-[8px] text-gray-500">осіб</div>
                                    </div>
                                </div>
                            </button>
                        );
                    })}
                </div>
            </div>

            {/* Quick actions */}
            <div className={cn(
                "px-6 py-3 border-b border-[#3A3A3A]/50 bg-[#161B22] flex items-center gap-2 transition-opacity duration-300",
                !activeShiftId ? "opacity-20 pointer-events-none" : "opacity-100"
            )}>
                <span className="text-[10px] text-gray-500 uppercase font-bold mr-2">Швидко:</span>
                <button
                    onClick={() => setAllStatus('present')}
                    className="px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase transition-colors"
                    style={{
                        background: 'rgba(52, 211, 153, 0.15)',
                        color: '#34D399',
                        border: '1px solid rgba(52, 211, 153, 0.3)',
                    }}
                >
                    ✓ Всі на місці
                </button>
                <button
                    onClick={() => setAllStatus('absent')}
                    className="px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase transition-colors"
                    style={{
                        background: 'rgba(239, 68, 68, 0.15)',
                        color: '#EF4444',
                        border: '1px solid rgba(239, 68, 68, 0.3)',
                    }}
                >
                    ✗ Очистити
                </button>
            </div>

            {/* Employees list */}
            <div className={cn(
                "flex-1 overflow-y-auto custom-scrollbar transition-opacity duration-300",
                !activeShiftId ? "opacity-20 pointer-events-none" : "opacity-100"
            )}>
                {activeShift?.employees.map((employee) => {
                    const status = getEmployeeStatus(employee.id);
                    const statusColors = getStatusColor(status);

                    return (
                        <div
                            key={employee.id}
                            onClick={() => cycleEmployeeStatus(employee.id)}
                            className="px-6 py-3 border-b border-[#3A3A3A]/20 hover:bg-white/[0.02] transition-colors cursor-pointer"
                        >
                            <div className="flex items-center justify-between">
                                <div className="flex items-center gap-3 flex-1">
                                    {/* Status indicator (clickable) */}
                                    <div
                                        className="w-8 h-8 rounded-lg flex items-center justify-center transition-all"
                                        style={{
                                            background: statusColors.bg,
                                            border: `1px solid ${statusColors.border}`,
                                        }}
                                    >
                                        {getStatusIcon(status)}
                                    </div>

                                    {/* Employee info */}
                                    <div className="flex-1">
                                        <div className="flex items-center gap-2">
                                            {getPositionIcon(employee.position)}
                                            <span className={cn(
                                                "text-[12px] font-semibold transition-all",
                                                status === 'present' ? "text-[#E6EDF3]" : "text-gray-500 line-through"
                                            )}>
                                                {employee.name}
                                            </span>
                                            {employee.isLeader && (
                                                <span className="px-1.5 py-0.5 rounded text-[7px] font-bold bg-[#FFD700]/20 text-[#FFD700] uppercase">
                                                    Старша
                                                </span>
                                            )}
                                        </div>
                                        <div className="text-[9px] text-[#8B949E] mt-0.5">
                                            {employee.position}
                                        </div>
                                    </div>
                                </div>

                                {/* Status badge */}
                                <div
                                    className="px-2 py-1 rounded-full text-[8px] font-bold uppercase"
                                    style={{
                                        background: statusColors.bg,
                                        color: statusColors.text,
                                        border: `1px solid ${statusColors.border}`,
                                    }}
                                >
                                    {getStatusLabel(status)}
                                </div>

                                {/* Capacity contribution */}
                                <div className="text-right ml-4 min-w-[60px]">
                                    {status === 'present' ? (
                                        <>
                                            <div className="text-[12px] font-bold text-[#52E8FF]">
                                                +{PRODUCTION_NORM_PER_PERSON} кг
                                            </div>
                                            <div className="text-[8px] text-[#8B949E]">потужність</div>
                                        </>
                                    ) : (
                                        <div className="text-[10px] text-gray-600">—</div>
                                    )}
                                </div>
                            </div>
                        </div>
                    );
                })}
            </div>

            {/* Footer with totals */}
            <div className={cn(
                "px-6 py-4 border-t border-[#3A3A3A] bg-[#111823] transition-opacity duration-300",
                !activeShiftId ? "opacity-20 pointer-events-none" : "opacity-100"
            )}>
                <div className="flex items-center justify-between">
                    <div className="flex items-center gap-4">
                        <div className="text-[10px] text-[#8B949E]">
                            <span className="text-[#34D399] font-bold">{presentCount}</span> на місці
                        </div>
                        <div className="text-[10px] text-[#8B949E]">
                            <span className="text-[#EF4444] font-bold">
                                {currentShiftAttendance?.employees.filter(e => e.status === 'absent').length || 0}
                            </span> відсутні
                        </div>
                        <div className="text-[10px] text-[#8B949E]">
                            <span className="text-[#FBBF24] font-bold">
                                {currentShiftAttendance?.employees.filter(e => e.status === 'sick').length || 0}
                            </span> хворі
                        </div>
                    </div>
                    <div className="flex items-center gap-2">
                        <span className="text-[10px] text-gray-500 uppercase font-bold">Макс. виробітку:</span>
                        <span className="text-[16px] font-black text-[#52E8FF]">{totalCapacity || 0} кг</span>
                    </div>
                </div>
            </div>
        </div>
    );
};

'use client';

import React, { useState, useMemo, useRef, useEffect } from 'react';
import useSWR from 'swr';
import { ChefHat, AlertTriangle, RefreshCw, RotateCcw, ChevronDown, ChevronRight, Activity, Percent, CheckCircle, Calculator, Truck, TrendingUp, Package, Store } from 'lucide-react';
import { ProductionTask } from '@/types/bi';
import { cn } from '@/lib/utils';
import { BackToHome } from '@/components/BackToHome';
import { DistributionModal } from './DistributionModal';
import { ProductionDetailModal } from './ProductionDetailModal';

// 🟢 PIZZA LOGIC CONSTANTS
const SAFETY_BUFFER = 2; // Days

interface Props {
    data: ProductionTask[];
    onRefresh: () => void;
    initialViewMode?: 'products' | 'stores';
}

// Internal Component for Distribution Logic per Accordion Item
const ProductAccordionItem = ({
    product,
    planningDays,
    isExpanded,
    onToggle
}: {
    product: any,
    planningDays: number,
    isExpanded: boolean,
    onToggle: () => void
}) => {
    const [totalBaked, setTotalBaked] = useState<number>(0);
    const [distributionPlan, setDistributionPlan] = useState<Record<number, number>>({});
    const [isDistributing, setIsDistributing] = useState(false);

    // Distribution Algorithm
    const handleDistribute = (e: React.MouseEvent) => {
        e.stopPropagation(); // Prevent accordion toggle
        setIsDistributing(true);

        setTimeout(() => { // Small fake delay for UX
            let remaining = totalBaked;
            const newPlan: Record<number, number> = {};

            const add = (storeId: number, amount: number) => {
                newPlan[storeId] = (newPlan[storeId] || 0) + amount;
                remaining -= amount;
            };

            const stores = product.stores;

            // STEP 1: CRITICAL (Stock < Min Stock)
            const totalCriticalNeed = stores.reduce((sum: number, s: any) => sum + s.computed.urgentDeficit, 0);

            if (totalCriticalNeed > 0) {
                if (remaining >= totalCriticalNeed) {
                    stores.forEach((s: any) => { if (s.computed.urgentDeficit > 0) add(s.storeId, s.computed.urgentDeficit); });
                } else {
                    stores.forEach((s: any) => {
                        if (s.computed.urgentDeficit > 0) {
                            const share = Math.floor((s.computed.urgentDeficit / totalCriticalNeed) * remaining);
                            if (share > 0) add(s.storeId, share);
                        }
                    });
                }
            }

            // STEP 2: REMAINING (Proportional to Avg Sales)
            if (remaining > 0) {
                const totalAvg = stores.reduce((sum: number, s: any) => sum + s.computed.avg, 0);
                if (totalAvg > 0) {
                    const step2Pool = remaining;
                    stores.forEach((s: any) => {
                        const rawShare = (s.computed.avg / totalAvg) * step2Pool;
                        add(s.storeId, Math.floor(rawShare));
                    });
                }
            }

            // STEP 3: ROUNDING
            while (remaining > 0) {
                const sorted = [...stores].sort((a: any, b: any) => a.computed.stock - b.computed.stock);
                for (const s of sorted) {
                    if (remaining <= 0) break;
                    add(s.storeId, 1);
                }
                if (remaining > 0) break;
            }

            setDistributionPlan(newPlan);
            setIsDistributing(false);
        }, 100);
    };

    const totalDistributed = Object.values(distributionPlan).reduce((a, b) => a + b, 0);
    const criticalStoresCount = product.stores.filter((s: any) => s.computed.isUrgent).length;

    // When used inside the new card grid, we only render the internal content (no header, no wrapper)
    // The card grid already provides the header and expansion logic
    return (
        <div className="border-t border-white/5 p-2">
            {/* STORES GRID */}
            <div className="grid grid-cols-3 md:grid-cols-4 xl:grid-cols-6 gap-2 mb-3">
                {[...product.stores].sort((a: any, b: any) => b.computed.avg - a.computed.avg).map((store: any) => {

                    const isLowStock = store.computed.stock < store.computed.minStock;
                    const planVal = distributionPlan[store.storeId] || 0;

                    // SOFT COLORS
                    const cardBg = isLowStock
                        ? "bg-red-500/10 border-red-500/20"
                        : "bg-emerald-500/10 border-emerald-500/20";

                    return (
                        <div
                            key={`${product.productCode}-${store.storeName}`}
                            className={cn(
                                "rounded-lg p-2 border flex flex-col gap-1 transition-colors",
                                cardBg
                            )}
                        >
                            {/* Store Name - Compact */}
                            <div className="text-xs font-bold uppercase tracking-wide truncate text-white/90 text-center" title={store.storeName}>
                                {store.storeName.replace('Магазин ', '').replace('"', '').replace('"', '')}
                            </div>

                            {/* Metrics Row - Compact */}
                            <div className="grid grid-cols-3 gap-1 text-[10px] font-mono leading-none mt-0.5">
                                <div className="flex flex-col gap-0.5">
                                    <span className="text-[9px] text-white/40 uppercase font-bold">Факт</span>
                                    <span className={cn("font-bold text-lg", isLowStock ? "text-[#E74856]" : "text-emerald-400")}>
                                        {store.computed.stock.toFixed(0)}
                                    </span>
                                </div>
                                <div className="flex flex-col gap-0.5 text-center">
                                    <span className="text-[9px] text-white/40 uppercase font-bold">Мін</span>
                                    <span className="font-bold text-lg text-cyan-400">{store.computed.minStock.toFixed(0)}</span>
                                </div>
                                <div className="flex flex-col gap-0.5 text-right">
                                    <span className="text-[9px] text-white/40 uppercase font-bold">Сер</span>
                                    <span className="font-bold text-lg text-[#FFB800]">{store.computed.avg.toFixed(1)}</span>
                                </div>
                            </div>

                            {/* Input Field - Reduced */}
                            <div className="pt-1.5 border-t border-white/10 mt-0.5 flex items-center justify-between">
                                <span className="text-[9px] text-[#FFB800] font-bold uppercase">План</span>
                                <input
                                    type="number"
                                    value={planVal || ''}
                                    onChange={(e) => {
                                        const val = Number(e.target.value);
                                        setDistributionPlan(prev => ({ ...prev, [store.storeId]: val }));
                                    }}
                                    onClick={(e) => e.stopPropagation()}
                                    className={cn(
                                        "w-14 bg-[#FFB800]/10 border border-[#FFB800]/20 rounded h-6 text-center font-mono font-bold text-base focus:outline-none focus:border-[#FFB800]",
                                        planVal > 0 ? "text-[#FFB800]" : "text-white/40"
                                    )}
                                    placeholder="-"
                                />
                            </div>
                        </div>
                    );
                })}
            </div>

            {/* CONTROLS */}
            <div className="p-3 bg-[#141829] rounded-lg border border-white/5 flex items-center gap-4">
                <div className="flex-1 max-w-xs">
                    <label className="text-[10px] text-white/40 uppercase font-bold tracking-widest block mb-1">
                        Скільки випечено (шт)
                    </label>
                    <input
                        type="number"
                        value={totalBaked || ''}
                        onChange={(e) => setTotalBaked(Number(e.target.value))}
                        onClick={(e) => e.stopPropagation()}
                        className="w-full bg-white/5 border border-white/10 rounded-lg h-10 px-3 font-mono text-[#FFB800] text-xl font-bold focus:outline-none focus:border-[#FFB800]"
                        placeholder="0"
                    />
                </div>

                <button
                    onClick={handleDistribute}
                    disabled={!totalBaked || isDistributing}
                    className="h-10 px-6 bg-[#FFB800] hover:bg-[#FFB800]/90 text-black font-bold uppercase text-xs tracking-wider rounded-lg transition-all disabled:opacity-50 mt-4 flex items-center gap-2"
                >
                    <RotateCcw size={16} className={isDistributing ? "animate-spin" : ""} />
                    Розподілити
                </button>

                <div className="ml-auto mt-4 text-right">
                    <div className="text-[10px] text-white/30 uppercase tracking-widest font-bold">Нерозподілено</div>
                    <div className={cn("font-mono font-bold text-xl", (totalBaked - totalDistributed) < 0 ? "text-red-500" : "text-white")}>
                        {(totalBaked - totalDistributed).toFixed(0)}
                    </div>
                </div>
            </div>
        </div>
    );
};

export const PizzaPowerMatrix = ({ data, onRefresh, initialViewMode = 'products' }: Props) => {
    // STATE
    const [planningDays, setPlanningDays] = useState<number>(3);
    const [isRefreshing, setIsRefreshing] = useState(false);
    const [expandedItems, setExpandedItems] = useState<Set<number>>(new Set());
    const [viewMode, setViewMode] = useState<'products' | 'stores'>(initialViewMode);
    const [expandedStores, setExpandedStores] = useState<Set<string>>(new Set());
    const [isUpdatingStock, setIsUpdatingStock] = useState(false);
    const [showDistModal, setShowDistModal] = useState(false);
    const [showProductionModal, setShowProductionModal] = useState(false);

    const handleRefresh = async () => {
        setIsRefreshing(true);
        await onRefresh();
        setTimeout(() => setIsRefreshing(false), 500);
    };

    // 🏭 PRODUCTION SUMMARY
    const { data: productionSummary } = useSWR('/api/pizza/summary', (url) => fetch(url, { credentials: 'include' }).then(r => r.json()), { refreshInterval: 30000 });

    // 🔥 WEBHOOK: Update stock from n8n
    const handleUpdateStock = async () => {
        setIsUpdatingStock(true);
        try {
            const response = await fetch('/api/pizza/update-stock', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ action: 'update_stock', timestamp: new Date().toISOString() })
            });

            if (response.ok) {
                // Refresh data after stock update
                await onRefresh();
            } else {
                console.error('Stock update failed:', response.status);
            }
        } catch (error) {
            console.error('Stock update error:', error);
        } finally {
            setIsUpdatingStock(false);
        }
    };


    const toggleItem = (code: number) => {
        setExpandedItems(prev => {
            const next = new Set(prev);
            if (next.has(code)) {
                next.delete(code);
            } else {
                next.add(code);
            }
            return next;
        });
    };

    const expandOne = (code: number) => {
        setExpandedItems(new Set([code]));
        setTimeout(() => {
            const el = document.getElementById(`product-${code}`);
            if (el) el.scrollIntoView({ behavior: 'smooth', block: 'start' });
        }, 100);
    };

    // 1. CALCULATE PRODUCT LEVEL AGGREGATES
    const products = useMemo(() => {
        return data.map(product => {
            let totalAvg = 0;
            let totalStock = 0;
            let totalRecommended = 0;
            let totalUrgentDeficit = 0;
            let totalMinStock = 0;

            const storesWithStats = product.stores.map(store => {
                const avg = (Number(store.avgSales) || 0); // No Multiplier x1000
                const stock = Number(store.currentStock) || 0;

                // Formulas per store
                const minStock = Number(store.minStock) || 0;

                const urgent = Math.max(0, minStock - stock);

                const target = Math.ceil((avg * planningDays) + minStock);
                const recommended = Math.max(0, target - stock);

                totalAvg += avg;
                totalStock += stock;
                totalMinStock += minStock;
                totalRecommended += recommended;
                totalUrgentDeficit += urgent;

                return {
                    ...store,
                    computed: {
                        avg,
                        stock,
                        minStock,
                        recommended,
                        urgentDeficit: urgent,
                        isUrgent: urgent > 0
                    }
                };
            });

            return {
                ...product,
                stores: storesWithStats.sort((a, b) => b.computed.urgentDeficit - a.computed.urgentDeficit),
                computed: {
                    totalAvg,
                    totalStock,
                    totalMinStock,
                    totalRecommended,
                    totalUrgentDeficit
                }
            };
        }).sort((a, b) => {
            if (b.computed.totalUrgentDeficit !== a.computed.totalUrgentDeficit) {
                return b.computed.totalUrgentDeficit - a.computed.totalUrgentDeficit;
            }
            return b.name.localeCompare(a.name);
        });

    }, [data, planningDays]);

    // Toggle store expansion
    const toggleStore = (storeName: string) => {
        setExpandedStores(prev => {
            const next = new Set(prev);
            if (next.has(storeName)) {
                next.delete(storeName);
            } else {
                next.add(storeName);
            }
            return next;
        });
    };

    // 1.5 GROUP BY STORES (inverted view)
    const storesGrouped = useMemo(() => {
        const storeMap = new Map<string, {
            storeName: string;
            storeId: number;
            products: Array<{
                productName: string;
                productCode: number;
                stock: number;
                avg: number;
                minStock: number;
                recommended: number;
                urgentDeficit: number;
                isUrgent: boolean;
            }>;
            totalStock: number;
            totalMinStock: number;
            totalUrgentDeficit: number;
            criticalProducts: number;
            totalAvgSales: number;
        }>();

        products.forEach(product => {
            product.stores.forEach((store: any) => {
                const storeName = store.storeName || 'Unknown';

                if (!storeMap.has(storeName)) {
                    storeMap.set(storeName, {
                        storeName,
                        storeId: store.storeId,
                        products: [],
                        totalStock: 0,
                        totalMinStock: 0,
                        totalUrgentDeficit: 0,
                        criticalProducts: 0,
                        totalAvgSales: 0
                    });
                }

                const entry = storeMap.get(storeName)!;
                entry.products.push({
                    productName: product.name,
                    productCode: product.productCode,
                    stock: store.computed.stock,
                    avg: store.computed.avg,
                    minStock: store.computed.minStock,
                    recommended: store.computed.recommended,
                    urgentDeficit: store.computed.urgentDeficit,
                    isUrgent: store.computed.isUrgent
                });
                entry.totalStock += store.computed.stock;
                entry.totalMinStock += store.computed.minStock;
                entry.totalUrgentDeficit += store.computed.urgentDeficit;
                if (store.computed.isUrgent) entry.criticalProducts++;
                entry.totalAvgSales += store.computed.avg;
            });
        });

        return Array.from(storeMap.values()).sort((a, b) => b.totalAvgSales - a.totalAvgSales);
    }, [products]);

    return (
        <div className="flex flex-col h-full w-full font-sans text-white bg-[#0B0E14]">
            {/* VIEW MODE TOGGLE - COMPACT */}
            <div className="px-4 py-3 flex items-center justify-start gap-4 bg-[#141829]/50 border-b border-white/5">
                <button
                    onClick={() => setViewMode('products')}
                    className={cn(
                        "px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all border flex items-center gap-2",
                        viewMode === 'products'
                            ? "bg-[#FFB800] border-[#FFB800] text-black shadow-[0_0_20px_rgba(255,184,0,0.4)] scale-105"
                            : "bg-white/5 border-white/5 text-white/40 hover:text-white hover:bg-white/10 hover:border-white/20"
                    )}
                >
                    <Package size={16} strokeWidth={3} className={viewMode === 'products' ? "text-black" : "text-white/40"} />
                    За продуктами
                </button>
                <button
                    onClick={() => setViewMode('stores')}
                    className={cn(
                        "px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all border flex items-center gap-2",
                        viewMode === 'stores'
                            ? "bg-[#00D4FF] border-[#00D4FF] text-black shadow-[0_0_20px_rgba(0,212,255,0.4)] scale-105"
                            : "bg-white/5 border-white/5 text-white/40 hover:text-white hover:bg-white/10 hover:border-white/20"
                    )}
                >
                    <Store size={16} strokeWidth={3} className={viewMode === 'stores' ? "text-black" : "text-white/40"} />
                    За точками
                </button>
            </div>

            {/* 🔥 CARD GRID LAYOUT */}
            <main className="flex-1 overflow-y-auto custom-scrollbar p-4 pt-2">
                {viewMode === 'products' ? (
                    /* PRODUCTS VIEW */
                    <div className="grid grid-cols-4 xl:grid-cols-6 gap-3 pb-20">
                        {products.map(product => {
                            const isExpanded = expandedItems.has(product.productCode);
                            const criticalStores = product.stores.filter((s: any) => s.computed.isUrgent).length;
                            const hasIssues = criticalStores > 0;

                            return (
                                <div
                                    key={product.id}
                                    id={`product-${product.productCode}`}
                                    className={cn(
                                        "rounded-2xl border-2 overflow-hidden transition-all duration-300 bg-gradient-to-br",
                                        hasIssues
                                            ? "from-[#E74856]/10 to-[#E74856]/5 border-[#E74856]/30 hover:border-[#E74856]/50"
                                            : "from-emerald-500/10 to-emerald-500/5 border-emerald-500/30 hover:border-emerald-500/50",
                                        isExpanded && "col-span-2 xl:col-span-3 border-[#FFB800]/50 shadow-xl shadow-[#FFB800]/10"
                                    )}
                                >
                                    {/* CARD HEADER */}
                                    <div
                                        onClick={() => toggleItem(product.productCode)}
                                        className={cn(
                                            "p-4 cursor-pointer transition-colors",
                                            isExpanded ? "bg-white/5" : "hover:bg-white/5"
                                        )}
                                    >
                                        <div className="flex items-center justify-between mb-3">
                                            <h3 className="text-lg font-black text-white leading-tight truncate pr-2">
                                                🍕 {product.name}
                                            </h3>
                                            <ChevronDown
                                                size={20}
                                                className={cn(
                                                    "text-white/40 transition-transform flex-shrink-0",
                                                    isExpanded && "rotate-180 text-[#FFB800]"
                                                )}
                                            />
                                        </div>

                                        <div className="grid grid-cols-2 gap-3">
                                            <div className="bg-white/5 rounded-xl p-3 text-center">
                                                <div className="text-[10px] text-white/40 uppercase font-bold tracking-wider mb-1">Залишок</div>
                                                <div className={cn(
                                                    "text-2xl font-mono font-black",
                                                    hasIssues ? "text-[#E74856]" : "text-emerald-400"
                                                )}>
                                                    {product.computed.totalStock.toFixed(0)}
                                                </div>
                                                <div className="text-[10px] text-white/30 font-bold">шт</div>
                                            </div>
                                            <div className={cn(
                                                "rounded-xl p-3 text-center",
                                                criticalStores > 0 ? "bg-[#E74856]/20" : "bg-emerald-500/10"
                                            )}>
                                                <div className="text-[10px] text-white/40 uppercase font-bold tracking-wider mb-1">Критичні</div>
                                                <div className={cn(
                                                    "text-2xl font-mono font-black",
                                                    criticalStores > 0 ? "text-[#E74856]" : "text-emerald-400"
                                                )}>
                                                    {criticalStores}
                                                </div>
                                                <div className="text-[10px] text-white/30 font-bold">магазинів</div>
                                            </div>
                                        </div>

                                        <div className="mt-3">
                                            <div className="h-1.5 bg-white/10 rounded-full overflow-hidden">
                                                <div
                                                    className={cn(
                                                        "h-full rounded-full transition-all",
                                                        hasIssues ? "bg-[#E74856]" : "bg-emerald-400"
                                                    )}
                                                    style={{
                                                        width: `${Math.min(100, (1 - criticalStores / Math.max(1, product.stores.length)) * 100)}%`
                                                    }}
                                                />
                                            </div>
                                        </div>
                                    </div>

                                    {isExpanded && (
                                        <ProductAccordionItem
                                            product={product}
                                            planningDays={planningDays}
                                            isExpanded={true}
                                            onToggle={() => toggleItem(product.productCode)}
                                        />
                                    )}
                                </div>
                            );
                        })}
                    </div>
                ) : (
                    /* STORES VIEW */
                    <div className="grid grid-cols-4 xl:grid-cols-6 gap-3 pb-20">
                        {storesGrouped.map(store => {
                            const isExpanded = expandedStores.has(store.storeName);
                            const hasIssues = store.criticalProducts > 0;
                            const fillPercent = store.totalMinStock > 0
                                ? (store.totalStock / store.totalMinStock) * 100
                                : 100;

                            return (
                                <div
                                    key={store.storeName}
                                    id={`store-${store.storeId}`}
                                    className={cn(
                                        "rounded-2xl border-2 overflow-hidden transition-all duration-300 bg-gradient-to-br",
                                        hasIssues
                                            ? "from-[#E74856]/10 to-[#E74856]/5 border-[#E74856]/30 hover:border-[#E74856]/50"
                                            : "from-emerald-500/10 to-emerald-500/5 border-emerald-500/30 hover:border-emerald-500/50",
                                        isExpanded && "col-span-2 xl:col-span-3 border-[#FFB800]/50 shadow-xl shadow-[#FFB800]/10"
                                    )}
                                >
                                    {/* STORE CARD HEADER */}
                                    <div
                                        onClick={() => toggleStore(store.storeName)}
                                        className={cn(
                                            "p-4 cursor-pointer transition-colors",
                                            isExpanded ? "bg-white/5" : "hover:bg-white/5"
                                        )}
                                    >
                                        <div className="flex items-center justify-between mb-3">
                                            <h3 className="text-lg font-black text-white leading-tight truncate pr-2">
                                                {store.storeName.replace('Магазин ', '').replace(/"/g, '')}
                                            </h3>
                                            <ChevronDown
                                                size={20}
                                                className={cn(
                                                    "text-white/40 transition-transform flex-shrink-0",
                                                    isExpanded && "rotate-180 text-[#FFB800]"
                                                )}
                                            />
                                        </div>

                                        <div className="grid grid-cols-3 gap-2">
                                            <div className="bg-white/5 rounded-xl p-3 text-center">
                                                <div className="text-[10px] text-white/40 uppercase font-bold tracking-wider mb-1">Залишок</div>
                                                <div className={cn(
                                                    "text-2xl font-mono font-black",
                                                    hasIssues ? "text-[#E74856]" : "text-emerald-400"
                                                )}>
                                                    {store.totalStock.toFixed(0)}
                                                </div>
                                                <div className="text-[10px] text-white/30 font-bold">шт</div>
                                            </div>
                                            <div className={cn(
                                                "rounded-xl p-3 text-center",
                                                store.criticalProducts > 0 ? "bg-[#E74856]/20" : "bg-emerald-500/10"
                                            )}>
                                                <div className="text-[10px] text-white/40 uppercase font-bold tracking-wider mb-1">Критичні</div>
                                                <div className={cn(
                                                    "text-2xl font-mono font-black",
                                                    store.criticalProducts > 0 ? "text-[#E74856]" : "text-emerald-400"
                                                )}>
                                                    {store.criticalProducts}
                                                </div>
                                                <div className="text-[10px] text-white/30 font-bold">продуктів</div>
                                            </div>

                                            {/* NEW: AVG SALES METRIC */}
                                            <div className="bg-[#00D4FF]/10 rounded-xl p-3 text-center border border-[#00D4FF]/20 flex flex-col justify-center">
                                                <div className="flex items-center justify-center gap-1 text-[9px] text-[#00D4FF]/80 uppercase font-bold mb-1 whitespace-nowrap">
                                                    <TrendingUp size={10} />
                                                    <span>Прод/день</span>
                                                </div>
                                                <div className="text-2xl font-mono font-black text-[#00D4FF] leading-none">
                                                    {store.totalAvgSales.toFixed(0)}
                                                </div>
                                                <div className="text-[10px] text-[#00D4FF]/50 font-bold mt-1">піц</div>
                                            </div>
                                        </div>

                                        <div className="mt-3">
                                            <div className="h-1.5 bg-white/10 rounded-full overflow-hidden">
                                                <div
                                                    className={cn(
                                                        "h-full rounded-full transition-all",
                                                        fillPercent >= 100 ? "bg-emerald-400" :
                                                            fillPercent < 50 ? "bg-[#E74856]" : "bg-[#FFB800]"
                                                    )}
                                                    style={{ width: `${Math.min(100, fillPercent)}%` }}
                                                />
                                            </div>
                                        </div>
                                    </div>

                                    {/* EXPANDED CONTENT - Products in this store */}
                                    {isExpanded && (
                                        <div className="border-t border-white/5 p-3">
                                            <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-2">
                                                {store.products.sort((a, b) => b.avg - a.avg).map(product => (
                                                    <div
                                                        key={`${store.storeName}-${product.productCode}`}
                                                        className={cn(
                                                            "rounded-lg p-3 border transition-colors",
                                                            product.isUrgent
                                                                ? "bg-red-500/10 border-red-500/20"
                                                                : "bg-emerald-500/10 border-emerald-500/20"
                                                        )}
                                                    >
                                                        <div className="text-sm font-bold text-white truncate mb-2" title={product.productName}>
                                                            🍕 {product.productName}
                                                        </div>
                                                        <div className="grid grid-cols-3 gap-1 text-center">
                                                            <div>
                                                                <div className="text-[9px] text-white/40 uppercase font-bold">Факт</div>
                                                                <div className={cn(
                                                                    "text-lg font-mono font-black",
                                                                    product.isUrgent ? "text-[#E74856]" : "text-emerald-400"
                                                                )}>
                                                                    {product.stock.toFixed(0)}
                                                                </div>
                                                            </div>
                                                            <div>
                                                                <div className="text-[9px] text-white/40 uppercase font-bold">Мін</div>
                                                                <div className="text-lg font-mono font-bold text-cyan-400">
                                                                    {product.minStock.toFixed(0)}
                                                                </div>
                                                            </div>
                                                            <div>
                                                                <div className="text-[9px] text-white/40 uppercase font-bold">Сер</div>
                                                                <div className="text-lg font-mono font-bold text-[#FFB800]">
                                                                    {product.avg.toFixed(1)}
                                                                </div>
                                                            </div>
                                                        </div>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                )}
            </main>

            {/* DISTRIBUTION MODAL */}
            <DistributionModal
                isOpen={showDistModal}
                onClose={() => setShowDistModal(false)}
                products={data}
            />

            {/* PRODUCTION MODAL */}
            <ProductionDetailModal
                isOpen={showProductionModal}
                onClose={() => setShowProductionModal(false)}
            />
        </div>
    );
};

'use client';

import React, { useState, useMemo } from 'react';
import { Send, Download, Copy, Check } from 'lucide-react';
import { OrderItem, SharePlatform } from '@/types/order';
import { formatOrderMessage } from '@/lib/messageFormatter';
import { groupItemsByCategory, generateExcel, prepareWorkbook } from '@/lib/order-export';
import { auditLog } from '@/lib/logger';
import { Modal, ModalHeader, ModalBody, ModalFooter, ModalButton } from '@/components/ui/Modal';

interface ShareOptionsModalProps {
    isOpen: boolean;
    items: OrderItem[];
    orderData: any;
    onClose: () => void;
    onShare: (platform: SharePlatform['id']) => void;
}

export const ShareOptionsModal = ({ isOpen, items, orderData, onClose, onShare }: ShareOptionsModalProps) => {
    const [copied, setCopied] = useState(false);

    const handleDownloadExcel = async () => {
        // Log export action
        await auditLog('EXPORT_EXCEL', 'ShareOptionsModal', {
            date: orderData.date,
            totalKg: orderData.totalKg,
            itemCount: items.length
        });

        const fileName = await generateExcel(orderData);
        alert(`Файл збережено: ${fileName}`);
    };

    const handleShareExcel = async () => {
        try {
            // Log share action
            await auditLog('SHARE_ORDER', 'ShareOptionsModal', {
                date: orderData.date,
                totalKg: orderData.totalKg,
                itemCount: items.length
            });

            const workbook = await prepareWorkbook(orderData);
            const buffer = await workbook.xlsx.writeBuffer();
            const fileName = `Graviton_${orderData.date.replace(/\./g, '-')}.xlsx`;
            const shareText = `Замовлення GRAVITON на ${orderData.date}\nЗагальна вага: ${orderData.totalKg} кг`;
            const file = new File(
                [buffer],
                fileName,
                { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' }
            );

            const downloadFile = () => {
                const blob = new Blob([buffer], {
                    type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
                });
                const url = window.URL.createObjectURL(blob);
                const link = document.createElement('a');
                link.href = url;
                link.download = fileName;
                link.click();
                window.URL.revokeObjectURL(url);
            };

            const hasShareApi = typeof navigator !== 'undefined' && typeof navigator.share === 'function';
            const canShareFiles = hasShareApi
                && typeof navigator.canShare === 'function'
                && navigator.canShare({ files: [file] });

            if (canShareFiles) {
                await navigator.share({
                    files: [file],
                    title: 'Виробниче замовлення',
                    text: shareText
                });
                return;
            }

            if (hasShareApi) {
                try {
                    await navigator.share({
                        title: 'Виробниче замовлення',
                        text: shareText
                    });
                } catch (shareError) {
                    console.warn('Text share failed:', shareError);
                }
            }

            downloadFile();
            alert('Ваш браузер не підтримує надсилання файлів. Файл завантажено, додайте його в Telegram/WhatsApp/Viber вручну.');
        } catch (error) {
            console.error('Помилка при поділитися:', error);
            await auditLog('ERROR', 'ShareOptionsModal', { error: String(error) });
            alert('Помилка при поділитися файлом');
        }
    };


    const messagePreview = useMemo(() => {
        return formatOrderMessage(items);
    }, [items]);

    const groupedByCategory = useMemo(() => {
        return groupItemsByCategory(items);
    }, [items]);

    const handleCopy = () => {
        navigator.clipboard.writeText(messagePreview);
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
    };

    return (
        <Modal isOpen={isOpen} onClose={onClose} size="md">
            {/* Header */}
            <ModalHeader icon={<Send size={20} />}>
                <h2 className="text-[16px] font-black uppercase tracking-tight text-white">
                    Поділитися замовленням
                </h2>
                <p className="text-[11px] text-white/40 mt-1">
                    Оберіть спосіб надсилання
                </p>
            </ModalHeader>

            {/* Content */}
            <ModalBody className="space-y-6">
                {/* Action Buttons */}
                <div className="space-y-4">
