                                </div>
                                <span>ЗАМОВЛЕННЯ</span>
                                {activeTab === 'orders' && (
                                    <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent -translate-x-full animate-[shimmer_2s_infinite] pointer-events-none" />
                                )}
                            </button>

                            <button
                                onClick={() => setActiveTab('matrix')}
                                className={cn(
                                    "flex-1 h-12 px-6 text-xs font-black uppercase tracking-[0.15em] rounded-xl transition-all duration-500 flex items-center justify-center gap-3 relative overflow-hidden group/tab",
                                    activeTab === 'matrix'
                                        ? "bg-gradient-to-r from-[#FFB800] to-[#FF8A00] text-[#0B0E14] shadow-[0_0_25px_rgba(255,184,0,0.4)]"
                                        : "text-white/30 hover:text-white/60 hover:bg-white/5"
                                )}
                            >
                                <div className={cn(
                                    "p-1.5 rounded-lg transition-colors",
                                    activeTab === 'matrix' ? "bg-black/10" : "bg-white/5"
                                )}>
                                    <Activity size={16} strokeWidth={2.5} />
                                </div>
                                <span>МАТРИЦЯ (OLD)</span>
                                {activeTab === 'matrix' && (
                                    <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent -translate-x-full animate-[shimmer_2s_infinite] pointer-events-none" />
                                )}
                            </button>

                            <button
                                onClick={() => setActiveTab('production')}
                                className={cn(
                                    "flex-1 h-12 px-6 text-xs font-black uppercase tracking-[0.15em] rounded-xl transition-all duration-500 flex items-center justify-center gap-3 relative overflow-hidden group/tab",
                                    activeTab === 'production'
                                        ? "bg-gradient-to-r from-[#58A6FF] to-[#1E5FCC] text-white shadow-[0_0_25px_rgba(88,166,255,0.4)]"
                                        : "text-white/30 hover:text-white/60 hover:bg-white/5"
                                )}
                            >
                                <div className={cn(
                                    "p-1.5 rounded-lg transition-colors",
                                    activeTab === 'production' ? "bg-black/20" : "bg-white/5"
                                )}>
                                    <ChefHat size={16} strokeWidth={2.5} />
                                </div>
                                <span>ВИРОБНИЦТВО</span>
                                {activeTab === 'production' && (
                                    <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full animate-[shimmer_2s_infinite] pointer-events-none" />
                                )}
                            </button>

                            <button
                                onClick={() => setActiveTab('logistics')}
                                className={cn(
                                    "flex-1 h-12 px-6 text-xs font-black uppercase tracking-[0.15em] rounded-xl transition-all duration-500 flex items-center justify-center gap-3 relative overflow-hidden group/tab",
                                    activeTab === 'logistics'
                                        ? "bg-gradient-to-r from-[#10B981] to-[#059669] text-white shadow-[0_0_25px_rgba(16,185,129,0.4)]"
                                        : "text-white/30 hover:text-white/60 hover:bg-white/5"
                                )}
                            >
                                <div className={cn(
                                    "p-1.5 rounded-lg transition-colors",
                                    activeTab === 'logistics' ? "bg-black/20" : "bg-white/5"
                                )}>
                                    <Truck size={16} strokeWidth={2.5} />
                                </div>
                                <span>ЛОГІСТИКА (NEW)</span>
                                {activeTab === 'logistics' && (
                                    <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full animate-[shimmer_2s_infinite] pointer-events-none" />
                                )}
                            </button>
                        </div>
                    )}
                </div>
            </header>

            {/* 2. CONTENT BLOCK */}
            <div className="flex-1 overflow-hidden relative">
                {(!showTabs || activeTab === 'orders') && (
                    <ProductionOpsTable data={data} onRefresh={onRefresh} />
                )}
                {(showTabs && activeTab === 'matrix') && (
                    <PizzaPowerMatrix data={data} onRefresh={onRefresh} />
                )}
                {(showTabs && activeTab === 'production') && (
                    <ProductionDetailView />
                )}
                {(showTabs && activeTab === 'logistics') && (
                    <DistributionControlPanel />
                )}
            </div>

            {/* MODALS */}
            <DistributionModal
                isOpen={showDistModal}
                onClose={() => setShowDistModal(false)}
                products={data}
            />
            <ProductionDetailModal
                isOpen={showProductionModal}
                onClose={() => setShowProductionModal(false)}
            />
        </div>
    );
};

'use client';

import React, { useMemo, useState } from 'react';
import { ProductionTask } from '@/types/bi';
import { cn } from '@/lib/utils';
import { AlertCircle, ChevronRight, Store } from 'lucide-react';
import { DistributionModal } from '@/components/DistributionModal';

interface Props {
    data: ProductionTask[];
}

export const StoreNeedGrid = ({ data }: Props) => {
    const [selectedStore, setSelectedStore] = useState<string | null>(null);

    // Grouping Logic
    const storeStats = useMemo(() => {
        const stats = new Map<string, {
            storeName: string;
            totalDeficit: number;
            totalRecommended: number;
            criticalItems: number;
            products: any[];
        }>();

        data.forEach(product => {
            product.stores.forEach(store => {
                const storeName = store.storeName;
                if (!stats.has(storeName)) {
                    stats.set(storeName, {
                        storeName,
                        totalDeficit: 0,
                        totalRecommended: 0,
                        criticalItems: 0,
                        products: []
                    });
                }

                const entry = stats.get(storeName)!;
                // Deficit calculation: Logic from user request (sum need_net)
                // Assuming 'deficitKg' or 'recommendedKg' maps to need_net in transformer
                const deficit = store.deficitKg;

                if (deficit > 0) {
                    entry.totalDeficit += deficit;
                    entry.products.push({
                        ...product,
                        storeSpecific: store
                    });
                }

                entry.totalRecommended += store.recommendedKg;
                if (store.deficitKg > 0 && store.currentStock === 0) {
                    entry.criticalItems += 1;
                }
            });
        });

        return Array.from(stats.values()).sort((a, b) => b.totalDeficit - a.totalDeficit);
    }, [data]);

    return (
        <div className="h-full overflow-y-auto custom-scrollbar p-4">
            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
                {storeStats.map(store => {
                    const isCritical = store.totalDeficit > 50 || store.criticalItems > 5; // Arbitrary thresholds for visual

                    return (
                        <div
                            key={store.storeName}
                            onClick={() => setSelectedStore(store.storeName)}
                            className={cn(
                                "rounded-xl border p-5 cursor-pointer transition-all hover:scale-[1.02] active:scale-[0.98] group relative overflow-hidden",
                                isCritical
                                    ? "bg-[#E74856]/10 border-[#E74856]/30 hover:bg-[#E74856]/20"
                                    : "bg-[#141829] border-white/5 hover:bg-[#1A1F3A]"
                            )}
                        >
                            <div className="flex items-start justify-between mb-4">
                                <div className="flex items-center gap-3">
                                    <div className={cn(
                                        "w-10 h-10 rounded-lg flex items-center justify-center",
                                        isCritical ? "bg-[#E74856]/20 text-[#E74856]" : "bg-white/5 text-white/40"
                                    )}>
                                        <Store size={20} />
                                    </div>
                                    <div>
                                        <h3 className="font-bold text-white leading-tight">
                                            {store.storeName.replace('Магазин ', '').replace(/"/g, '')}
                                        </h3>
                                        <p className="text-[10px] text-white/40 uppercase tracking-wider font-bold mt-1">
                                            {store.products.length} позицій
                                        </p>
                                    </div>
                                </div>
                                {isCritical && (
