import { createClient } from '@/utils/supabase/client';

/**
 * SWR fetcher з автоматичною авторизацією.
 * Бере access_token із supabase.auth.getSession() і шле Authorization: Bearer <token>.
 */
export const authedFetcher = async (url: string) => {
    const supabase = createClient();
    const { data, error } = await supabase.auth.getSession();

    // 🔍 TEMP DEBUG LOG
    console.log('[authedFetcher] url=', url, 'hasSession=', !!data.session, 'err=', error?.message);

    const token = data.session?.access_token;

    const headers: Record<string, string> = {};
    if (token) {
        headers['Authorization'] = `Bearer ${token}`;
    }

    const res = await fetch(url, {
        credentials: 'include', // keep include for cookie flow backup
        headers,
    });

    if (!res.ok) {
        const errorVal = new Error('Fetch failed');
        (errorVal as any).status = res.status;
        (errorVal as any).info = await res.json().catch(() => ({}));
        throw errorVal;
    }

    return res.json();
};

import { createClient as createServerSupabase } from '@/utils/supabase/server';
import { AuditAction, Logger } from './logger';

/**
 * Server-side audit log (for API routes).
 * Captures IP address from request headers.
 */
export async function serverAuditLog(
    action: AuditAction,
    target: string,
    request: Request,
    metadata?: Record<string, unknown>,
    userId?: string | null
): Promise<void> {
    // 1. IP Normalization
    let ip = request.headers.get('x-forwarded-for') || request.headers.get('x-real-ip') || 'unknown';
    if (ip.includes(',')) {
        ip = ip.split(',')[0].trim();
    }

    // 3. user_agent Hardening (max 200 chars strictly)
    let userAgent = request.headers.get('user-agent') || 'unknown';
    if (userAgent.length > 200) {
        userAgent = userAgent.substring(0, 197) + '...';
    }

    // 2. Metadata Sanitization
    const safeMetadata = sanitizeMetadata(metadata);

    const entry = {
        user_id: userId ?? null,
        action,
        target,
        metadata: safeMetadata,
        ip_address: ip,
        user_agent: userAgent,
        created_at: new Date().toISOString(),
    };

    // 3. Fire-and-forget Insert
    // We do NOT await this promise to avoid blocking the API response.
    // However, we must handle the promise rejection to avoid "Unhandled Rejection" warnings.
    createServerSupabase()
        .then(supabase => supabase.from('audit_logs').insert(entry))
        .then(({ error }) => {
            if (error) {
                // Minimal console log on error
                Logger.warn('[ServerAuditLog] Supabase insert failed', {
                    meta: {
                        action,
                        target,
                        error: error.message,
                        code: error.code
                    }
                });
            } else {
                // Minimal console log on success
                Logger.info('[ServerAuditLog] Action recorded', {
                    meta: {
                        action,
                        target,
                        user_id: userId ?? null,
                        ip_address: ip,
                        ok: true
                    }
                });
            }
        })
        .catch(err => {
            Logger.error('[ServerAuditLog] Exception', {
                error: err.message || String(err),
                meta: { action, target }
            });
        });
}

function sanitizeMetadata(meta?: Record<string, unknown>): Record<string, unknown> | undefined {
    if (!meta) return undefined;

    try {
        // 2) Strict Production Mode (allowlist)
        if (process.env.AUDIT_STRICT_MODE === 'true') {
            const ALLOWLIST = new Set([
                'store_id', 'product_id', 'qty', 'amount', 'order_id',
                'route', 'status', 'status_code', 'duration_ms', 'error_code'
            ]);

            const filtered: Record<string, unknown> = { _strict: true };
            for (const [key, value] of Object.entries(meta)) {
                if (ALLOWLIST.has(key)) {
                    filtered[key] = value;
                }
            }
            return filtered;
        }

        // Standard Mode with PII Redaction
        const redacted = JSON.parse(JSON.stringify(meta), (key, value) => {
            // 1. Redact secrets
            if (/password|token|key|authorization|secret/i.test(key)) {
                return '[REDACTED]';
            }
            // 2. Redact PII
            if (/email|phone|name|address|comment|message|customer|client|first_name|last_name|full_name/i.test(key)) {
                return '[REDACTED_PII]';
            }
            // 3. Check string values for JWT-like patterns
            if (typeof value === 'string' && /^[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+$/.test(value)) {
                return '[REDACTED_TOKEN]';
            }
            return value;
        });

        // Size check (approximate via JSON string length)
        const jsonStr = JSON.stringify(redacted);
        if (jsonStr.length > 8192) { // 8KB limit
            return {
                _truncated: true,
                originalSize: jsonStr.length,
                keys: Object.keys(redacted).slice(0, 50)
            };
        }

        return redacted;
    } catch (e) {
        return { _error: 'Metadata sanitization failed' };
    }
}

import { OrderItem, SavedOrder } from '@/types/order';
import { SKUCategory } from '@/types/bi';

const CATEGORY_EMOJI: Record<string, string> = {
    'ВАРЕНИКИ': '🥟',
    'ПЕЛЬМЕНІ': '🥢',
    'ХІНКАЛІ': '🥡',
    'ЧЕБУРЕКИ': '🌯',
    'КОВБАСКИ': '🌭',
    'ГОЛУБЦІ': '🥬',
    'КОТЛЕТИ': '🥩',
    'СИРНИКИ': '🥞',
    'ФРИКАДЕЛЬКИ': '🧆',
    'ЗРАЗИ': '🥔',
    'ПЕРЕЦЬ ФАРШИРОВАНИЙ': '🫑',
    'МЛИНЦІ': '🥞',
    'БЕНДЕРИКИ': '🌮'
};

const getEmoji = (category: string) => CATEGORY_EMOJI[category] || '📦';

interface CategoryGroup {
    category: SKUCategory;
    emoji: string;
    totalKg: number;
    items: OrderItem[];
}

function groupByCategory(items: OrderItem[]): CategoryGroup[] {
    const categoryMap = new Map<SKUCategory, Map<string, number>>();

    items.forEach(item => {
        if (!categoryMap.has(item.category)) {
            categoryMap.set(item.category, new Map());
        }
        const productMap = categoryMap.get(item.category)!;
        const currentKg = productMap.get(item.productName) || 0;
        productMap.set(item.productName, currentKg + item.kg);
    });

    return Array.from(categoryMap.entries())
        .map(([category, products]) => {
            const productList = Array.from(products.entries()).map(([productName, kg]) => ({
                productName,
                kg
            })).sort((a, b) => a.productName.localeCompare(b.productName));

            const totalKg = productList.reduce((sum, p) => sum + p.kg, 0);

            return {
                category,
                emoji: getEmoji(category),
                totalKg,
                // Partial OrderItem for formatting
                items: productList as any[]
            };
        })
        .sort((a, b) => b.totalKg - a.totalKg);
}

export function formatOrderMessage(items: OrderItem[], date: string = new Date().toISOString()): string {
    const lines: string[] = [];

    // Header
    lines.push('📋 ЗАМОВЛЕННЯ НА ВИРОБНИЦТВО');
    lines.push('═'.repeat(40));
    lines.push(`📅 Дата: ${new Date(date).toLocaleString('uk-UA', {
        day: '2-digit',
        month: '2-digit',
        year: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
    })}`);
    lines.push('');

    // Group by category
    const byCategory = groupByCategory(items);

    byCategory.forEach(({ category, emoji, totalKg, items }) => {
        lines.push(`${emoji} ${category}: ${totalKg.toFixed(1)} кг`);
        lines.push('─'.repeat(40));

        items.forEach(item => {
