    if (auth.error) return auth.error;

    try {
        const body: DistributionRequest = await request.json();
        const { productId, productionQuantity } = body;

        // Fetch stats for this product
        const { data: stores, error } = await supabase
            .from('v_pizza_distribution_stats')
            .select('*')
            .eq('product_id', productId);

        if (error || !stores) {
            throw new Error(error?.message || 'Failed to fetch distribution stats');
        }

        // Initialize result map
        const result: Record<number, number> = {};
        let remaining = productionQuantity;
        const storesData = stores as any[]; // Use any to be flexible with column names

        // Helper to accessor
        const getId = (s: any) => s.spot_id || s.store_id || 0;
        const getStock = (s: any) => Number(s.stock_now ?? s.current_stock ?? 0);
        const getMin = (s: any) => Number(s.norm_3_days ?? s.min_stock ?? 0);
        const getNeed = (s: any) => Number(s.need_net ?? s.net_need ?? 0);
        const getPriority = (s: any) => s.priority ?? s.surplus_priority ?? 999;

        // Initialize distribution for all stores to 0
        storesData.forEach(s => {
            const id = getId(s);
            if (id) result[id] = 0;
        });

        // --- STAGE 2: "Hygiene" (Fill Zeros) ---
        // Give 1 unit to stores with 0 stock
        const zeroStockStores = storesData.filter(s => getStock(s) === 0);
        for (const store of zeroStockStores) {
            if (remaining > 0) {
                const id = getId(store);
                if (id) {
                    result[id] += 1;
                    remaining -= 1;
                }
            }
        }

        // --- STAGE 3: Proportional Deficit ---
        if (remaining > 0) {
            let totalNetNeed = 0;
            const storeNeeds: { storeId: number; need: number }[] = [];

            storesData.forEach(s => {
                const id = getId(s);
                if (!id) return;

                const distributedSoFar = result[id];
                const effectiveStock = getStock(s) + distributedSoFar;
                // Recalculate need based on effective stock
                // If effective stock >= min (norm), need is 0
                // Otherwise need is min - effective

                // NOTE: logic was: if need_net > 0...
                // But need_net from view is static. We must account for Stage 2 distribution.
                const min = getMin(s);
                const need = Math.max(0, min - effectiveStock);

                if (need > 0) {
                    storeNeeds.push({ storeId: id, need });
                    totalNetNeed += need;
                }
            });

            if (totalNetNeed > 0) {
                if (remaining < totalNetNeed) {
                    // DEFICIT MODE: Proportional distribution
                    const K = remaining / totalNetNeed;

                    for (const item of storeNeeds) {
                        const qty = Math.floor(item.need * K);
                        if (qty > 0 && remaining >= qty) {
                            result[item.storeId] += qty;
                            remaining -= qty;
                        }
                    }
                } else {
                    // SURPLUS/ENOUGH MODE: Fill all needs to 100%
                    for (const item of storeNeeds) {
                        if (remaining >= item.need) {
                            result[item.storeId] += item.need;
                            remaining -= item.need;
                        } else {
                            // Should not happen if remaining >= totalNetNeed, but safety check
                            result[item.storeId] += remaining;
                            remaining = 0;
                        }
                    }
                }
            }
        }

        // --- STAGE 4: Surplus Distribution ---
        // If still remaining, distribute by priority
        if (remaining > 0) {
            const sortedByPriority = [...storesData].sort((a, b) => {
                const pA = getPriority(a);
                const pB = getPriority(b);
                return pA - pB;
            });

            while (remaining > 0) {
                let distributedInLoop = false;
                for (const store of sortedByPriority) {
                    if (remaining <= 0) break;
                    const id = getId(store);
                    if (id) {
                        result[id] += 1;
                        remaining -= 1;
                        distributedInLoop = true;
                    }
                }
                if (!distributedInLoop) break;
            }
        }

        return NextResponse.json({
            productId,
            originalQuantity: productionQuantity,
            distributed: result,
            remaining // Should be 0
        });

    } catch (error) {
        console.error('[Calculate Distribution] Error:', error);
        return NextResponse.json({ error: String(error) }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { supabase } from '@/lib/supabase';
import { requireAuth } from '@/lib/auth-guard';

interface DistributionConfirmation {
    distributions: Array<{
        storeId: number;
        productId: number;
        quantity: number;
    }>;
    userId?: string; // Optional for logging current user
}

// Fixed Warehouse ID for "Цех Пиццерия Гравитон"
const SOURCE_WAREHOUSE_ID = 15;

/**
 * POST /api/pizza/confirm-distribution
 * Executing distribution: creates movement documents in DB
 */
export async function POST(request: NextRequest) {
    const auth = await requireAuth();
    if (auth.error) return auth.error;

    try {
        const body: DistributionConfirmation = await request.json();
        const { distributions, userId } = body;

        if (!distributions || distributions.length === 0) {
            return NextResponse.json({ success: true, message: 'No distributions to process' });
        }

        const results = [];
        const errors = [];

        // In a real app, we might want to batch this or use a stored procedure / transaction.
        // For now, we'll process sequentially or in parallel batches.

        // We need mapping from storeId (spot_id) to storage_id (warehouse)
        // This mapping might come from `v_pizza_distribution_stats` or separate query.
        // Let's assume passed storeId IS the target storage_id or we fetch it.
        // Looking at context, usually specific stores have specific storage IDs.
        // TЗ says: "Accordig to mapping in view (spot_id -> storage_id)"

        // Let's fetch the mapping first to be safe
        const { data: mapping, error: mapError } = await supabase
            .from('v_pizza_distribution_stats')
            .select('store_id, storage_id') // Assuming view has storage_id
        // If view doesn't have storage_id, we might need another table (e.g. shops)
        // Let's check typical structure or just assume store_id passed from FE is correct ID to move TO.
        // Wait, TЗ explicitly mentions "mapping from view (spot_id -> storage_id)".
        // I'll query unique store mapping.

        if (mapError) {
            throw new Error('Failed to fetch storage mapping');
        }

        const storeToStorageMap = new Map<number, number>();
        mapping?.forEach((row: any) => {
            if (row.store_id && row.storage_id) {
                storeToStorageMap.set(row.store_id, row.storage_id);
            }
        });

        for (const dist of distributions) {
            const { storeId, productId, quantity } = dist;

            if (quantity <= 0) continue;

            const targetStorageId = storeToStorageMap.get(storeId);

            if (!targetStorageId) {
                errors.push(`No storage mapping for store ${storeId}`);
                continue;
            }

            // Create movement
            // NOTE: Table name and structure is assumed based on standard patterns (movements / operations)
            // I will use a generic 'movements' table structure, but this might need adjustment if schema differs.
            // "Система должна генерировать документы перемещения (movements)"

            const { data, error } = await supabase
                .from('movements')
                .insert({
                    source_storage_id: SOURCE_WAREHOUSE_ID,
                    target_storage_id: targetStorageId,
                    product_id: productId,
                    quantity: quantity,
                    status: 'pending', // or 'completed'
                    created_by: userId || 'system',
                    created_at: new Date().toISOString(),
                    type: 'distribution'
                })
                .select();

            if (error) {
                errors.push(`Failed to move product ${productId} to store ${storeId}: ${error.message}`);
            } else {
                results.push(data);
            }
        }

        if (errors.length > 0) {
            return NextResponse.json({
                success: false,
                message: 'Some distributions failed',
                errors,
                results
            }, { status: 207 }); // Multi-Status
        }

        return NextResponse.json({
            success: true,
            message: 'Distribution confirmed and movements created',
            count: results.length
        });

    } catch (error) {
        console.error('[Confirm Distribution] Error:', error);
        return NextResponse.json({ error: String(error) }, { status: 500 });
    }
}

