'use client';

import React, { useMemo, useEffect, useState } from 'react';
import useSWR from 'swr';
import { DashboardLayout } from '@/components/layout';
import { TaskCard } from '@/components/TaskCard';
import { ProductionTask, BI_Metrics, SupabaseDeficitRow, SKUCategory } from '@/types/bi';
import { transformDeficitData } from '@/lib/transformers';
import { ErrorBoundary } from '@/components/ErrorBoundary';
import { RotateCw, Globe } from 'lucide-react';
import { UI_TOKENS } from '@/lib/design-tokens';
import { useStore } from '@/context/StoreContext';

import { authedFetcher } from '@/lib/authed-fetcher';

const fetcher = authedFetcher;

const HeaderKPI = ({ label, value }: { label: string; value: string | number }) => (
    <div className="px-5 py-3 bg-[#141C27] rounded-[10px] min-w-[150px] border border-[#1F2630] flex flex-col justify-center">
        <span className="text-[11px] font-bold text-[#8B949E] uppercase tracking-widest mb-1">{label}</span>
        <span className="text-[14px] font-black text-[#E6EDF3]">{value}</span>
    </div>
);

const LegendItem = ({ color, label }: { color: string; label: string }) => (
    <div className="flex items-center gap-2 px-2">
        <div className="w-3 h-3 rounded-full shadow-[0_0_8px_rgba(0,0,0,0.5)]" style={{ backgroundColor: color }} />
        <span className="text-[12px] font-medium text-[#E6EDF3] tracking-tight">{label}</span>
    </div>
);

export default function ProductionPage() {
    const { currentCapacity } = useStore();
    const { data: deficitData, error: deficitError, mutate: mutateDeficit } = useSWR<SupabaseDeficitRow[]>(
        '/api/graviton/deficit',
        fetcher,
        { refreshInterval: 30000 }
    );

    const { data: metrics, error: metricsError, mutate: mutateMetrics } = useSWR<BI_Metrics>(
        '/api/graviton/metrics',
        fetcher,
        { refreshInterval: 30000 }
    );

    const [isRefreshing, setIsRefreshing] = React.useState(false);
    const [now, setNow] = useState(new Date());

    const tasks = useMemo((): ProductionTask[] => {
        if (!deficitData || !Array.isArray(deficitData)) return [];
        return transformDeficitData(deficitData);
    }, [deficitData]);

    useEffect(() => {
        const timer = setInterval(() => setNow(new Date()), 1000);
        return () => clearInterval(timer);
    }, []);

    const tasksByCategory = useMemo(() => {
        const grouped: Record<string, ProductionTask[]> = {};
        tasks.forEach(task => {
            if (!grouped[task.category]) grouped[task.category] = [];
            grouped[task.category].push(task);
        });
        return grouped;
    }, [tasks]);

    const formattedDate = now.toLocaleDateString('uk-UA', { weekday: 'long', day: 'numeric', month: 'long' });
    const formattedTime = now.toLocaleTimeString('uk-UA', { hour: '2-digit', minute: '2-digit' });

    const handleRefresh = async () => {
        setIsRefreshing(true);
        try {
            const response = await fetch('http://localhost:5678/webhook-test/operator', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ action: 'refresh_stock', timestamp: new Date().toISOString() })
            });

            if (response.ok) {
                await new Promise(resolve => setTimeout(resolve, 2000));
                await Promise.all([mutateDeficit(), mutateMetrics()]);
            }
        } catch (err) {
            console.error('Refresh error:', err);
        } finally {
            setIsRefreshing(false);
        }
    };

    const handleStatusChange = (taskId: string, status: ProductionTask['status']) => {
        console.log(`Task ${taskId} status changed to ${status}`);
    };

    if (deficitError || metricsError) {
        return <div className="p-10 text-red-500 font-bold">Помилка завантаження даних виробництва.</div>;
    }

    if (!metrics || !deficitData) {
        return <div className="p-10 text-slate-500 animate-pulse uppercase font-bold">Синхронізація двигуна виробництва...</div>;
    }

    return (
        <DashboardLayout currentWeight={metrics.shopLoad} maxWeight={currentCapacity}>
            <div className="max-w-[1200px] mx-auto min-h-[calc(100vh-160px)]">
                {/* Outer Panel like SVG */}
                <div className="bg-[#0B0F14] rounded-[16px] border border-[#1F2630] p-6 lg:p-10 shadow-2xl h-full flex flex-col">

                    {/* Header Shell according to SVG */}
                    <div className="bg-[#111823] rounded-xl border border-[#202938] px-8 py-5 mb-6 flex flex-col md:flex-row justify-between items-center gap-6 shadow-xl relative overflow-hidden">
                        {/* Interactive Background Glow */}
                        <div className="absolute top-0 left-0 w-full h-[1px] bg-gradient-to-r from-transparent via-[#58A6FF]/20 to-transparent" />

                        <div className="flex flex-col gap-1">
                            <div className="flex items-center gap-3">
                                <h1 className="text-[18px] font-black text-[#E6EDF3] tracking-tighter uppercase whitespace-nowrap">
                                    Галя Балувана <span className="text-[#8B949E] px-1">•</span> <span className="text-[#58A6FF]">Центр управління</span>
                                </h1>
                                <div className="bg-[#1F6FEB] px-2 py-0.5 rounded-full flex items-center gap-1 shadow-[0_0_15px_rgba(31,111,235,0.3)]">
                                    <div className="w-1.5 h-1.5 rounded-full bg-white animate-pulse" />
                                    <span className="text-[10px] font-black text-white uppercase tracking-widest">LIVE</span>
                                </div>
                            </div>
                            <div className="flex items-center gap-2 text-[11px] font-bold text-[#8B949E] uppercase tracking-[0.1em]">
                                <span>{formattedDate}</span>
                                <span className="text-[#3FB950]">•</span>
                                <span className="text-[#E6EDF3]">{formattedTime}</span>
                                <span className="text-[#3FB950]">•</span>
                                <span className="text-[#3FB950]">ОНЛАЙН</span>
                            </div>
                        </div>

                        <div className="flex flex-wrap gap-3">
                            <HeaderKPI label="Дефіцит кг" value="1.2k кг" />
                            <HeaderKPI label="Критичні SKU" value={metrics.criticalSKU} />
                            <HeaderKPI label="Завантаження" value={`${Math.round(metrics.shopLoad / ((currentCapacity || 450) / 100))}%`} />
                            <HeaderKPI label="Зміна / SLA" value="98%" />
                        </div>
                    </div>

                    {/* Legend Bar matching SVG */}
                    <div className="bg-[#111823] rounded-xl border border-[#1F2630] px-6 py-4 mb-8 flex items-center gap-8 shadow-sm">
                        <span className="text-[11px] font-black text-[#8B949E] uppercase tracking-[0.15em]">Легенда:</span>
                        <div className="flex items-center gap-8">
                            <LegendItem color={UI_TOKENS.colors.priority.critical} label="Critical" />
                            <LegendItem color={UI_TOKENS.colors.priority.high} label="High" />
                            <LegendItem color={UI_TOKENS.colors.priority.reserve} label="Reserve" />
                            <LegendItem color={UI_TOKENS.colors.priority.normal} label="Normal" />
                        </div>
                    </div>

                    {/* Main Content Columns matching SVG */}
                    <div className="flex-1 grid grid-cols-12 gap-8">
                        {/* Column 1: Queue */}
                        <div className="col-span-12 lg:col-span-4 flex flex-col">
                            <div className="flex items-center gap-3 mb-6 px-2">
                                <h2 className="text-[14px] font-black text-[#E6EDF3] tracking-tight">Production Queue</h2>
                                <div className="flex-1 h-px bg-gradient-to-r from-[#1F2630] to-transparent" />
                            </div>
                            <div className="flex-1 overflow-y-auto custom-scrollbar space-y-6 pr-2">
                                <ErrorBoundary>
                                    {Object.entries(tasksByCategory).map(([category, catTasks]) => (
                                        <div key={category} className="space-y-3">
                                            <h3 className="text-[10px] font-black text-[#8B949E] uppercase tracking-[0.2em] flex items-center gap-2">
                                                <div className="w-1 h-3 bg-[#58A6FF] rounded-full" />
                                                {category}
                                            </h3>
                                            <div className="space-y-4">
                                                {catTasks.map(task => (
                                                    <TaskCard key={task.id} task={task} onStatusChange={handleStatusChange} />
                                                ))}
                                            </div>
                                        </div>
                                    ))}
                                </ErrorBoundary>
                            </div>
                        </div>

                        {/* Column 2: Analytics */}
                        <div className="col-span-12 lg:col-span-4 flex flex-col border-x border-[#1F2630] border-dashed px-4">
                            <div className="flex items-center gap-3 mb-6 px-2">
                                <h2 className="text-[14px] font-black text-[#E6EDF3] tracking-tight">Network Analytics</h2>
                                <div className="flex-1 h-px bg-gradient-to-r from-[#1F2630] to-transparent" />
                            </div>
                            <div className="space-y-6">
                                <div className="bg-[#0F1622] rounded-xl border border-[#1E2A3A] p-6 h-[170px] shadow-sm">
                                    <h3 className="text-[12px] font-bold text-[#8B949E] uppercase tracking-widest mb-4">Top deficit by category</h3>
                                    <div className="h-full opacity-20 border-t border-dashed border-[#1E2A3A] mt-8" />
                                </div>
                                <div className="bg-[#0F1622] rounded-xl border border-[#1E2A3A] p-6 h-[190px] shadow-sm">
                                    <h3 className="text-[12px] font-bold text-[#8B949E] uppercase tracking-widest mb-4">Store risk heatmap</h3>
                                    <div className="grid grid-cols-6 gap-2 mt-4">
                                        {Array.from({ length: 18 }).map((_, i) => (
                                            <div key={i} className="aspect-square rounded-md bg-[#E5534B]/10 border border-[#E5534B]/20 transition-all hover:bg-[#E5534B]/20 cursor-pointer" />
                                        ))}
                                    </div>
                                </div>
                            </div>
                        </div>

                        {/* Column 3: Alerts */}
                        <div className="col-span-12 lg:col-span-4 flex flex-col">
                            <div className="flex items-center gap-3 mb-6 px-2">
                                <h2 className="text-[14px] font-black text-[#E6EDF3] tracking-tight">Alerts & Actions</h2>
                                <div className="flex-1 h-px bg-gradient-to-r from-[#1F2630] to-transparent" />
                            </div>
                            <div className="space-y-6">
                                <div className="bg-[#1A0F14] rounded-xl border border-[#3A1E2A] p-6 h-[130px] shadow-[inset_0_0_20px_rgba(229,83,75,0.05)] transition-all hover:border-[#F85149]/50">
                                    <h3 className="text-[12px] font-black text-[#F85149] uppercase tracking-widest mb-3 flex items-center gap-2">
                                        <div className="w-1.5 h-1.5 rounded-full bg-[#F85149] animate-pulse" />
                                        Critical Stores
                                    </h3>
                                    <p className="text-[11px] text-[#8B949E] leading-relaxed">3 локації потребують негайного поповнення SKU для запобігання відсутності товару.</p>
                                </div>
                                <div className="bg-[#0F1622] rounded-xl border border-[#1E2A3A] p-6 flex-1 min-h-[230px] shadow-sm">
                                    <h3 className="text-[12px] font-bold text-[#8B949E] uppercase tracking-widest mb-6">Action panel</h3>
                                    <div className="space-y-3">
                                        <button
                                            onClick={handleRefresh}
                                            disabled={isRefreshing}
                                            className="w-full py-3 bg-[#58A6FF] text-[#0B0F14] text-[11px] font-black uppercase rounded-lg shadow-lg shadow-blue-500/10 hover:brightness-110 active:scale-[0.98] transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                                        >
                                            {isRefreshing && <RotateCw size={14} className="animate-spin" />}
                                            {isRefreshing ? 'Оновлення...' : 'Оновити залишки'}
                                        </button>
                                        <button className="w-full py-3 border border-[#1E2A3A] text-[#8B949E] text-[11px] font-black uppercase rounded-lg hover:bg-white/5 transition-all">
                                            Синхронізувати вебхук
                                        </button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </DashboardLayout>
    );
}

'use client';

import React, { useMemo, useState } from 'react';
import { ProductionTask } from '@/types/bi';
import { AlertCircle, TrendingUp, MapPin, ChevronRight } from 'lucide-react';
import { cn } from '@/lib/utils';
import { UI_TOKENS } from '@/lib/design-tokens';
import { useStore } from '@/context/StoreContext';

export const BIInsights = ({ queue }: { queue: ProductionTask[] }) => {
    const { selectedStore } = useStore();
    const [expandedStore, setExpandedStore] = useState<string | null>(null);
    const [hoveredStore, setHoveredStore] = useState<string | null>(null);

    const insights = useMemo(() => {
        const riskStoresMap = queue.reduce((acc: Record<string, { count: number, items: string[] }>, t) => {
            t.stores.forEach(s => {
                if (selectedStore !== 'Усі' && s.storeName !== selectedStore) return;

                if (s.currentStock === 0) {
                    if (!acc[s.storeName]) acc[s.storeName] = { count: 0, items: [] };
                    acc[s.storeName].count++;
                    acc[s.storeName].items.push(t.name);
                }
            });
            return acc;
        }, {});

        const topRiskStores = Object.entries(riskStoresMap)
            .map(([store, data]) => ({ store, ...data }))
            .sort((a, b) => b.count - a.count)
            .slice(0, 3);

        return { topRiskStores };
    }, [queue, selectedStore]);

    const toggleStore = (store: string) => {
        setExpandedStore(expandedStore === store ? null : store);
    };

    return (
        <div className="flex flex-col gap-4 h-full font-sans">
            {/* 🎯 HEADER SECTION - COMPACT */}
            <div className="flex flex-col items-center justify-center text-center space-y-1.5 mb-1">
                <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-[#E74856]/10 border border-[#E74856]/20 shadow-[0_0_15px_rgba(231,72,86,0.1)]">
                    <AlertCircle size={12} className="text-[#E74856] animate-pulse" />
                    <span className="text-[9px] font-black text-[#E74856] uppercase tracking-[0.2em]">ЗВЕРНУТИ УВАГУ</span>
                </div>
            </div>

            {/* 🏬 RISK STORES GLASS PANEL */}
            <div className="glass-panel-premium p-0.5 rounded-xl overflow-hidden border-white/10">
                <div className="flex items-center gap-3 px-4 py-3 border-b border-white/5 bg-white/[0.02]">
                    <div className="p-1.5 rounded-lg bg-[#E74856]/10">
                        <MapPin size={14} className="text-[#E74856]" />
                    </div>
                    <div className="flex flex-col">
                        <h4 className="text-[11px] font-black text-white uppercase tracking-wider">
                            {selectedStore === 'Усі' ? 'Ризики дефіциту' : 'Аналіз ризиків'}
                        </h4>
                        <span className="text-[8px] font-bold text-white/30 uppercase tracking-widest leading-none mt-0.5">
                            {selectedStore === 'Усі' ? 'Топ-3 критичних локацій' : selectedStore}
                        </span>
                    </div>
                </div>

                <div className="p-2.5 space-y-2">
                    {insights.topRiskStores.length === 0 ? (
                        <div className="py-4 text-center">
                            <span className="text-[10px] font-bold text-white/20 uppercase tracking-widest italic">Ризиків не виявлено</span>
                        </div>
                    ) : (
                        insights.topRiskStores.map(({ store, count, items }) => (
                            <div key={store} className="relative group/card">
                                <button
                                    onClick={() => toggleStore(store)}
                                    onMouseEnter={() => setHoveredStore(store)}
                                    onMouseLeave={() => setHoveredStore(null)}
                                    className={cn(
                                        "w-full px-4 py-3 text-left rounded-lg transition-all duration-300 overflow-hidden border",
                                        expandedStore === store
                                            ? "border-[#E74856]/40 bg-[#E74856]/5 shadow-[0_0_15px_rgba(231,72,86,0.1)]"
                                            : "border-white/5 bg-white/[0.03] hover:bg-white/[0.05] hover:border-white/10"
                                    )}
                                    style={{ backdropFilter: 'blur(8px)', WebkitBackdropFilter: 'blur(8px)' }}
                                >
                                    {/* Accent line */}
                                    <div className={cn(
                                        "absolute left-0 top-0 bottom-0 w-0.5 transition-transform duration-500",
                                        expandedStore === store ? "scale-y-100" : "scale-y-0"
                                    )} style={{ background: '#E74856' }} />

                                    <div className="flex items-center justify-between relative z-10">
                                        <div className="flex flex-col">
                                            <span className="text-[11px] font-black text-white/90 uppercase tracking-wide">
                                                {store}
                                            </span>
                                            <span className="text-[8px] font-bold text-white/20 uppercase tracking-[0.1em] mt-0.5">
                                                {items.length} позицій
                                            </span>
                                        </div>
                                        <div className="flex items-center gap-3">
                                            <div className="flex flex-col items-end">
                                                <span className="text-[12px] font-black text-[#E74856] leading-none">
                                                    {count}
                                                </span>
                                                <span className="text-[7px] font-black text-[#E74856]/60 uppercase tracking-tighter mt-0.5">ДЕФІЦИТ</span>
                                            </div>
                                            <ChevronRight size={14} className={cn(
                                                "transition-transform duration-300 text-white/10",
                                                expandedStore === store && "rotate-90 text-[#E74856]"
                                            )} />
                                        </div>
                                    </div>
                                </button>

                                {expandedStore === store && (
                                    <div className="mt-1 px-4 pb-2 space-y-1 animate-in fade-in slide-in-from-top-1 duration-200">
                                        {items.map((item, idx) => (
                                            <div key={idx} className="flex items-center gap-2 py-1 border-b border-white/5 last:border-0 group/item">
                                                <div className="w-1 h-1 rounded-full bg-[#E74856]/40" />
                                                <span className="text-[9px] font-bold text-white/50 tracking-tight group-hover/item:text-white transition-colors">{item}</span>
                                            </div>
                                        ))}
                                    </div>
                                )}
                            </div>
                        ))
                    )}
                </div>
            </div>

            {/* 📈 SYSTEM FORECAST - COMPACT */}
            <div className="glass-panel-premium p-4 rounded-xl flex flex-col items-center border-white/10">
                <div className="flex items-center gap-2 mb-3 self-start">
                    <div className="p-1.5 rounded-lg bg-emerald-500/10">
                        <TrendingUp className="text-emerald-400" size={14} />
                    </div>
                    <h4 className="text-[11px] font-black text-white uppercase tracking-wider">Прогноз</h4>
                </div>

                <div className="w-full h-16 bg-black/20 rounded-lg border border-white/5 flex flex-col items-center justify-center relative overflow-hidden group">
                    <div className="absolute inset-0 opacity-10">
                        <svg className="w-full h-full" overflow="visible" viewBox="0 0 100 100" preserveAspectRatio="none">
                            <path d="M0,80 Q15,20 30,50 T60,30 T90,60 L100,50" fill="none" stroke="#00D4FF" strokeWidth="1" className="animate-shimmer" />
                        </svg>
                    </div>
                    <span className="text-[9px] text-white/30 font-black uppercase tracking-[0.3em] mb-0.5 relative z-10">AI АНАЛІЗ</span>
                    <span className="text-[8px] text-white/10 font-bold uppercase tracking-widest relative z-10">Live Stream...</span>
                </div>
            </div>

            {/* ⚡ QUICK ACTIONS - MINI */}
            <div className="glass-panel-premium p-3 rounded-xl flex items-center justify-between gap-3 bg-[#E74856]/5 border-dashed border-[#E74856]/20">
                <div className="flex items-center gap-2">
                    <AlertCircle className="text-amber-500/60" size={14} />
                    <span className="text-[9px] font-black text-white/70 uppercase tracking-tight">Смарт-асистент</span>
                </div>
                <button
                    className="px-4 py-1.5 bg-emerald-600/80 hover:bg-emerald-500 text-white text-[9px] font-black uppercase tracking-widest rounded-lg shadow-lg active:scale-95 transition-all"
                >
                    Згенерувати
                </button>
            </div>
        </div>
    );
};

'use client';

import React, { useState, useMemo, useEffect } from 'react';
import { ChevronDown, ChevronRight, CheckCircle2, Package, AlertTriangle, X, RefreshCw } from 'lucide-react';
import { ProductionTask, PriorityKey, SKUCategory, PriorityHierarchy, CategoryGroup } from '@/types/bi';
import { cn } from '@/lib/utils';
import { UI_TOKENS } from '@/lib/design-tokens';
import { useStore } from '@/context/StoreContext';
import { StoreSpecificView } from './StoreSpecificView';
import { OrderConfirmationModal } from './OrderConfirmationModal';
import { ShareOptionsModal } from './ShareOptionsModal';
import { OrderItem, SharePlatform } from '@/types/order';
import { generateExcel, groupItemsByCategory } from '@/lib/order-export';
import { ProductCard } from './graviton/ProductCard';

const CATEGORY_EMOJI: Record<string, string> = {};

const getEmoji = (category: string) => '';

interface Props {
  deficitQueue: ProductionTask[];
  allProductsQueue: ProductionTask[];
  refreshUrgency?: 'normal' | 'warning' | 'critical';
  onMetricsUpdate?: (metrics: { totalKg: number, criticalWeight: number, reserveWeight: number, criticalSKU: number, reserveSKU: number }) => void;
  onManualRefresh?: () => void;
  planningDays?: number;
  onPlanningDaysChange?: (days: number) => void;
}

export const BIPowerMatrix = ({
  deficitQueue,
  allProductsQueue,
  refreshUrgency = 'normal',
  onMetricsUpdate,
  onManualRefresh,
  planningDays: controlledPlanningDays,
  onPlanningDaysChange
}: Props) => {
  const { selectedStore, currentCapacity } = useStore();

  // Local state for fallback if not controlled
  const [localPlanningDays, setLocalPlanningDays] = useState<number>(1);

  // Use controlled value if present, else local
  const planningDays = controlledPlanningDays !== undefined ? controlledPlanningDays : localPlanningDays;

  // Handler to update both
  const handleSetPlanningDays = (days: number) => {
    if (onPlanningDaysChange) {
      onPlanningDaysChange(days);
    } else {
      setLocalPlanningDays(days);
    }
  };

  const SAFETY_BUFFER_DAYS = 4;

  const [expandedPriorities, setExpandedPriorities] = useState<Set<PriorityKey>>(
    new Set(['critical', 'high'] as PriorityKey[])
  );
  const [expandedCategories, setExpandedCategories] = useState<Set<string>>(new Set());
  const [expandedProducts, setExpandedProducts] = useState<Set<string>>(new Set());
  const [selectedStores, setSelectedStores] = useState<Map<string, boolean>>(new Map());

  // Independent state for RESERVE (Step 89)
  const [expandedReserve, setExpandedReserve] = useState(false);
  const [expandedReserveCategories, setExpandedReserveCategories] = useState<Set<string>>(new Set());
  const [expandedReserveProducts, setExpandedReserveProducts] = useState<Set<string>>(new Set());

  // Modal states
  const [isOrderModalOpen, setIsOrderModalOpen] = useState(false);
  const [showShiftRestrictionModal, setShowShiftRestrictionModal] = useState(false);
  const [showShareModal, setShowShareModal] = useState(false);
  const [orderData, setOrderData] = useState<any>(null);
  const [orderItems, setOrderItems] = useState<OrderItem[]>([]);
  const [isOrderConfirmed, setIsOrderConfirmed] = useState(false);

  // Reset confirmation when selection changes
  useEffect(() => {
    setIsOrderConfirmed(false);
  }, [selectedStores]);

  // Вибираємо правильний датасет залежно від режиму
  // ⚠️ ALWAYS use allProductsQueue as base for dynamic calculation to catch items that will become deficit soon
  // previously: const rawQueue = selectedStore === 'Усі' ? deficitQueue : allProductsQueue;
  const rawQueue = allProductsQueue;

  const dynamicQueue = useMemo(() => {
    return rawQueue.map(item => {
      // 1. Filter and Recalculate for each store
      const updatedStores = item.stores.filter(store => {
        // Force include if we are in "Store View" (selectedStore !== 'Усі')
        // Otherwise apply Visibility Logic: stock < minStock

        const avgRaw = parseFloat(String(store.avgSales));
        const stockRaw = parseFloat(String(store.currentStock));
        const minStockRaw = parseFloat(String(store.minStock));

        const avg = isNaN(avgRaw) ? 0 : avgRaw;
        const stock = isNaN(stockRaw) ? 0 : stockRaw;
        const minStock = isNaN(minStockRaw) ? 0 : minStockRaw;

        // VISIBILITY LOGIC
        if (selectedStore === 'Усі') {
          // Show only if there is a deficit relative to Min Stock
          // Debugging safety
          if (minStock === 0 && stock === 0) return false;

          return stock < minStock;
        }

        // In specific store view, we show everything for that store (filtering by store happens in filteredQueue)
        return true;
      }).map(store => {
        const avgRaw = parseFloat(String(store.avgSales));
        const stockRaw = parseFloat(String(store.currentStock));
        const minStockRaw = parseFloat(String(store.minStock)); // Get Min Stock

        const avg = isNaN(avgRaw) ? 0 : avgRaw;
        const stock = isNaN(stockRaw) ? 0 : stockRaw;
        const minStock = isNaN(minStockRaw) ? 0 : minStockRaw;

        // USER REQUEST:
        // 1. Store View (Monitoring): Need = Min Stock - Fact (Immediate Deficit)
        // 2. All Stores View (Production Planning): Need = Min Stock + (Planning Days * Avg Sales) - Fact (Dynamic Plan)

        let finalOrder = 0;

        if (selectedStore !== 'Усі') {
          // Store Monitoring Mode
          finalOrder = Math.max(0, Math.ceil(minStock - stock));
        } else {
          // Production Planning Mode (Dynamic with Days)
          finalOrder = Math.max(0, Math.ceil(minStock + (avg * planningDays) - stock));
        }

        // Urgent is essentially the same as Need in this context if Need > 0
        const urgentOrder = finalOrder;

        return {
          ...store,
          recommendedKg: finalOrder,
          deficitKg: urgentOrder
        };
      });

      if (updatedStores.length === 0) return null;

      // Recalculate aggregated values for the item
      // Recalculate aggregated values for the item
      const totalRecommended = updatedStores.reduce((sum, s) => sum + (s.recommendedKg || 0), 0);
      const totalDeficit = updatedStores.reduce((sum, s) => sum + (s.deficitKg || 0), 0);

      // Recalculate Priority based on dynamic values
      let newPriority: PriorityKey = item.priority;

      if (totalDeficit > 0) {
        newPriority = 'critical';
      } else if (totalRecommended > 0) {
        newPriority = 'reserve';
      } else {
        newPriority = 'normal'; // Should typically be filtered out by visibility logic anyway
      }

      return {
        ...item,
        priority: newPriority,
        stores: updatedStores,
        recommendedQtyKg: totalRecommended,
        totalDeficitKg: totalDeficit
      } as ProductionTask;
    }).filter((item): item is ProductionTask => {
      if (item === null) return false;
      // Final Safety Filter: If we are in "All Stores", show only if "finalOrder" > 0
      if (selectedStore === 'Усі') {
        return (item.recommendedQtyKg || 0) > 0;
      }
      return true;
    });
  }, [rawQueue, planningDays, selectedStore]);

  // Фільтруємо чергу залежно від обраного магазину
  const filteredQueue = useMemo((): ProductionTask[] => {
    if (selectedStore === 'Усі') return dynamicQueue;

    return dynamicQueue
      .map(item => {
        const storeData = item.stores.find(s => s.storeName === selectedStore);
        if (!storeData) return null;

        return {
          ...item,
          stores: [storeData],
          recommendedQtyKg: storeData.recommendedKg,
          totalDeficitKg: storeData.deficitKg
        } as ProductionTask;
      })
      .filter((item): item is ProductionTask => item !== null);
  }, [dynamicQueue, selectedStore]);

  // ДОДАЙ ЦЕЙ CONSOLE.LOG (Step 93):
  console.log('📊 Статистика filteredQueue:', {
    total: filteredQueue.length,
    critical: filteredQueue.filter(i => i.priority === 'critical').length,
    high: filteredQueue.filter(i => i.priority === 'high').length,
    reserve: filteredQueue.filter(i => i.priority === 'reserve').length,
    sample: filteredQueue.slice(0, 3).map(i => ({ name: i.name, priority: i.priority }))
  });

  console.log('🔄 BIPowerMatrix Render | Planning Days:', planningDays);

  // ============================================================================
  // ALL HOOKS MUST BE CALLED UNCONDITIONALLY (Rules of Hooks)
  // ============================================================================

  // Підрахунок обраної ваги
  const selectedWeight = useMemo(() => {
    let total = 0;
    filteredQueue.forEach(item => {
      item.stores.forEach(store => {
        const key = `${item.productCode}_${store.storeName}`;
        if (selectedStores.has(key)) {
          total += store.recommendedKg;
        }
      });
    });
    return Math.round(total);
  }, [filteredQueue, selectedStores]);

  const hierarchy = useMemo((): PriorityHierarchy[] => {
    const priorityMap = new Map<PriorityKey, Map<SKUCategory, Map<string, ProductionTask[]>>>();

    filteredQueue.forEach(item => {
      // Step 98: Merge high into critical
      let priorityLabel = item.priority || 'reserve';
      if (priorityLabel === 'high') priorityLabel = 'critical';

      const categoryName = item.category || 'Інше';
      const productId = item.productCode.toString();

      if (!priorityMap.has(priorityLabel)) {
        priorityMap.set(priorityLabel, new Map());
      }

      const categoryMap = priorityMap.get(priorityLabel)!;

      if (!categoryMap.has(categoryName)) {
        categoryMap.set(categoryName, new Map());
      }

      const productMap = categoryMap.get(categoryName)!;

      if (!productMap.has(productId)) {
        productMap.set(productId, []);
      }
      productMap.get(productId)!.push(item);
    });

    const priorityConfigs = [
      {
        key: 'critical',
        label: 'ТЕРМІНОВО (Stock < Buffer)',
        emoji: '🔥',
        color: '#E74856',
        colorDark: '#C41E3A',
        glow: '#FF6B6B'
      },
      {
        key: 'reserve',
        label: 'ПЛАНОВЕ ПОПОВНЕННЯ',
        emoji: '📅',
        color: '#007BA7',
        colorDark: '#005F8C',
        glow: '#00BCF2'
      }
    ] as const;

    return priorityConfigs.map(config => {
      const categoryMap = priorityMap.get(config.key as PriorityKey);
      if (!categoryMap || categoryMap.size === 0) return null;

      const categories: CategoryGroup[] = [];
      let totalKg = 0;

      categoryMap.forEach((productMap, categoryName) => {
        let categoryKg = 0;
        const products: ProductionTask[] = [];

        productMap.forEach((occurrences) => {
          const base = occurrences[0];
          const combinedStores = occurrences.flatMap(curr => curr.stores);
          const combinedRecommended = combinedStores.reduce((sum, s) => sum + s.recommendedKg, 0);
          const totalFactDeficit = combinedStores.reduce((sum, s) => sum + s.deficitKg, 0);

          products.push({
            ...base,
            stores: combinedStores,
            recommendedQtyKg: Math.round(combinedRecommended),
            totalDeficitKg: Math.round(totalFactDeficit)
          } as ProductionTask);

          categoryKg += combinedRecommended;
        });

        categories.push({
          categoryName,
          emoji: getEmoji(categoryName),
          totalKg: Math.round(categoryKg),
          itemsCount: products.length,
          items: products.sort((a, b) => b.recommendedQtyKg - a.recommendedQtyKg)
        });

        totalKg += categoryKg;
      });

      return {
        key: config.key,
        label: config.label,
        emoji: config.emoji,
        color: config.color,
        colorDark: config.colorDark,
        glow: config.glow,
        totalKg: Math.round(totalKg),
        categoriesCount: categories.length,
        categories: categories.sort((a, b) => b.totalKg - a.totalKg)
      } as PriorityHierarchy;
    }).filter((p): p is PriorityHierarchy => p !== null);
  }, [filteredQueue]);

  // 🔥 SYNC METRICS WITH PARENT (page.tsx)
  useEffect(() => {
    if (!onMetricsUpdate) return;

    let criticalWeight = 0, criticalSKU = 0;
    let reserveWeight = 0, reserveSKU = 0;

    hierarchy.forEach(p => {
      if (p.key === 'critical' || p.key === 'high') {
        criticalWeight += p.totalKg;
        criticalSKU += p.categories.reduce((acc, cat) => acc + cat.itemsCount, 0);
      } else if (p.key === 'reserve') {
        reserveWeight += p.totalKg;
        reserveSKU += p.categories.reduce((acc, cat) => acc + cat.itemsCount, 0);
      }
    });

    const totalKg = criticalWeight + reserveWeight;

    // Use a timeout to avoid render-cycle conflicts if parent updates state immediately
    const timer = setTimeout(() => {
      onMetricsUpdate({
        totalKg,
        criticalWeight,
        reserveWeight,
        criticalSKU,
        reserveSKU
      });
    }, 0);

    return () => clearTimeout(timer);
  }, [hierarchy, onMetricsUpdate]);

  // Calculate stats for local usage (Footer)
  const stats = useMemo(() => {
    const criticalPriority = hierarchy.find(p => p.key === 'critical');
    const recommendedWeight = Math.round(criticalPriority?.totalKg || 0);
    // Reserve is needed for total
    const reservePriority = hierarchy.find(p => p.key === 'reserve');
    const totalAllWeight = Math.round(recommendedWeight + (reservePriority?.totalKg || 0));

    return {
      recommendedWeight,
      totalAllWeight
    };
  }, [hierarchy]);

  const { recommendedWeight, totalAllWeight } = stats;

  const togglePriority = (key: PriorityKey) => {
    setExpandedPriorities((prev: Set<PriorityKey>) => {
      const next = new Set(prev);
      if (next.has(key)) next.delete(key);
      else next.add(key);
      return next;
    });
  };

  const toggleCategory = (priorityKey: PriorityKey, categoryName: SKUCategory) => {
    const key = `${priorityKey}_${categoryName}`;
    setExpandedCategories((prev: Set<string>) => {
      const next = new Set(prev);
      if (next.has(key)) next.delete(key);
      else next.add(key);
      return next;
    });
  };

  const toggleProduct = (productCode: number) => {
    const key = productCode.toString();
    setExpandedProducts((prev: Set<string>) => {
      const next = new Set(prev);
      if (next.has(key)) next.delete(key);
      else next.add(key);
      return next;
    });
  };

  const toggleStoreSelection = (productCode: number, storeName: string) => {
    const key = `${productCode}_${storeName}`;
    setSelectedStores(prev => {
      const next = new Map(prev);
      if (next.has(key)) {
        next.delete(key);
      } else {
        next.set(key, true);
      }
      return next;
    });
  };

  const toggleAllStoresForProduct = (item: ProductionTask) => {
    const allSelected = item.stores.every(store => {
      const key = `${item.productCode}_${store.storeName}`;
      return selectedStores.has(key);
    });

    setSelectedStores(prev => {
      const next = new Map(prev);
      item.stores.forEach(store => {
        const key = `${item.productCode}_${store.storeName}`;
        if (allSelected) {
          next.delete(key);
        } else {
          next.set(key, true);
        }
      });
      return next;
    });
  };

  const toggleSelectAllByCategory = (category: CategoryGroup) => {
    // Check if ALL items in this category are fully selected
    const allItemsSelected = category.items.every(item =>
      item.stores.every(store => {
        const key = `${item.productCode}_${store.storeName}`;
        return selectedStores.has(key);
      })
    );

    setSelectedStores(prev => {
      const next = new Map(prev);

      category.items.forEach(item => {
        item.stores.forEach(store => {
          const key = `${item.productCode}_${store.storeName}`;
          if (allItemsSelected) {
            // Deselect all
            next.delete(key);
          } else {
            // Select all
            next.set(key, true);
          }
        });
      });

      return next;
    });
  };

  const selectRecommended = () => {
    const selection = new Map<string, boolean>();

    hierarchy.forEach((priority: PriorityHierarchy) => {
      // Note: 'critical' now includes 'high' due to merge
      if (priority.key === 'critical') {
        priority.categories.forEach((category: CategoryGroup) => {
          category.items.forEach((item: ProductionTask) => {
            item.stores.forEach(store => {
              const key = `${item.productCode}_${store.storeName}`;
              selection.set(key, true);
            });
          });
        });
      }
    });

    setSelectedStores(selection);
  };

  const selectAll = () => {
    const selection = new Map<string, boolean>();

    // Select ALL items from ALL priorities
    hierarchy.forEach((priority: PriorityHierarchy) => {
      priority.categories.forEach((category: CategoryGroup) => {
        category.items.forEach((item: ProductionTask) => {
          item.stores.forEach(store => {
            const key = `${item.productCode}_${store.storeName}`;
            selection.set(key, true);
          });
        });
      });
    });

    // Also include reserve (which is handled separately in safeReserve)
    const reserveItems = filteredQueue.filter(i => i.priority === 'reserve');
    reserveItems.forEach(item => {
      item.stores.forEach(store => {
        const key = `${item.productCode}_${store.storeName}`;
        selection.set(key, true);
      });
    });

    setSelectedStores(selection);
  };

  const clearSelection = () => {
    setSelectedStores(new Map());
  };

  // 2. Формування замовлення (Step 44-50)
  const handleFormOrder = () => {
    // If no shift selected, show restriction modal
    if (currentCapacity === null) {
      setShowShiftRestrictionModal(true);
      return;
    }

    const items: OrderItem[] = [];
    const currentTotal = 0;
    hierarchy.forEach((priority: PriorityHierarchy) => {
      priority.categories.forEach((category: CategoryGroup) => {
        category.items.forEach((item: ProductionTask) => {
          item.stores.forEach((store) => {
            const key = `${item.productCode}_${store.storeName}`;
            if (selectedStores.has(key)) {
              // SMART ORDER FORMULA: Min Stock + (Planning Days * Avg Sales) - Fact
              const minStock = parseFloat(String(store.minStock)) || 0;
              const avgSales = parseFloat(String(store.avgSales)) || 0;
              const currentStock = parseFloat(String(store.currentStock)) || 0;

              const smartQuantity = Math.max(0, Math.ceil(minStock + (avgSales * planningDays) - currentStock));

              // Deficit is what we show in the card (Immediate Need)
              const strictDeficit = store.recommendedKg;

              items.push({
                id: key,
                productCode: item.productCode,
                productName: item.name,
                category: item.category,
                storeName: store.storeName,
                quantity: smartQuantity,
                kg: smartQuantity,
                minRequired: strictDeficit,
                maxRecommended: smartQuantity, // Allow up to smart quantity in slider
                priority: item.priority
              });
            }
          });
        });
      });
    });

    if (items.length === 0) {
      alert('Оберіть товари для замовлення');
      return;
    }

    const finalOrderItems = items.filter(item => item.kg > 0);
    const totalOrderWeight = finalOrderItems.reduce((sum, item) => sum + item.kg, 0);

    const order = {
      date: new Date().toLocaleDateString('uk-UA'),
      totalKg: totalOrderWeight,
      items: finalOrderItems
    };

    setOrderData(order);
    setOrderItems(order.items); // Keep for compatibility with existing modals
    setIsOrderModalOpen(true);
  };

  const handleConfirmOrder = (confirmedItems: OrderItem[]) => {
    setOrderItems(confirmedItems);
    setIsOrderModalOpen(false);
    setShowShareModal(true);
  };

  const handleShare = async (platform: SharePlatform['id']) => {
    try {
      const response = await fetch('/api/send-order', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ items: orderItems, platform })
      });

      const data = await response.json();

      if (data.success) {
        alert(`✅ Замовлення успішно відправлено через ${platform}!`);
        setShowShareModal(false);
        clearSelection();
      } else {
        alert(`❌ Помилка: ${data.error || 'Не вдалося відправити'}`);
      }
    } catch (error) {
      console.error('Share error:', error);
      alert('❌ Помилка мережі');
    }
  };

  // Группировка по категориям
  const groupedByCategory = useMemo(() => {
    const groups = groupItemsByCategory(orderData?.items || []);
    // Добавляем эмодзи для UI
    const groupsWithEmoji: Record<string, any> = {};
    Object.entries(groups).forEach(([cat, data]) => {
      groupsWithEmoji[cat] = {
        ...data,
        emoji: getEmoji(cat)
      };
    });
    return groupsWithEmoji;
  }, [orderData]);

  // ============================================================================
  // CONDITIONAL RENDERING (after all hooks are called)
  // ============================================================================

  if (selectedStore !== 'Усі') {
    return <StoreSpecificView queue={filteredQueue} storeName={selectedStore} />;
  }

  return (
    <div className="flex flex-col h-full w-full font-sans overflow-hidden">
      {/* Header with weight counter */}
      <header className="flex-shrink-0 px-4 py-3 border-b border-[#3e4362] bg-gradient-to-r from-[#1a1f3a] to-[#0a0e27] z-20">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-4">
            <h3 className="text-[14px] font-black uppercase tracking-tighter text-[var(--foreground)] flex items-center gap-2">
              📋 {selectedWeight > 0 ? `Замовлення на ${selectedWeight} кг` : 'Формування замовлення'}
            </h3>

            {/* PLANNING DAYS CONTROL */}
            <div className="flex items-center space-x-1 bg-white/5 p-1 rounded-lg border border-white/10">
              <span className="text-[10px] font-bold px-2 text-white/40 uppercase tracking-wider">План (днів):</span>
              {[1, 2, 3, 4, 5, 6, 7, 14].map((d) => (
                <button
                  key={d}
                  onClick={() => handleSetPlanningDays(d)}
                  className={cn(
                    "w-8 h-6 flex items-center justify-center rounded text-[11px] font-bold transition-all",
                    planningDays === d
                      ? "bg-[#00D4FF] text-black shadow-[0_0_10px_rgba(0,212,255,0.4)]"
                      : "text-white/60 hover:bg-white/10 hover:text-white"
                  )}
                >
                  {d}
                </button>
              ))}
            </div>
          </div>

          <div className="flex items-center gap-2">
            <div className="h-2 w-2 rounded-full bg-[#52e8ff] animate-pulse"></div>
            <span className="text-[11px] text-[#8b949e]">
              Вибрано: <span className={`font-bold ${selectedWeight > (currentCapacity || 0) ? 'text-[#e74856]' : 'text-[#52e8ff]'}`}>
                {selectedWeight} кг
              </span> / {currentCapacity ?? '—'} кг
            </span>
          </div>
        </div>
      </header>

      {/* Main Content (scrollable) */}
      <main className="flex-1 overflow-y-auto custom-scrollbar">
        {hierarchy.map((priority: PriorityHierarchy) => {
          // Skip reserve in main loop (rendered separately at the end)
          if (priority.key === 'reserve') return null;

          const isPriorityExpanded = expandedPriorities.has(priority.key);

          return (
            <div key={priority.key} className="border-b border-[var(--border)]/50 last:border-0">
              {/* Priority Header */}
              <div
                className="priority-card w-[90%] mx-auto my-2 px-4 py-3 rounded-xl cursor-pointer flex flex-col transition-all duration-300 hover:translate-y-[-2px] border-b border-white/5 hover:shadow-[0_8px_24px_var(--priority-shadow)]"
                style={{
                  background: `linear-gradient(135deg, ${priority.color}66 0%, ${priority.colorDark}66 100%)`,
                  backdropFilter: 'blur(10px)',
                  WebkitBackdropFilter: 'blur(10px)',
                  borderLeft: `4px solid ${priority.glow}`,
                  border: '1px solid rgba(255, 255, 255, 0.1)',
                  boxShadow: '0 8px 24px rgba(0, 0, 0, 0.4)',
                  //@ts-ignore
                  '--priority-shadow': `${priority.glow}50`
                }}
                onClick={() => togglePriority(priority.key)}
                role="button"
                aria-expanded={isPriorityExpanded}
                tabIndex={0}
                onKeyDown={(e) => e.key === 'Enter' && togglePriority(priority.key)}
              >
                <div className="relative flex items-center justify-center w-full">
                  {/* Left: Arrow */}
                  <div className="absolute left-0">
                    {isPriorityExpanded ?
                      <ChevronDown size={20} className="text-[var(--text-muted)]" /> :
                      <ChevronRight size={20} className="text-[var(--text-muted)]" />
                    }
                  </div>

                  {/* Center: Title & Description */}
                  <div className="flex flex-col items-center justify-center text-center">
                    <div className="flex items-center gap-2 mb-0.5">
                      <span className="text-[20px] filter drop-shadow-md">{priority.emoji}</span>
                      <span className="text-[14px] font-black uppercase tracking-[0.15em] text-white"
                        style={{ textShadow: `0 0 20px ${priority.color}` }}>
                        {priority.label.split('(')[0]}
                      </span>
                    </div>

                    {/* Explicit Description based on priority key */}
                    <div className="text-[9px] font-extrabold text-[#ff6b6b] uppercase tracking-wider bg-black/30 px-3 py-0.5 rounded-full border border-[#ff6b6b]/20 mt-1 max-w-[95%] text-center whitespace-nowrap shadow-[0_0_10px_rgba(255,107,107,0.1)]">
                      {priority.key === 'critical' && "⛔️ ТЕРМІНОВО ПОПОВНИТИ"}
                    </div>
                  </div>

                  {/* Right: Category Count Badge */}
                  <div className="absolute right-0">
                    <div className="px-2 py-0.5 rounded-lg bg-black/20 border border-white/5 backdrop-blur-sm">
                      <span className="text-[10px] font-bold text-white/90">
                        {priority.categoriesCount} <span className="text-white/50 text-[8px] uppercase">кат.</span>
                      </span>
                    </div>
                  </div>
                </div>

                {/* Статистика (внизу карточки) */}
                <div className="flex items-center justify-center gap-6 mt-2 pt-2 border-t border-white/10">
                  <div className="flex items-center gap-1.5">
                    <span className="text-[9px] text-white/50 uppercase tracking-widest font-bold">Вага:</span>
                    <span className="text-[13px] font-black text-[#52E8FF] tracking-wide" style={{ textShadow: '0 0 10px rgba(82,232,255,0.3)' }}>
                      {priority.totalKg} кг
                    </span>
                  </div>
                </div>
              </div>

              {/* Categories */}
              {isPriorityExpanded && priority.categories.map((category: CategoryGroup) => {
                const categoryKey = `${priority.key}_${category.categoryName}`;
                const isCategoryExpanded = expandedCategories.has(categoryKey);

                return (
                  <div key={categoryKey} className="border-b border-[var(--border)]/10 last:border-0">
                    {/* Category Row */}
                    <div
                      className="mx-2 my-1 pl-8 pr-4 py-2.5 rounded-lg hover:bg-[#2a2f4a] cursor-pointer flex items-center justify-between transition-all duration-200 group"
                      onClick={() => toggleCategory(priority.key, category.categoryName as SKUCategory)}
                      role="button"
                      aria-expanded={isCategoryExpanded}
                      tabIndex={0}
                      onKeyDown={(e) => e.key === 'Enter' && toggleCategory(priority.key, category.categoryName as SKUCategory)}
                    >
                      <div className="flex items-center gap-2">
                        {isCategoryExpanded ?
                          <ChevronDown size={14} className="text-[var(--text-muted)]" /> :
                          <ChevronRight size={14} className="text-[var(--text-muted)]" />
                        }

                        {/* Select All Category Checkbox */}
                        <button
                          onClick={(e) => {
                            e.stopPropagation();
                            toggleSelectAllByCategory(category);
                          }}
                          className={cn(
                            "ml-2 w-4 h-4 rounded border flex items-center justify-center transition-all opacity-0 group-hover:opacity-100 focus:opacity-100",
                            category.items.every(item => item.stores.every(store => selectedStores.has(`${item.productCode}_${store.storeName}`)))
                              ? "bg-[var(--status-normal)] border-[var(--status-normal)] opacity-100"
                              : "border-[var(--text-muted)] hover:border-[var(--status-normal)]"
                          )}
                          title="Обрати всю категорію"
                        >
                          <CheckCircle2 size={10} className="text-white" />
                        </button>

                        <span className="text-[12px] font-bold text-[var(--foreground)]">
                          {category.categoryName}
                        </span>
                        <span className="text-[10px] text-[var(--text-muted)]">
                          ({category.itemsCount} поз.)
                        </span>
                      </div>
                      <span
                        className="text-[13px] font-black"
                        style={{
                          background: 'linear-gradient(135deg, #E74856 0%, #FF6B6B 100%)',
                          WebkitBackgroundClip: 'text',
                          WebkitTextFillColor: 'transparent',
                          backgroundClip: 'text'
                        }}
                      >
                        {category.totalKg} кг
                      </span>
                    </div>

                    {/* Products */}
                    {/* Products Grid */}
                    {isCategoryExpanded && (
                      <div className="ml-6 mt-1 space-y-1">
                        {category.items.map((item: ProductionTask) => {
                          const isProductExpanded = expandedProducts.has(item.productCode.toString());
                          const allStoresSelected = item.stores.every(store => {
                            const key = `${item.productCode}_${store.storeName}`;
                            return selectedStores.has(key);
                          });

                          return (
                            <div key={item.productCode}>
                              {/* Row Logic */}
                              <div
                                className="px-4 py-2 bg-white/[0.02] hover:bg-white/[0.04] rounded cursor-pointer transition-colors flex items-center justify-between group/row"
                                onClick={() => toggleProduct(item.productCode)}
                              >
                                <div className="flex items-center gap-2">
                                  {isProductExpanded ?
                                    <ChevronDown size={12} className="text-[var(--text-muted)]" /> :
                                    <ChevronRight size={12} className="text-[var(--text-muted)]" />
                                  }

                                  {/* Checkbox for Product (Select All Stores) */}
                                  <button
                                    onClick={(e) => {
                                      e.stopPropagation();
                                      toggleAllStoresForProduct(item);
                                    }}
                                    className={cn(
                                      "w-3.5 h-3.5 rounded border flex items-center justify-center transition-all mr-2",
                                      allStoresSelected
                                        ? "bg-[var(--status-normal)] border-[var(--status-normal)]"
                                        : "border-[#3e3e42] hover:border-[var(--status-normal)]"
                                    )}
                                  >
                                    {allStoresSelected && <CheckCircle2 size={8} className="text-white" />}
                                  </button>

                                  <div className="flex flex-col">
                                    <span className="text-[11px] text-[var(--foreground)] group-hover/row:text-white transition-colors">
                                      {item.name}
                                    </span>
                                  </div>
                                </div>

                                {/* Right Side: Total KG for this product */}
                                <div className="flex items-center gap-4">
                                  <span className="text-[11px] font-bold text-[#58a6ff]">
                                    {Math.round(item.stores.reduce((acc, s) => acc + s.recommendedKg, 0))} кг
                                  </span>
                                </div>
                              </div>

                              {/* Expanded Stores List */}
                              {isProductExpanded && (
                                <div className="ml-8 mt-1 space-y-1 border-l border-white/5 pl-2">
                                  {item.stores.map(store => {
                                    const storeKey = `${item.productCode}_${store.storeName}`;
                                    const isSelected = selectedStores.has(storeKey);
                                    const avg = parseFloat(String(store.avgSales)) || 0;
                                    const stock = parseFloat(String(store.currentStock)) || 0;
                                    const min = parseFloat(String(store.minStock)) || 0;
                                    const rec = store.recommendedKg;

                                    return (
                                      <div
                                        key={storeKey}
                                        className="px-4 py-2 bg-white/[0.01] hover:bg-white/[0.03] rounded transition-colors flex items-center justify-between"
                                        onClick={(e) => {
                                          e.stopPropagation();
                                          toggleStoreSelection(item.productCode, store.storeName);
                                        }}
                                      >
                                        <div className="flex items-center gap-3">
                                          <button
                                            className={cn(
                                              "w-3.5 h-3.5 rounded border flex items-center justify-center transition-all",
                                              isSelected
                                                ? "bg-[#3FB950] border-[#3FB950]"
                                                : "border-[#3e3e42] hover:border-[#3FB950]"
                                            )}
                                          >
                                            {isSelected && <CheckCircle2 size={8} className="text-white" />}
                                          </button>

                                          <div className="flex flex-col">
                                            <span className="text-[11px] text-white/50">
                                              {store.storeName.replace('Магазин "', '').replace('"', '')}
                                            </span>
                                          </div>
                                        </div>

                                        <div className="flex items-center gap-6 text-[10px] font-mono">
                                          <div className="flex flex-col items-end">
                                            <span className="text-white/20 text-[8px] uppercase">Факт</span>
                                            <span className={stock < min ? "text-[#FF6B6B]" : "text-[#52E8FF]"}>{stock.toFixed(1)}</span>
                                          </div>
                                          <div className="flex flex-col items-end">
                                            <span className="text-white/20 text-[8px] uppercase">Мін</span>
                                            <span className="text-[#FFB84D]">{min.toFixed(1)}</span>
                                          </div>
                                          <div className="flex flex-col items-end">
                                            <span className="text-white/20 text-[8px] uppercase">Сер.</span>
                                            <span className="text-white/60">{avg.toFixed(1)}</span>
                                          </div>
                                          <div className="flex flex-col items-end w-12">
                                            <span className="text-white/20 text-[8px] uppercase">Треба</span>
                                            <span className={cn(
                                              "font-bold text-[12px]",
                                              rec > 0 ? "text-[#3FB950]" : "text-white/10"
                                            )}>
                                              {Math.ceil(rec)}
                                            </span>
                                          </div>
                                        </div>
                                      </div>
                                    );
                                  })}
                                </div>
                              )}
                            </div>
                          );
                        })}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          );
        })}

        {/* 🔵 РЕЗЕРВ КАРТОЧКА (Step 89/92) - Always Visible */}
        {(() => {
          const reserveFromHierarchy = hierarchy.find(h => h.key === 'reserve');
          const safeReserve = reserveFromHierarchy || {
            key: 'reserve',
            label: 'РЕКОМЕНДОВАНО (зробити наперед)',
            emoji: '🔵',
            color: '#007BA7',
            totalKg: 0,
            categoriesCount: 0,
            glow: '#00BCF2',
            categories: []
          } as PriorityHierarchy;

          return (
            <div className="mb-4">
              <div
                className="priority-card w-[90%] mx-auto my-2 px-4 py-3 rounded-xl cursor-pointer flex flex-col transition-all duration-300 hover:translate-y-[-2px] border-b border-white/5 hover:shadow-[0_8px_24px_rgba(0,188,242,0.3)]"
                style={{
                  background: 'linear-gradient(135deg, rgba(0,123,167,0.4) 0%, rgba(0,95,140,0.4) 100%)',
                  backdropFilter: 'blur(10px)',
                  WebkitBackdropFilter: 'blur(10px)',
                  borderLeft: '4px solid #00BCF2',
                  border: '1px solid rgba(255, 255, 255, 0.1)',
                  boxShadow: '0 8px 24px rgba(0, 0, 0, 0.4)'
                }}
                onClick={() => setExpandedReserve(!expandedReserve)}
              >
                <div className="relative flex items-center justify-center w-full">
                  {/* Left: Arrow */}
                  <div className="absolute left-0">
                    {expandedReserve ?
                      <ChevronDown size={20} className="text-white/70" /> :
                      <ChevronRight size={20} className="text-white/70" />
                    }
                  </div>

                  {/* Center: Title & Description */}
                  <div className="flex flex-col items-center justify-center text-center">
                    <div className="flex items-center gap-2 mb-0.5">
                      <span className="text-[20px] filter drop-shadow-md">🔵</span>
                      <span className="text-[14px] font-black uppercase tracking-[0.15em] text-white"
                        style={{ textShadow: '0 0 20px #00BCF2' }}>
                        РЕЗЕРВ
                      </span>
                    </div>

                    {/* Explicit Description for Reserve */}
                    <div className="text-[9px] font-bold text-white/70 uppercase tracking-wide bg-black/20 px-2 py-0.5 rounded-full border border-white/5 mt-0.5 max-w-[95%] text-center whitespace-nowrap">
                      ТОВАРУ НИЖЧЕ МІНІМАЛЬНОГО
                    </div>
                  </div>

                  {/* Right: Category Count Badge */}
                  <div className="absolute right-0">
                    <div className="px-2 py-0.5 rounded-lg bg-black/20 border border-white/5 backdrop-blur-sm">
                      <span className="text-[10px] font-bold text-white/90">
                        {safeReserve.categoriesCount} <span className="text-white/50 text-[8px] uppercase">кат.</span>
                      </span>
                    </div>
                  </div>
                </div>

                {/* Статистика */}
                <div className="flex items-center justify-center gap-6 mt-2 pt-2 border-t border-white/10">
                  <div className="flex items-center gap-1.5">
                    <span className="text-[9px] text-white/50 uppercase tracking-widest font-bold">Вага:</span>
                    <span className="text-[13px] font-black text-[#52E8FF] tracking-wide" style={{ textShadow: '0 0 10px rgba(82,232,255,0.3)' }}>
                      {safeReserve.totalKg} кг
                    </span>
                  </div>
                </div>
              </div>

              {/* РЕЗЕРВ РОЗГОРНУТО */}
              {expandedReserve && (
                <div className="mx-3 mb-4">
                  {safeReserve.categories.map((category) => {
                    const { categoryName, itemsCount, totalKg, items: products } = category;
                    const isCategoryExpanded = expandedReserveCategories.has(categoryName);

                    return (
                      <div key={categoryName} className="mb-2">
                        {/* Категорія */}
                        <div
                          className="px-4 py-3 bg-white/[0.03] hover:bg-white/[0.05] rounded-lg cursor-pointer transition-colors flex items-center justify-between border border-white/5 group"
                          onClick={() => {
                            const newSet = new Set(expandedReserveCategories);
                            if (newSet.has(categoryName)) {
                              newSet.delete(categoryName);
                            } else {
                              newSet.add(categoryName);
                            }
                            setExpandedReserveCategories(newSet);
                          }}
                        >
                          <div className="flex items-center gap-2">
                            {isCategoryExpanded ?
                              <ChevronDown size={14} className="text-white/50" /> :
                              <ChevronRight size={14} className="text-white/50" />
                            }

                            {/* Select All Reserve Category Checkbox */}
                            <button
                              onClick={(e) => {
                                e.stopPropagation();
                                toggleSelectAllByCategory(category);
                              }}
                              className={cn(
                                "ml-2 w-4 h-4 rounded border flex items-center justify-center transition-all opacity-0 group-hover:opacity-100 focus:opacity-100",
                                category.items.every(item => item.stores.every(store => selectedStores.has(`${item.productCode}_${store.storeName}`)))
                                  ? "bg-[#00BCF2] border-[#00BCF2] opacity-100 placeholder:shadow-[0_0_10px_rgba(0,188,242,0.5)]"
                                  : "border-white/20 hover:border-[#00BCF2]"
                              )}
                              title="Обрати всю категорію"
                            >
                              <CheckCircle2 size={10} className="text-white" />
                            </button>

                            <span className="text-[13px] font-semibold text-white/90">
                              {categoryName}
                            </span>
                            <span className="text-[10px] text-white/50">
                              ({itemsCount} поз.)
                            </span>
                          </div>
                          <span className="text-[12px] font-bold text-[#00BCF2]">
                            {Math.round(totalKg)} кг
                          </span>
                        </div>

                        {/* Товари категорії */}
                        {/* Товари категорії */}
                        {isCategoryExpanded && (
                          <div className="ml-6 mt-1 space-y-1">
                            {products.map(item => {
                              const productId = item.productCode.toString();
                              const isProductExpanded = expandedReserveProducts.has(productId);
                              const productTotalKg = item.stores.reduce((sum, s) => sum + s.recommendedKg, 0);

                              return (
                                <div key={productId}>
                                  {/* Товар */}
                                  <div
                                    className="px-4 py-2 bg-white/[0.02] hover:bg-white/[0.04] rounded cursor-pointer transition-colors flex items-center justify-between"
                                    onClick={() => {
                                      const newSet = new Set(expandedReserveProducts);
                                      if (newSet.has(productId)) {
                                        newSet.delete(productId);
                                      } else {
                                        newSet.add(productId);
                                      }
                                      setExpandedReserveProducts(newSet);
                                    }}
                                  >
                                    <div className="flex items-center gap-2">
                                      {isProductExpanded ?
                                        <ChevronDown size={12} className="text-white/40" /> :
                                        <ChevronRight size={12} className="text-white/40" />
                                      }
                                      <span className="text-[11px] text-white/80">
                                        {item.name}
                                      </span>
                                      <span className="text-[9px] text-white/40">
                                        ({item.stores.length} маг.)
                                      </span>
                                    </div>
                                    <span className="text-[11px] font-bold text-[#58a6ff]">
                                      {Math.round(productTotalKg)} кг
                                    </span>
                                  </div>

                                  {/* Магазини */}
                                  {isProductExpanded && (
                                    <div className="ml-6 mt-1 space-y-1">
                                      {item.stores.map(store => {
                                        const storeKey = `${item.productCode}_${store.storeName}`;
                                        const isSelected = selectedStores.has(storeKey);

                                        return (
                                          <div
                                            key={storeKey}
                                            className="px-4 py-2 bg-white/[0.01] hover:bg-white/[0.03] rounded transition-colors flex items-center justify-between"
                                          >
                                            <div className="flex items-center gap-2">
                                              <button
                                                onClick={(e) => {
                                                  e.stopPropagation();
                                                  toggleStoreSelection(item.productCode, store.storeName);
                                                }}
                                                className={cn(
                                                  "w-3.5 h-3.5 rounded border flex items-center justify-center transition-all",
                                                  isSelected
                                                    ? "bg-[#3FB950] border-[#3FB950]"
                                                    : "border-[#3e3e42] hover:border-[#3FB950]"
                                                )}
                                              >
                                                {isSelected && <CheckCircle2 size={8} className="text-white" />}
                                              </button>

                                              <div className="flex items-center justify-between text-[10px] flex-1">
                                                <span className="text-white/50">🏪 {store.storeName}</span>
                                                <div className="font-mono">
                                                  <span className="text-white/60">факт:</span>{' '}
                                                  <span className={store.currentStock < 0 ? 'text-[#FF6B6B]' : 'text-[#52E8FF]'}>
                                                    {store.currentStock.toFixed(1)}
                                                  </span>
                                                  <span className="text-white/30 mx-1">→</span>
                                                  <span className="text-white/60">мін:</span>{' '}
                                                  <span className="text-[#FFB84D]">{store.minStock.toFixed(1)}</span>
                                                  <span className="text-white/30 mx-1">→</span>
                                                  <span className="text-white/60">треба:</span>{' '}
                                                  <span className="text-[#3FB950] font-bold">{store.recommendedKg}</span> кг
                                                </div>
                                              </div>
                                            </div>
                                          </div>
                                        );
                                      })}
                                    </div>
                                  )}
                                </div>
                              );
                            })}
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          );
        })()}
      </main>

      <footer className="flex-shrink-0 px-4 py-5 border-t border-white/10 bg-[#0d1117]/90 backdrop-blur-xl">
        <div className="flex gap-3 items-center h-16 max-w-5xl mx-auto">
          {/* Button 1: SELECT ALL EVERYTHING */}
          <button
            onClick={selectAll}
            className="flex-1 h-full px-4 rounded-xl font-black text-[10px] uppercase tracking-wider transition-all border border-[#52E8FF]/20 bg-[#52E8FF]/5 text-[#52E8FF] hover:bg-[#52E8FF]/10 hover:border-[#52E8FF]/40 flex flex-col items-center justify-center gap-1 group"
          >
            <span className="opacity-60 group-hover:opacity-100 italic">Все дерево</span>
            <span className="text-[13px]">Вибрати все</span>
            <span className="text-[10px] font-black opacity-80">{totalAllWeight} кг</span>
          </button>

          {/* Button 2: CONFIRM MANUAL PICK (ВИБРАТИ ОБРАНЕ) */}
          <button
            onClick={() => setIsOrderConfirmed(true)}
            disabled={selectedStores.size === 0 || isOrderConfirmed}
            className={cn(
              "flex-1 h-full px-4 rounded-xl font-black text-[10px] uppercase tracking-wider transition-all border flex flex-col items-center justify-center gap-1 group",
              selectedStores.size > 0 && !isOrderConfirmed
                ? "border-[#3FB950]/50 bg-[#3FB950]/10 text-[#3FB950] hover:bg-[#3FB950]/20 shadow-[0_0_20px_rgba(63,185,80,0.1)]"
                : isOrderConfirmed
                  ? "border-[#3FB950] bg-[#3FB950] text-[#0d1117] shadow-[0_0_30px_rgba(63,185,80,0.3)]"
                  : "border-white/5 bg-white/5 text-white/10 cursor-not-allowed"
            )}
          >
            <span className={cn("text-[9px] italic", isOrderConfirmed ? "opacity-90" : "opacity-60")}>
              {isOrderConfirmed ? "ВИБІР ПІДТВЕРДЖЕНО" : "ТІЛЬКИ ОБРАНЕ"}
            </span>
            <span className="text-[13px]">Вибрати обране</span>
            <span className="text-[10px] font-black">{selectedWeight} кг</span>
          </button>

          {/* Button 3: FORM REQUEST (PRIMARY) */}
          <button
            onClick={handleFormOrder}
            disabled={!isOrderConfirmed}
            className={cn(
              "flex-[1.5] h-full px-6 rounded-xl font-black text-[14px] uppercase tracking-[0.15em] transition-all duration-300 flex items-center justify-center gap-3 relative overflow-hidden group",
              isOrderConfirmed
                ? "bg-gradient-to-r from-[#00D4FF] to-[#0099FF] text-white shadow-[0_0_30px_rgba(0,212,255,0.3)] hover:shadow-[0_0_50px_rgba(0,212,255,0.5)] hover:scale-[1.02] active:scale-[0.98]"
                : "bg-white/5 text-white/5 cursor-not-allowed border border-white/5"
            )}
          >
            {isOrderConfirmed && (
              <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent -translate-x-full group-hover:animate-shimmer pointer-events-none" />
            )}
            <Package size={22} className={cn(isOrderConfirmed ? "text-white animate-bounce" : "text-white/5")} />
            <span className="drop-shadow-md text-center">Сформувати заявку</span>
          </button>

          {/* Button 4: CLEAR */}
          <button
            onClick={clearSelection}
            className="flex-1 h-full px-4 rounded-xl font-black text-[10px] uppercase tracking-wider transition-all border border-[#F85149]/20 bg-[#F85149]/5 text-[#F85149] hover:bg-[#F85149]/10 hover:border-[#F85149]/40 flex flex-col items-center justify-center gap-1 group"
          >
            <span className="opacity-60 group-hover:opacity-100 italic">Скинути вибір</span>
            <span className="text-[13px]">Очистити</span>
            <span className="text-[10px] font-black opacity-80">{selectedWeight} кг</span>
          </button>
        </div>
      </footer>

      {/* Modals */}
      {/* Data Outdated Modal - NOW WITH BUTTON */}
      {refreshUrgency === 'critical' && (
        <div
          className="fixed inset-0 z-[100] flex items-center justify-center p-4"
          style={{
            background: 'rgba(5, 5, 10, 0.9)',
            backdropFilter: 'blur(10px)'
          }}
        >
          <div className="relative w-full max-w-md bg-[#161b22] border border-[#f85149]/30 rounded-2xl p-8 text-center shadow-[0_0_50px_rgba(248,81,73,0.3)]">

            {/* Pulse Effect */}
            <div className="absolute inset-0 bg-[#f85149]/5 animate-pulse pointer-events-none" />

            <div className="w-20 h-20 bg-[#f85149]/10 rounded-full flex items-center justify-center mx-auto mb-6 border border-[#f85149]/20">
              <AlertTriangle size={40} className="text-[#f85149]" />
            </div>

            <h3 className="text-2xl font-black text-white uppercase mb-2">
              Дані застаріли
            </h3>

            <p className="text-[#8b949e] mb-8 leading-relaxed">
              Інформація не оновлювалась більше 15 хвилин.
              <br />
              Для продовження роботи необхідно оновити дані.
            </p>

            {/* DIRECT ACTION BUTTON */}
            {onManualRefresh ? (
              <button
                onClick={onManualRefresh}
                className="mx-auto px-8 py-4 rounded-xl font-bold uppercase tracking-wider text-white bg-[#f85149] hover:bg-[#da3633] transition-all shadow-[0_0_20px_rgba(248,81,73,0.4)] hover:scale-105 active:scale-95 flex items-center gap-3 justify-center"
              >
                <RefreshCw size={20} className="animate-spin-slow" />
                Оновити дані зараз
              </button>
            ) : (
              <div className="animate-bounce">
                <span className="text-[#f85149] text-xs font-bold uppercase tracking-widest">
                  ☝️ Натисніть "Оновити" в меню зліва
                </span>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Shift Restriction Modal */}
      {showShiftRestrictionModal && refreshUrgency !== 'critical' && (
        <div
          className="fixed inset-0 z-[100] flex items-center justify-center"
          style={{ background: 'rgba(0,0,0,0.8)', backdropFilter: 'blur(8px)' }}
          onClick={() => setShowShiftRestrictionModal(false)}
        >
          <div
            className="w-[400px] bg-[#161b22] border border-[#f85149]/30 rounded-2xl shadow-[0_0_50px_rgba(248,81,73,0.15)] p-6 space-y-4 animate-in zoom-in duration-300 relative overflow-hidden"
            onClick={e => e.stopPropagation()}
          >
            {/* Background glow effect */}
            <div className="absolute top-0 right-0 w-64 h-64 bg-[#f85149]/5 blur-[80px] rounded-full pointer-events-none -translate-y-1/2 translate-x-1/2" />

            {/* Icon */}
            <div className="flex items-center justify-center mb-6">
              <div className="w-16 h-16 rounded-2xl bg-[#f85149]/10 flex items-center justify-center border border-[#f85149]/20 shadow-[0_0_20px_rgba(248,81,73,0.1)]">
                <AlertTriangle size={32} className="text-[#f85149] animate-pulse" />
              </div>
            </div>

            {/* Text */}
            <div className="text-center space-y-2 relative z-10">
              <h3 className="text-xl font-black text-[#e6edf3] uppercase tracking-wide">
                Зміна не обрана
              </h3>
              <p className="text-[13px] text-[#8b949e] leading-relaxed">
                Неможливо сформувати замовлення без активної зміни.
                <br />
                Будь ласка, натисніть кнопку <span className="text-[#00D4FF] font-bold">Персонал</span> у верхній панелі керування (поруч із оновленням залишків) та оберіть зміну.
              </p>
            </div>

            {/* Actions */}
            <div className="pt-4 relative z-10">
              <button
                onClick={() => setShowShiftRestrictionModal(false)}
                className="w-full py-3 bg-[#238636] hover:bg-[#2ea043] text-white font-bold rounded-xl transition-all shadow-lg shadow-green-900/20 active:scale-[0.98]"
              >
                ЗРОЗУМІЛО
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Confirmation Modal */}
      <OrderConfirmationModal
        isOpen={isOrderModalOpen}
        onClose={() => setIsOrderModalOpen(false)}
        items={orderItems}
        onConfirm={handleConfirmOrder}
      />


      <ShareOptionsModal
        isOpen={showShareModal}
        items={orderItems}
        orderData={orderData}
        onClose={() => setShowShareModal(false)}
        onShare={handleShare}
      />
    </div >
  );
};

'use client';

import React, { useState } from 'react';
import { ProductionTask } from '@/types/bi';
import { Calculator, Truck, CheckCircle2, AlertCircle, Save, ArrowLeft, RefreshCw } from 'lucide-react';
import { Modal, ModalHeader, ModalBody, ModalFooter, ModalButton } from '@/components/ui/Modal';

interface Props {
    isOpen: boolean;
    onClose: () => void;
    products: ProductionTask[];
}

interface DistributionResult {
    storeId: number;
    productId: number;
    quantity: number;
    originalQuantity?: number;
}

type Step = 'input' | 'review' | 'success';

export const DistributionModal = ({ isOpen, onClose, products }: Props) => {
    const [step, setStep] = useState<Step>('input');
    const [inputs, setInputs] = useState<Record<number, string>>({}); // productId -> quantity (string for input)
    const [results, setResults] = useState<DistributionResult[]>([]);
    const [isCalculating, setIsCalculating] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [error, setError] = useState<string | null>(null);

    // Filter unique products (just in case duplicates exist in queue)
    const uniqueProducts = Array.from(new Set(products.map(p => p.productCode)))
        .map(code => products.find(p => p.productCode === code)!);

    const handleInputChange = (productId: number, val: string) => {
        setInputs(prev => ({ ...prev, [productId]: val }));
    };

    const handleCalculate = async () => {
        setIsCalculating(true);
        setError(null);
        setResults([]);

        const distributions: DistributionResult[] = [];

        try {
            // Process products with entered quantity > 0
            const itemsToProcess = uniqueProducts.filter(p => {
                const qty = parseInt(inputs[p.productCode] || '0');
                return qty > 0;
            });

            if (itemsToProcess.length === 0) {
                setError('Введіть кількість хоча б для однієї піци');
                setIsCalculating(false);
                return;
            }

            // Call API for each product (could be parallelized)
            for (const p of itemsToProcess) {
                const qty = parseInt(inputs[p.productCode] || '0');

                const response = await fetch('/api/pizza/calculate-distribution', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ productId: p.productCode, productionQuantity: qty })
                });

                if (!response.ok) throw new Error('Calculation failed');

                const data = await response.json();

                // data.distributed is { storeId: quantity }
                Object.entries(data.distributed).forEach(([storeId, amount]) => {
                    const quantity = amount as number;
                    if (quantity > 0) {
                        distributions.push({
                            storeId: parseInt(storeId),
                            productId: p.productCode,
                            quantity,
                            originalQuantity: quantity
                        });
                    }
                });
            }

            setResults(distributions);
            setStep('review');
        } catch (err) {
            setError('Помилка розрахунку. Спробуйте ще раз.');
            console.error(err);
        } finally {
            setIsCalculating(false);
        }
    };

    const handleConfirm = async () => {
        setIsSubmitting(true);
        try {
            const response = await fetch('/api/pizza/confirm-distribution', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    distributions: results.map(r => ({
                        storeId: r.storeId,
                        productId: r.productId,
                        quantity: r.quantity
                    }))
                })
            });

            if (!response.ok) throw new Error('Failed to confirm');

            setStep('success');
            setTimeout(() => {
                onClose();
                setStep('input');
                setInputs({});
                setResults([]);
            }, 2000);
        } catch (err) {
            setError('Помилка збереження. Перевірте зʼєднання.');
        } finally {
            setIsSubmitting(false);
        }
    };

    // Helper to get store name from product data
    const getStoreName = (storeId: number) => {
        for (const p of products) {
            const s = p.stores.find(s => s.storeId === storeId);
            if (s) return s.storeName;
        }
        return `Магазин #${storeId}`;
    };

    // Group results by Store for review
    const resultsByStore = results.reduce((acc, curr) => {
        if (!acc[curr.storeId]) acc[curr.storeId] = [];
        acc[curr.storeId].push(curr);
        return acc;
    }, {} as Record<number, DistributionResult[]>);

    return (
        <Modal isOpen={isOpen} onClose={onClose} size="xl" zIndex={150}>
            {/* Header */}
            <ModalHeader icon={<Truck size={22} />}>
                <h2 className="text-xl font-bold text-white uppercase tracking-wider">
                    Розподіл Продукції
                </h2>
                <p className="text-xs text-white/40 mt-1">
                    Автоматичний алгоритм (4 етапи)
                </p>
            </ModalHeader>

            {/* Content */}
            <ModalBody className="bg-[#0A0E14]">
                {/* Error Message */}
                {error && (
                    <div className="mb-6 p-4 bg-[#EF4444]/10 border border-[#EF4444]/30 rounded-xl flex items-center gap-3 text-[#EF4444]">
                        <AlertCircle size={20} />
                        <span className="text-sm font-medium">{error}</span>
                    </div>
                )}

                {/* Step: Input */}
                {step === 'input' && (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                        {uniqueProducts.map(product => (
                            <div
                                key={product.productCode}
                                className="bg-white/[0.02] border border-white/5 rounded-xl p-4 flex flex-col gap-3 hover:bg-white/[0.04] hover:border-white/10 transition-all group"
                            >
                                <h3 className="font-bold text-white/90 truncate group-hover:text-white transition-colors" title={product.name}>
                                    {product.name}
                                </h3>
                                <div className="flex items-center gap-2">
                                    <input
                                        type="number"
                                        placeholder="0"
                                        className="bg-black/30 border border-white/10 rounded-lg h-12 px-3 w-full text-center text-xl font-bold text-[#00D4FF] focus:border-[#00D4FF] focus:outline-none focus:ring-2 focus:ring-[#00D4FF]/20 transition-all"
                                        value={inputs[product.productCode] || ''}
                                        onChange={(e) => handleInputChange(product.productCode, e.target.value)}
                                    />
                                    <span className="text-white/30 text-sm font-bold min-w-[30px]">шт</span>
                                </div>
                            </div>
                        ))}
                    </div>
                )}

                {/* Step: Review */}
                {step === 'review' && (
                    <div className="space-y-4">
                        {Object.entries(resultsByStore).map(([storeIdStr, items]) => {
                            const storeId = parseInt(storeIdStr);
                            return (
                                <div key={storeId} className="bg-white/[0.02] border border-white/5 rounded-xl overflow-hidden">
                                    <div className="px-4 py-3 bg-white/[0.02] border-b border-white/5 flex justify-between items-center">
                                        <span className="font-bold text-white flex items-center gap-2">
                                            🏪 {getStoreName(storeId)}
                                        </span>
                                        <span className="text-xs bg-white/5 px-2 py-1 rounded text-white/40 font-mono">
                                            ID: {storeId}
                                        </span>
                                    </div>
                                    <div className="divide-y divide-white/[0.03]">
                                        {items.map((item, idx) => {
                                            const product = uniqueProducts.find(p => p.productCode === item.productId);
                                            return (
                                                <div key={idx} className="p-4 flex items-center justify-between hover:bg-white/[0.02] transition-colors">
                                                    <span className="text-sm text-white/80">{product?.name || `Product ${item.productId}`}</span>
                                                    <div className="flex items-center gap-2">
                                                        <button
                                                            className="w-9 h-9 rounded-lg bg-white/5 hover:bg-white/10 flex items-center justify-center text-white/50 hover:text-white font-bold text-lg transition-all"
                                                            onClick={() => {
                                                                const newResults = [...results];
                                                                const index = newResults.indexOf(item);
                                                                if (index > -1) {
                                                                    newResults[index].quantity = Math.max(0, item.quantity - 1);
                                                                    setResults(newResults);
                                                                }
                                                            }}
                                                        >
                                                            −
                                                        </button>
                                                        <div className="w-14 text-center font-mono font-bold text-[#F59E0B] text-lg">
                                                            {item.quantity}
                                                        </div>
                                                        <button
                                                            className="w-9 h-9 rounded-lg bg-white/5 hover:bg-white/10 flex items-center justify-center text-white/50 hover:text-white font-bold text-lg transition-all"
                                                            onClick={() => {
                                                                const newResults = [...results];
                                                                const index = newResults.indexOf(item);
                                                                if (index > -1) {
                                                                    newResults[index].quantity = item.quantity + 1;
                                                                    setResults(newResults);
                                                                }
                                                            }}
                                                        >
                                                            +
                                                        </button>
                                                    </div>
                                                </div>
                                            );
                                        })}
                                    </div>
                                </div>
                            );
                        })}
                        {Object.keys(resultsByStore).length === 0 && (
                            <div className="text-center py-16 text-white/30">
                                <Truck size={48} className="mx-auto mb-4 opacity-20" />
                                <p className="text-sm">Нічого не розподілено</p>
                                <p className="text-xs mt-2 opacity-60">Можливо, немає дефіциту або введено нулі</p>
                            </div>
                        )}
                    </div>
                )}

                {/* Step: Success */}
                {step === 'success' && (
                    <div className="flex flex-col items-center justify-center py-20 text-center">
                        <div className="w-20 h-20 bg-[#10B981]/20 rounded-full flex items-center justify-center text-[#10B981] mb-6 animate-bounce">
                            <CheckCircle2 size={40} />
                        </div>
                        <h3 className="text-2xl font-bold text-white mb-2">Успішно!</h3>
                        <p className="text-white/50">Документи переміщення створено.</p>
                    </div>
                )}
            </ModalBody>

            {/* Footer */}
            <ModalFooter>
                <div className="flex justify-between items-center">
                    {step === 'input' && (
                        <>
                            <p className="text-xs text-white/30 max-w-[50%]">
                                Введіть кількість виготовленої продукції. Алгоритм автоматично розподілить її між магазинами.
                            </p>
                            <ModalButton
                                variant="primary"
                                onClick={handleCalculate}
                                loading={isCalculating}
                                icon={<Calculator size={18} />}
                            >
                                Розрахувати
                            </ModalButton>
                        </>
                    )}

                    {step === 'review' && (
                        <>
                            <ModalButton
                                variant="ghost"
                                onClick={() => setStep('input')}
                                icon={<ArrowLeft size={16} />}
                            >
                                Назад
                            </ModalButton>
                            <ModalButton
                                variant="primary"
                                onClick={handleConfirm}
                                loading={isSubmitting}
                                icon={<Save size={18} />}
                            >
                                Підтвердити
                            </ModalButton>
                        </>
                    )}
                </div>
            </ModalFooter>
        </Modal>
    );
};

'use client';

import React, { useState, useMemo } from 'react';
import { STORES } from '@/lib/transformers';
import { ProductionTask, SKUCategory, PriorityKey } from '@/types/bi';
import { cn } from '@/lib/utils';
import { Search, Filter, ChevronDown } from 'lucide-react';
import { UI_TOKENS } from '@/lib/design-tokens';
import { useStore } from '@/context/StoreContext';

export const MatrixTable = ({ skus }: { skus: ProductionTask[] }) => {
    const { selectedStore, setSelectedStore } = useStore();
    const [onlyCritical, setOnlyCritical] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');
    const [selectedCategory, setSelectedCategory] = useState<string>('Усі');
    const [selectedPriority, setSelectedPriority] = useState<string>('Усі');

    const filteredSkus = useMemo(() => {
        return skus.filter(sku => {
            const matchesSearch = sku.name.toLowerCase().includes(searchQuery.toLowerCase());
            const matchesCategory = selectedCategory === 'Усі' || sku.category === selectedCategory;
            const matchesCritical = !onlyCritical || sku.outOfStockStores > 0;
            const matchesStore = selectedStore === 'Усі' || sku.stores.some(s => s.storeName === selectedStore);
            const matchesPriority = selectedPriority === 'Усі' || sku.priority === selectedPriority;
            return matchesSearch && matchesCategory && matchesCritical && matchesStore && matchesPriority;
        });
    }, [skus, searchQuery, selectedCategory, onlyCritical, selectedStore, selectedPriority]);

    const categories = ['Усі', ...Array.from(new Set(skus.map(s => s.category)))];

    const getCellColor = (stock: number, threshold: number) => {
