import React, { useState } from 'react';
import useSWR from 'swr';
import { Play, Loader2, AlertCircle, RefreshCw, CheckCircle2, ShoppingBag, Truck, Download } from 'lucide-react';
import { cn } from '@/lib/utils';
import { motion, AnimatePresence } from 'framer-motion';
import { generateDistributionExcel } from '@/lib/order-export';

// --- Types ---
interface DistributionResult {
    product_name: string;
    spot_name: string;
    quantity_to_ship: number;
    calc_time: string;
}

interface ProductionStatus {
    prod_count: number;
}

import { authedFetcher } from '@/lib/authed-fetcher';

const fetcher = authedFetcher;

export const DistributionControlPanel = () => {
    // 1. Fetch Results (What has been distributed today?)
    const {
        data: resultsData,
        isLoading: resultsLoading,
        mutate: refreshResults
    } = useSWR<DistributionResult[]>('/api/pizza/distribution/results', fetcher, { refreshInterval: 10000 });

    const [isRunning, setIsRunning] = useState(false);
    const [isExporting, setIsExporting] = useState(false);
    const [lastRunResult, setLastRunResult] = useState<string | null>(null);

    // 📥 ACTION: Export to Excel
    const handleExport = async () => {
        if (!resultsData || resultsData.length === 0) return;

        setIsExporting(true);
        try {
            await generateDistributionExcel(resultsData);
            setLastRunResult('Файл збережено!');
            setTimeout(() => setLastRunResult(null), 3000);
        } catch (error) {
            console.error('Export failed:', error);
            alert('Помилка при експорті');
        } finally {
            setIsExporting(false);
        }
    };

    // 🚀 ACTION: Trigger Distribution
    const handleRunDistribution = async () => {
        setIsRunning(true);
        setLastRunResult(null);
        try {
            const res = await fetch('/api/pizza/distribution/run', { method: 'POST' });
            const json = await res.json();

            if (!res.ok) throw new Error(json.error || 'Failed to run distribution');

            setLastRunResult(json.message || 'Success');
            await refreshResults(); // Immediately update table
        } catch (error: any) {
            console.error('Distribution error:', error);
            setLastRunResult(`Error: ${error.message}`);
        } finally {
            setIsRunning(false);
        }
    };

    return (
        <div className="flex flex-col h-full bg-[#0B0E14] overflow-hidden font-sans">

            {/* --- CONTROL HEADER --- */}
            <div className="p-6 border-b border-white/5 bg-[#141829]/30 flex flex-col md:flex-row items-center justify-between gap-6">

                {/* Left: Info */}
                <div className="flex items-start gap-4">
                    <div className="w-12 h-12 rounded-xl bg-[#FFB800]/10 border border-[#FFB800]/20 flex items-center justify-center shrink-0">
                        <Truck size={24} className="text-[#FFB800]" />
                    </div>
                    <div>
                        <h2 className="text-xl font-bold text-white uppercase tracking-wide">Панель Логіста</h2>
                        <div className="text-[10px] text-white/40 uppercase font-black tracking-widest mt-1">
                            Керування розподілом продукції
                        </div>
                    </div>
                </div>

                {/* Right: Action Buttons */}
                <div className="flex flex-col items-end gap-2 w-full md:w-auto">
                    <div className="flex items-center gap-3 w-full md:w-auto">
                        {/* EXPORT BUTTON */}
                        <button
                            onClick={handleExport}
                            disabled={isExporting || resultsLoading || !resultsData || resultsData.length === 0}
                            className={cn(
                                "h-12 px-6 rounded-xl font-bold uppercase tracking-wider transition-all flex items-center gap-2 border border-white/10 shrink-0",
                                !resultsData || resultsData.length === 0
                                    ? "bg-white/5 text-white/20 cursor-not-allowed"
                                    : "bg-[#1A1F3A] text-[#00D4FF] hover:bg-[#00D4FF]/10 hover:border-[#00D4FF]/30 active:scale-[0.98]"
                            )}
                            title="Скачати Excel"
                        >
                            {isExporting ? <Loader2 size={18} className="animate-spin" /> : <Download size={18} />}
                            <span className="hidden sm:inline text-xs">Excel</span>
                        </button>

                        {/* RUN BUTTON */}
                        <button
                            onClick={handleRunDistribution}
                            disabled={isRunning}
                            className={cn(
                                "relative overflow-hidden h-12 px-8 rounded-xl font-black uppercase tracking-wider transition-all flex items-center gap-3 shadow-xl w-full md:w-auto justify-center",
                                isRunning
                                    ? "bg-[#1A1F3A] text-white/50 cursor-not-allowed border border-white/5"
                                    : "bg-gradient-to-r from-[#FFB800] to-[#FF8A00] text-[#0B0E14] hover:shadow-[0_0_30px_rgba(255,184,0,0.3)] hover:scale-[1.02] active:scale-[0.98]"
                            )}
                        >
                            {isRunning ? (
                                <>
                                    <Loader2 size={20} className="animate-spin" />
                                    <span>Розрахунок...</span>
                                </>
                            ) : (
                                <>
                                    <Play size={20} fill="currentColor" />
                                    <span>Сформувати розподілення</span>
                                </>
                            )}
                        </button>
                    </div>

                    {/* Feedback Message */}
                    <AnimatePresence>
                        {lastRunResult && (
                            <motion.div
                                initial={{ opacity: 0, y: -10 }}
                                animate={{ opacity: 1, y: 0 }}
                                exit={{ opacity: 0 }}
                                className="text-xs font-mono text-emerald-400 flex items-center gap-1.5"
                            >
                                <CheckCircle2 size={12} />
                                {lastRunResult}
                            </motion.div>
                        )}
                    </AnimatePresence>
                </div>
            </div>

            {/* --- RESULTS TABLE --- */}
            <div className="flex-1 overflow-hidden p-6">
                <div className="bg-[#141829]/50 border border-white/5 rounded-2xl h-full flex flex-col overflow-hidden">

                    {/* Table Header */}
                    <div className="grid grid-cols-12 gap-4 p-4 border-b border-white/5 bg-white/[0.02] text-[10px] uppercase font-bold tracking-widest text-white/40">
                        <div className="col-span-1 text-center">#</div>
                        <div className="col-span-5">Товар</div>
                        <div className="col-span-4">Магазин</div>
                        <div className="col-span-2 text-right">К-ть</div>
                    </div>

                    {/* Table Body */}
                    <div className="flex-1 overflow-y-auto custom-scrollbar p-2">
                        {resultsLoading ? (
                            <div className="flex flex-col items-center justify-center h-full text-white/20 gap-3">
                                <Loader2 size={32} className="animate-spin text-[#FFB800]" />
                                <span className="text-xs tracking-widest">Завантаження даних...</span>
                            </div>
                        ) : !Array.isArray(resultsData) || resultsData.length === 0 ? (
                            <div className="flex flex-col items-center justify-center h-full text-white/20 gap-4">
                                <div className="w-16 h-16 rounded-full bg-white/5 flex items-center justify-center">
                                    <ShoppingBag size={32} />
                                </div>
                                <span className="text-xs uppercase tracking-widest font-bold">Розподіл ще не сформовано</span>
                            </div>
                        ) : (
                            <div className="space-y-1">
                                {resultsData.map((row, idx) => (
                                    <motion.div
                                        key={`${row.product_name}-${row.spot_name}-${idx}`}
                                        initial={{ opacity: 0, x: -20 }}
                                        animate={{ opacity: 1, x: 0 }}
                                        transition={{ delay: idx * 0.05 }}
                                        className="grid grid-cols-12 gap-4 p-3 rounded-lg hover:bg-white/5 transition-colors border border-transparent hover:border-white/5 items-center group"
                                    >
                                        <div className="col-span-1 text-center text-white/20 font-mono text-xs">{idx + 1}</div>
                                        <div className="col-span-5 font-medium text-white/90 text-sm group-hover:text-[#FFB800] transition-colors line-clamp-1" title={row.product_name}>
                                            {row.product_name}
                                        </div>
                                        <div className="col-span-4 text-xs text-white/60 line-clamp-1" title={row.spot_name}>
                                            {row.spot_name}
                                        </div>
                                        <div className="col-span-2 text-right">
                                            <span className="inline-flex items-center justify-center px-3 py-1 rounded bg-[#FFB800]/10 text-[#FFB800] text-xs font-black font-mono border border-[#FFB800]/20 min-w-[3rem]">
                                                {row.quantity_to_ship}
                                            </span>
                                        </div>
                                    </motion.div>
                                ))}
                            </div>
                        )}
                    </div>

                    {/* Footer Info */}
                    <div className="p-3 border-t border-white/5 bg-[#0B0E14]/50 flex justify-between items-center text-[10px] text-white/30 uppercase tracking-widest font-mono">
                        <div>Всього позицій: {resultsData?.length || 0}</div>
                        <div className="flex items-center gap-2">
                            <span>Останнє оновлення: {new Date().toLocaleTimeString()}</span>
                            <button onClick={() => refreshResults()} className="hover:text-white transition-colors">
                                <RefreshCw size={12} />
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

'use client';

import React, { useMemo, useState } from 'react';
import useSWR from 'swr';
import { cn } from '@/lib/utils';
import { Loader2, Save, Activity, AlertCircle, Percent, TrendingUp } from 'lucide-react';
import { ProductionTask } from '@/types/bi';

interface Props {
    data: ProductionTask[]; // From v_pizza_distribution_stats
    onRefresh: () => void;
}

interface FactoryStockItem {
    product_name: string;
    baked_at_factory: number;
}

interface AnalyticsData {
    kpi: {
        currentStock: number;
        totalNeed: number;
        totalTarget: number;
        criticalPositions: number;
        fillLevel: string;
    };
    top5: {
        pizza_name: string;
        shop_stock: number;
        risk_index: number;
    }[];
}

import { authedFetcher } from '@/lib/authed-fetcher';

export const OrderFormTable = ({ data, onRefresh }: Props) => {
    // 1. Fetch Factory Stock
    const { data: factoryStockData, isLoading: isStockLoading } = useSWR<FactoryStockItem[]>(
        '/api/pizza/production-detail',
        (url) => authedFetcher(url),
        { refreshInterval: 10000 }
    );

    // 1.1 Fetch Analytics Data
    const { data: analytics } = useSWR<AnalyticsData>(
        '/api/pizza/analytics',
        (url) => authedFetcher(url),
        { refreshInterval: 30000 }
    );

    // 2. Local State
    const [productionPlan, setProductionPlan] = useState<Record<string, number>>({});
    const [isSubmitting, setIsSubmitting] = useState(false);

    // 3. Aggregate Data
    const tableRows = useMemo(() => {
        return data.map(product => {
            // Calculate Network Deficit (Sum of need_net from all stores)
            // Assuming product.stores contains all store entries for this product
            // deficitKg mapped from need_net in transformer
            const networkDeficit = product.stores.reduce((sum, s) => sum + (s.deficitKg || 0), 0);

            // Find Factory Stock
            const stockItem = factoryStockData?.find(
                item => item.product_name?.trim().toLowerCase() === product.name.trim().toLowerCase()
            );
            const factoryStock = stockItem?.baked_at_factory || 0;

            return {
                id: product.id,
                name: product.name,
                networkDeficit,
                factoryStock,
                currentPlan: productionPlan[product.id] || 0
            };
        })
            .filter(row => row.networkDeficit > 0 || row.factoryStock > 0) // Optional: Hide irrelevant rows? User asked for "Summary table", implying all relevant.
            .sort((a, b) => b.networkDeficit - a.networkDeficit);
    }, [data, factoryStockData, productionPlan]);


    // 4. Submit Handler
    const handleSubmit = async () => {
        setIsSubmitting(true);
        try {
            // Filter only items with input > 0
            const itemsToOrder = tableRows
                .filter(r => (productionPlan[r.id] || 0) > 0)
                .map(r => ({
                    product_id: r.id,
                    product_name: r.name,
                    quantity: productionPlan[r.id]
                }));

            if (itemsToOrder.length === 0) {
                alert('Будь ласка, введіть кількість.');
                setIsSubmitting(false);
                return;
            }

            const res = await fetch('/api/pizza/create-order', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ orders: itemsToOrder })
            });

            if (res.ok) {
                alert('Замовлення сформовано!');
                setProductionPlan({});
                onRefresh();
            } else {
                throw new Error('Failed to create order');
            }
        } catch (error) {
            console.error(error);
            alert('Помилка відправки');
        } finally {
            setIsSubmitting(false);
        }
    };

    const totalDeficit = tableRows.reduce((sum, r) => sum + r.networkDeficit, 0);
    const totalOrdered = Object.values(productionPlan).reduce((sum, v) => sum + v, 0);

    return (
        <div className="flex flex-col h-full bg-[#141829] rounded-xl border border-white/5 overflow-hidden">
            {/* ANALYTICS BLOCK */}
            <div className="p-4 grid gap-4 shrink-0 bg-[#0B0E14] border-b border-white/5">
                {/* KPI ROW */}
                <div className="grid grid-cols-4 gap-4 mb-6">
                    {/* KPI 1 */}
                    <div className="bg-[#141829]/50 border border-white/5 rounded-xl p-3 flex flex-col justify-center">
                        <div className="flex items-center gap-2 text-white/40 mb-1 text-[10px] uppercase font-bold tracking-widest">
                            <Activity size={12} />
                            <span>Залишки в мережі</span>
                        </div>
                        <div className="text-2xl font-mono font-bold text-white">
                            {analytics?.kpi?.currentStock?.toLocaleString() ?? '-'}
                            <span className="text-[10px] text-white/30 ml-1">шт</span>
                        </div>
                    </div>
                    {/* KPI 2 */}
                    <div className="bg-[#141829]/50 border border-white/5 rounded-xl p-3 flex flex-col justify-center">
                        <div className="flex items-center gap-2 text-white/40 mb-1 text-[10px] uppercase font-bold tracking-widest">
                            <TrendingUp size={12} />
                            <span>Загальна потреба</span>
                        </div>
                        <div className="text-2xl font-mono font-bold text-[#FFB800]">
                            {analytics?.kpi?.totalNeed?.toLocaleString() ?? '-'}
                            <span className="text-[10px] text-white/30 ml-1">шт</span>
                        </div>
                    </div>
                    {/* KPI 3 */}
                    {/* KPI 3: Target Stock (Replaces Critical) */}
                    <div className="bg-[#141829]/50 border border-white/5 rounded-xl p-3 flex flex-col justify-center">
                        <div className="flex items-center gap-2 text-white/40 mb-1 text-[10px] uppercase font-bold tracking-widest">
                            <Activity size={12} />
                            <span>Цільовий запас</span>
                        </div>
                        <div className="text-2xl font-mono font-bold text-[#00D4FF]">
                            {analytics?.kpi?.totalTarget?.toLocaleString() ?? '-'}
                            <span className="text-[10px] text-white/30 ml-1">шт</span>
                        </div>
                    </div>
                    {/* KPI 4 */}
                    <div className="bg-[#141829]/50 border border-white/5 rounded-xl p-3 flex flex-col justify-center">
                        <div className="flex items-center gap-2 text-white/40 mb-1 text-[10px] uppercase font-bold tracking-widest">
                            <Percent size={12} />
                            <span>Рівень наповнення</span>
                        </div>
                        <div className={cn(
                            "text-2xl font-mono font-bold",
                            Number(analytics?.kpi?.fillLevel) >= 80 ? "text-emerald-400" : "text-[#FFB800]"
                        )}>
                            {analytics?.kpi?.fillLevel ?? '-'}%
                        </div>
                    </div>
                </div>

                {/* TOP 5 TABLE */}
                {analytics?.top5 && analytics.top5.length > 0 && (
                    <div className="bg-[#141829]/30 border border-white/5 rounded-xl p-3">
                        <div className="text-[10px] text-white/40 uppercase font-bold tracking-widest mb-2 flex items-center gap-2">
                            <TrendingUp size={12} className="text-[#E74856]" />
                            ТОП-5 Гарячих позицій
                        </div>
                        <div className="grid grid-cols-5 gap-2">
                            {analytics.top5.map((item, idx) => (
                                <div key={idx} className="bg-[#141829] rounded p-2 border border-white/5 flex items-center justify-between">
                                    <div className="text-xs font-bold text-white truncate max-w-[100px]" title={item.pizza_name}>
                                        {item.pizza_name}
                                    </div>
                                    <div className="text-right leading-none">
                                        <div className={cn("font-mono font-bold", item.shop_stock <= 0 ? "text-[#E74856]" : "text-white")}>
                                            {item.shop_stock} шт
                                        </div>
                                        <div className="text-[9px] text-white/30 mt-0.5">Risk: {item.risk_index}</div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                )}
            </div>

            {/* Header */}
            <div className="grid grid-cols-[3fr_1fr_1fr_1.5fr] gap-4 px-6 py-4 bg-[#1A1F3A] border-b border-white/5 text-[10px] uppercase font-bold tracking-widest text-white/40">
                <div>Назва піци</div>
                <div className="text-right text-[#E74856]">Дефіцит мережі</div>
                <div className="text-right text-[#00D4FF]">В цеху</div>
                <div className="text-center text-[#FFB800]">Заявка</div>
            </div>

            {/* List */}
            <div className="flex-1 overflow-y-auto custom-scrollbar p-2">
                {isStockLoading && !factoryStockData && (
                    <div className="flex justify-center p-4"><Loader2 className="animate-spin text-[#00D4FF]" /></div>
                )}

                {tableRows.map(row => (
                    <div key={row.id} className="grid grid-cols-[3fr_1fr_1fr_1.5fr] gap-4 items-center px-4 py-3 border-b border-white/5 last:border-0 hover:bg-white/5 transition-colors">
                        <div className="font-medium text-white/90">{row.name}</div>

                        <div className="text-right font-mono font-bold text-lg text-[#E74856]">
                            {row.networkDeficit > 0 ? row.networkDeficit : <span className="text-white/10">-</span>}
                        </div>

                        <div className="text-right font-mono font-bold text-lg text-[#00D4FF]">
                            {row.factoryStock > 0 ? row.factoryStock : <span className="text-white/10">-</span>}
                        </div>

                        <div className="flex justify-center">
                            <input
                                type="number"
                                value={productionPlan[row.id] || ''}
                                onChange={(e) => {
                                    const val = Math.max(0, Number(e.target.value));
                                    setProductionPlan(prev => ({ ...prev, [row.id]: val }));
                                }}
                                className={cn(
                                    "w-24 h-10 bg-[#0F1220] border border-white/10 rounded-lg text-center font-mono font-bold text-xl text-white focus:outline-none focus:border-[#FFB800] transition-all",
                                    (productionPlan[row.id] || 0) > 0 && "text-[#FFB800] border-[#FFB800]/50 bg-[#FFB800]/10"
                                )}
                                placeholder="-"
                            />
                        </div>
                    </div>
                ))}
            </div>

            {/* Footer */}
            <div className="p-4 bg-[#1A1F3A] border-t border-white/5 flex items-center justify-between">
                <div className="flex items-center gap-6">
                    <div>
                        <div className="text-[10px] text-white/40 uppercase font-bold">Всього дефіцит</div>
                        <div className="text-xl font-mono font-bold text-[#E74856]">{totalDeficit}</div>
                    </div>
                    <div>
                        <div className="text-[10px] text-white/40 uppercase font-bold">Всього в заявці</div>
                        <div className="text-xl font-mono font-bold text-[#FFB800]">{totalOrdered}</div>
                    </div>
                </div>

                <button
                    onClick={handleSubmit}
                    disabled={isSubmitting || totalOrdered === 0}
                    className="flex items-center gap-2 px-6 py-3 bg-[#FFB800] hover:bg-[#FFB800]/90 text-black font-bold uppercase tracking-wider rounded-xl transition-all disabled:opacity-50 disabled:cursor-not-allowed"
                >
                    {isSubmitting ? <Loader2 className="animate-spin" /> : <Save size={18} />}
                    Сформувати
                </button>
            </div>
        </div>
    );
};

'use client';

import React, { useState } from 'react';
import useSWR from 'swr';
import { ProductionTask } from '@/types/bi';
import { cn } from '@/lib/utils';
import { generateProductionPlanExcel } from '@/lib/order-export';
import { Activity, Percent, TrendingUp, Calculator, Package, AlertTriangle, ChevronDown, FileSpreadsheet, Loader2 } from 'lucide-react';

interface Props {
    data: ProductionTask[];
    onRefresh: () => void;
}

export const ProductionOpsTable = ({ data, onRefresh }: Props) => {
    // 2. State
    const [days, setDays] = useState(1);
    const [isShiftMode, setIsShiftMode] = useState(false);
    const [selectedPizza, setSelectedPizza] = useState<string | null>(null);
    const [notification, setNotification] = useState<string | null>(null);

    // 3. Execution State
    const [isLoading, setIsLoading] = useState(false);
    const [isExporting, setIsExporting] = useState(false);
    const [isCalculated, setIsCalculated] = useState(false);
    const [planData, setPlanData] = useState<any[]>([]);

    // 4. Shop Stats
    const { data: shopStats } = useSWR<any[]>(
        selectedPizza ? `/api/pizza/shop-stats?pizza=${encodeURIComponent(selectedPizza)}` : null,
        (url: string) => fetch(url).then(r => r.json())
    );

    const handleGenerateOrder = async () => {
        setIsLoading(true);
        setPlanData([]);
        setIsCalculated(false);
        setSelectedPizza(null);

        try {
            const queryParams = new URLSearchParams({
                days: isShiftMode ? '3' : days.toString()
            });

            const response = await fetch(`/api/pizza/order-plan?${queryParams}`);

            if (!response.ok) throw new Error('API Error');

            const data = await response.json();
            setPlanData(data);
            setIsCalculated(true);

        } catch (error) {
            console.error("Calculation failed:", error);
            alert("Помилка розрахунку");
        } finally {
            setIsLoading(false);
        }
    };

    const handleExportExcel = async () => {
        if (planData.length === 0) return;
        setIsExporting(true);
        try {
            await generateProductionPlanExcel(planData, isShiftMode ? 3 : days);
            setNotification('Файл успішно збережено!');
            setTimeout(() => setNotification(null), 3000);
        } catch (error) {
            console.error('Export failed:', error);
            alert('Помилка експорту');
        } finally {
            setIsExporting(false);
        }
    };

    return (
        <div className="h-full flex flex-col bg-[#0B0E14] overflow-hidden font-sans">
            {/* 1. MANAGEMENT BLOCK (Control Panel) */}
            <div className="px-8 py-6 bg-[#0F1220]/80 border-b border-white/5 shrink-0 relative flex items-center gap-10 backdrop-blur-xl z-20 shadow-2xl transition-all">

                {/* Notification Toast */}
                {notification && (
                    <div className="absolute top-2 right-8 bg-[#00D4FF]/20 text-[#00D4FF] border border-[#00D4FF]/30 px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest animate-in fade-in slide-in-from-top-2 z-30 shadow-[0_0_30px_rgba(0,212,255,0.2)]">
                        {notification}
                    </div>
                )}

                {/* Days Input Group */}
                <div className="flex items-center gap-4 group/input">
                    <div className="flex flex-col">
                        <label className={cn(
                            "text-[10px] font-black uppercase tracking-[0.2em] mb-1.5 transition-colors",
                            isShiftMode ? "text-white/20" : "text-white/40 group-hover/input:text-[#FFB800]"
                        )}>
                            Планування
                        </label>
                        <div className="flex items-center gap-3">
                            <input
                                type="number"
                                min="1"
                                max="30"
                                value={isShiftMode ? 3 : days}
                                disabled={isShiftMode}
                                onChange={(e) => {
                                    const val = parseInt(e.target.value);
                                    if (!isNaN(val)) setDays(Math.max(1, val));
                                }}
                                className={cn(
                                    "w-24 h-12 bg-black/40 border-2 rounded-xl text-center font-mono font-black text-xl text-white focus:outline-none transition-all duration-300",
                                    isShiftMode
                                        ? "border-transparent text-white/10 opacity-30 cursor-not-allowed"
                                        : "border-white/5 focus:border-[#FFB800] focus:shadow-[0_0_20px_rgba(255,184,0,0.15)] group-hover/input:border-white/10"
                                )}
                            />
                            <span className={cn(
                                "text-xs font-bold uppercase tracking-widest",
                                "text-white/30"
                            )}>Днів</span>
                        </div>
                    </div>
                </div>

                <div className="h-10 w-px bg-white/5" />

                {/* 3x3 Toggle Segment */}
                <div className="flex flex-col">
                    <label className="text-[10px] font-black uppercase tracking-[0.2em] mb-1.5 text-white/40">
                        Режим роботи
                    </label>
                    <div
                        onClick={() => setIsShiftMode(!isShiftMode)}
                        className="flex items-center gap-4 cursor-pointer group select-none bg-black/40 border-2 border-white/5 hover:border-white/10 px-4 py-2 rounded-xl transition-all h-12"
                    >
                        <div className={cn(
                            "relative w-12 h-6 rounded-full transition-all duration-500",
                            isShiftMode ? "bg-[#00D4FF] shadow-[0_0_15px_rgba(0,212,255,0.3)]" : "bg-white/10"
                        )}>
                            <div className={cn(
                                "absolute top-1 left-1 w-4 h-4 rounded-full bg-white transition-transform duration-500 shadow-xl",
                                isShiftMode ? "translate-x-6" : "translate-x-0"
                            )} />
                        </div>
                        <span className={cn(
                            "text-xs font-black uppercase tracking-widest transition-colors",
                            isShiftMode ? "text-white" : "text-white/40 group-hover:text-white"
                        )}>
                            Режим 3х3
                        </span>
                    </div>
                </div>

                <div className="flex-1" />

                {/* EXPORT BUTTON */}
                {isCalculated && (
                    <button
                        onClick={handleExportExcel}
                        disabled={isExporting}
                        className={cn(
                            "flex items-center gap-3 px-6 py-4 bg-[#10B981]/10 border border-[#10B981]/20 hover:bg-[#10B981]/20 active:scale-95 text-[#10B981] font-black uppercase tracking-[0.2em] text-xs rounded-2xl transition-all mr-4 disabled:opacity-50 disabled:cursor-not-allowed",
                            isExporting && "animate-pulse"
                        )}
                    >
                        {isExporting ? <Loader2 size={16} className="animate-spin" /> : <FileSpreadsheet size={18} strokeWidth={2.5} />}
                        {isExporting ? "Експорт..." : "Excel звір"}
                    </button>
                )}

                {/* Action Button */}
                <button
                    onClick={handleGenerateOrder}
                    disabled={isLoading}
                    className={cn(
                        "flex items-center gap-4 px-10 py-4 bg-gradient-to-r from-[#00D4FF] to-[#0088FF] hover:to-[#00D4FF] active:scale-95 text-[#0B0E14] font-black uppercase tracking-[0.2em] text-sm rounded-2xl transition-all shadow-[0_10px_30px_rgba(0,212,255,0.3)] hover:shadow-[0_15px_40px_rgba(0,212,255,0.5)] disabled:opacity-50 disabled:cursor-not-allowed",
                        isLoading && "animate-pulse"
                    )}
                >
                    <Calculator size={20} strokeWidth={3} />
                    {isLoading ? "Розрахунок..." : "Розрахувати"}
                </button>
            </div>

            {/* 2. RESULTS GRID */}
            <div className="flex-1 overflow-auto bg-[#0B0E14] relative text-white px-8 py-6 custom-scrollbar">

                {/* LOADING / EMPTY STATES */}
                {isLoading && (
                    <div className="absolute inset-0 flex items-center justify-center bg-[#0B0E14]/90 z-30 backdrop-blur-sm">
                        <div className="flex flex-col items-center gap-6">
                            <div className="relative">
                                <div className="absolute inset-0 blur-2xl bg-[#FFB800]/20 animate-pulse rounded-full" />
                                <Calculator className="animate-[spin_3s_linear_infinite] text-[#FFB800] relative z-10" size={64} />
                            </div>
                            <div className="flex flex-col items-center">
                                <span className="text-xl font-black uppercase tracking-[0.3em] text-white">Аналіз даних</span>
                                <span className="text-[10px] font-bold uppercase tracking-widest text-white/30 mt-2">Формування оптимального замовлення</span>
                            </div>
                        </div>
                    </div>
                )}

                {!isCalculated && !isLoading && (
                    <div className="h-full flex flex-col items-center justify-center opacity-30 select-none">
                        <div className="w-24 h-24 rounded-full border-2 border-dashed border-white/20 flex items-center justify-center mb-6">
                            <Activity size={40} className="animate-pulse" />
                        </div>
                        <h3 className="text-lg font-black uppercase tracking-[0.2em] mb-2 text-white">Готовий до розрахунку</h3>
                        <p className="text-xs font-medium text-white/40 tracking-wider">Оберіть дні та натисніть кнопку "Розрахувати"</p>
                    </div>
                )}

                {/* RESULTS - HORIZONTAL TAPE + FULL GRID LAYOUT */}
                {isCalculated && !isLoading && (
                    <div className="flex flex-col gap-10 pb-10">
                        {Object.entries(planData.reduce((acc, item) => {
                            (acc[item.p_day] = acc[item.p_day] || []).push(item);
                            return acc;
                        }, {} as Record<number, any[]>))
                            .sort(([dayA], [dayB]) => Number(dayA) - Number(dayB))
                            .map(([day, items]: [string, any]) => (
                                <div key={day} className="flex flex-col gap-4">
                                    {/* DAY HEADER */}
                                    <div className="flex items-center gap-6 px-2 mb-2">
                                        <div className="px-6 py-2 rounded-xl bg-white/5 border border-white/10 text-white text-sm font-black uppercase tracking-[0.3em] shadow-lg">
                                            День <span className="text-[#00D4FF] ml-1">{day}</span>
                                        </div>
                                        <div className="h-px bg-gradient-to-r from-white/10 via-transparent to-transparent flex-1" />
                                        <div className="text-[10px] text-white/20 font-black uppercase tracking-[0.2em]">
                                            {items.length} ПРЕДМЕТІВ
                                        </div>
                                    </div>

                                    {/* HORIZONTAL TAPE OF CARDS */}
                                    <div className="flex gap-4 overflow-x-auto pb-6 px-1 custom-scrollbar snap-x">
                                        {items.sort((a: any, b: any) => (Number(b.p_avg) || 0) - (Number(a.p_avg) || 0)).map((item: any, idx: number) => {
                                            const isSelected = selectedPizza === item.p_name;
                                            const pStock = Number(item.p_stock);
                                            const pOrder = Number(item.p_order);
                                            const target = pStock + pOrder;
                                            const percentage = target === 0 ? 100 : Math.min(100, (pStock / target) * 100);

                                            const isCritical = percentage < 60;
                                            const isWarning = percentage >= 60 && percentage < 90;

                                            return (
                                                <div
                                                    key={idx}
                                                    onClick={() => setSelectedPizza(prev => prev === item.p_name ? null : item.p_name)}
                                                    className={cn(
                                                        "min-w-[280px] snap-start bg-[#141829]/40 border rounded-2xl transition-all duration-500 cursor-pointer select-none group/card relative backdrop-blur-sm",
                                                        isSelected
                                                            ? "ring-2 ring-[#00D4FF] border-[#00D4FF]/20 shadow-[0_15px_40px_rgba(0,212,255,0.2)] bg-[#141829]/80 scale-[1.02]"
                                                            : "border-white/5 hover:border-white/20 hover:bg-[#141829]/60"
                                                    )}
                                                >
                                                    {/* Status Indicator Bar */}
                                                    <div className={cn(
                                                        "h-1 w-full rounded-t-2xl",
                                                        isCritical ? "bg-red-500 shadow-[0_0_10px_#ef4444]" :
                                                            isWarning ? "bg-amber-500 shadow-[0_0_10px_#f59e0b]" :
                                                                "bg-emerald-500 shadow-[0_0_10px_#10b981]"
                                                    )} />

                                                    <div className="p-4">
                                                        <div className="flex items-start justify-between gap-3 mb-4">
                                                            <h4 className="text-[11px] font-black text-white/90 leading-tight tracking-tight uppercase group-hover/card:text-white transition-colors truncate" title={item.p_name}>
                                                                {item.p_name}
                                                            </h4>
                                                            {isCritical && <AlertTriangle size={14} className="text-red-500 shrink-0" />}
                                                        </div>

                                                        <div className="flex items-end justify-between mb-4">
                                                            <div className="flex flex-col">
                                                                <span className="text-[8px] font-black text-white/30 uppercase tracking-[0.15em] mb-0.5">ЗАМОВЛЕННЯ</span>
                                                                <div className="flex items-baseline gap-1">
                                                                    <span className={cn(
                                                                        "text-3xl font-black font-mono leading-none tracking-tighter",
                                                                        pOrder > 0 ? "text-[#00D4FF]" : "text-white/10"
                                                                    )}>
                                                                        {pOrder.toFixed(0)}
                                                                    </span>
                                                                    <span className="text-[10px] font-black text-white/20 uppercase">шт</span>
                                                                </div>
                                                            </div>
                                                            <div className="flex flex-col items-end">
                                                                <span className="text-[8px] font-black text-white/30 uppercase tracking-[0.15em] mb-0.5">ФАКТ</span>
                                                                <span className={cn(
                                                                    "text-lg font-black font-mono leading-none",
                                                                    isCritical ? "text-red-500" : isWarning ? "text-amber-500" : "text-emerald-500"
                                                                )}>
                                                                    {pStock.toFixed(0)}
                                                                </span>
                                                            </div>
                                                        </div>

                                                        <div className="relative h-1.5 bg-black/40 rounded-full overflow-hidden border border-white/5 mb-3">
                                                            <div
                                                                className={cn(
                                                                    "h-full rounded-full transition-all duration-1000",
                                                                    isCritical ? "bg-red-500" :
                                                                        isWarning ? "bg-amber-500" :
                                                                            "bg-emerald-500"
                                                                )}
                                                                style={{ width: `${percentage}%` }}
                                                            />
                                                        </div>

                                                        <div className="flex items-center justify-between text-[9px] font-bold text-white/40 uppercase tracking-widest pt-1 border-t border-white/5">
                                                            <div className="flex gap-3">
                                                                <span>Мін <span className="text-white/80 font-mono ml-0.5">{Number(item.p_min).toFixed(0)}</span></span>
                                                                <span>Сер <span className="text-white/80 font-mono ml-0.5">{Number(item.p_avg).toFixed(1)}</span></span>
                                                            </div>
                                                            <ChevronDown size={12} className={cn("transition-transform duration-500", isSelected && "rotate-180 text-[#00D4FF]")} />
                                                        </div>
                                                    </div>
                                                </div>
                                            );
                                        })}
                                    </div>

                                    {/* FULL GRID ANALYTICS (Appears when a pizza is selected) */}
                                    {selectedPizza && items.some((i: any) => i.p_name === selectedPizza) && (
                                        <div className="mt-2 bg-[#0F1220]/60 border border-white/5 rounded-3xl p-8 animate-in fade-in slide-in-from-top-4 duration-500 backdrop-blur-md shadow-2xl">
                                            <div className="flex items-baseline justify-between mb-8 pb-4 border-b border-white/5">
                                                <div className="flex items-center gap-4">
                                                    <div className="w-2 h-8 bg-[#00D4FF] rounded-full shadow-[0_0_15px_rgba(0,212,255,0.4)]" />
                                                    <h3 className="text-xl font-black uppercase tracking-[0.2em] text-white">
                                                        Аналітика: <span className="text-[#00D4FF]">{selectedPizza}</span>
                                                    </h3>
                                                </div>
                                                <div className="text-[10px] font-black text-white/20 uppercase tracking-[0.2em]">
                                                    {shopStats?.length || 0} ТОЧОК ПРОДАЖУ ТА ПРІОРИТЕТІВ
                                                </div>
                                            </div>

                                            {!shopStats ? (
                                                <div className="py-20 flex flex-col items-center gap-6">
                                                    <div className="relative">
                                                        <div className="absolute inset-0 blur-2xl bg-[#00D4FF]/20 animate-pulse rounded-full" />
                                                        <Activity className="animate-spin text-[#00D4FF] relative z-10" size={48} />
                                                    </div>
                                                    <span className="text-xs font-black uppercase tracking-[0.3em] text-white/20">Отримання даних по магазинах...</span>
                                                </div>
                                            ) : (
                                                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-5 gap-4">
                                                    {[...shopStats]
                                                        .sort((a, b) => (b.avg_sales_day || 0) - (a.avg_sales_day || 0))
                                                        .map((stat, sIdx) => {
                                                            const isDeficit = (stat.stock_now || 0) <= (stat.min_stock || 0);
                                                            const need = Math.max(0, Math.ceil((stat.avg_sales_day * days) + (stat.min_stock || 0) - (stat.stock_now || 0)));

                                                            return (
                                                                <div key={sIdx} className={cn(
                                                                    "rounded-2xl p-5 border transition-all duration-300 flex flex-col justify-between group/shop relative overflow-hidden",
                                                                    isDeficit
                                                                        ? "bg-red-500/10 border-red-500/20 shadow-[0_10px_30px_rgba(239,68,68,0.05)]"
                                                                        : "bg-black/30 border-white/5 hover:border-white/20"
                                                                )}>
                                                                    <div className="flex flex-col mb-4">
                                                                        <h5 className="text-xs font-black uppercase tracking-tight text-white/80 group-hover/shop:text-white transition-colors mb-2 truncate" title={stat.spot_name}>
                                                                            {stat.spot_name}
                                                                        </h5>
                                                                        <div className="flex items-center gap-2">
                                                                            <span className="text-[9px] font-black text-white/10 uppercase tracking-widest">СЕР.ПРОДАЖІ:</span>
                                                                            <span className="text-sm font-mono font-black text-[#00D4FF]">
                                                                                {Number(stat.avg_sales_day || 0).toFixed(1)}
                                                                            </span>
                                                                        </div>
                                                                    </div>

                                                                    <div className="flex items-end justify-between pt-4 border-t border-white/5">
                                                                        <div className="flex flex-col">
                                                                            <span className="text-[8px] font-black text-white/20 uppercase mb-1">ФАКТ</span>
                                                                            <span className={cn("text-xl font-mono font-black leading-none", isDeficit ? "text-red-400" : "text-emerald-400")}>
                                                                                {stat.stock_now || 0}
                                                                            </span>
                                                                        </div>
                                                                        <div className="flex flex-col items-end">
                                                                            <span className="text-[8px] font-black text-[#58A6FF] uppercase mb-1 drop-shadow-[0_0_8px_rgba(88,166,255,0.3)]">ТРЕБА</span>
                                                                            <span className="text-2xl font-mono font-black text-[#58A6FF] leading-none">
                                                                                {need.toFixed(0)}
                                                                            </span>
                                                                        </div>
                                                                    </div>

                                                                    {isDeficit && (
                                                                        <div className="absolute top-2 right-2">
                                                                            <div className="w-2 h-2 bg-red-500 rounded-full animate-pulse shadow-[0_0_10px_#ef4444]" />
                                                                        </div>
                                                                    )}
                                                                </div>
                                                            );
                                                        })}
                                                </div>
                                            )}
                                        </div>
                                    )}
                                </div>
                            ))}
                    </div>
                )}
            </div>
        </div>
    );
};

import React, { useState, useMemo } from 'react';
import useSWR from 'swr';
import { cn } from '@/lib/utils';
import { ChefHat, Activity, CheckCircle, Percent, RefreshCw, Calculator, Loader2, AlertCircle, Truck } from 'lucide-react';
import { PizzaPowerMatrix } from '../PizzaPowerMatrix';
import { ProductionOpsTable } from './ProductionOrderTable';
import { ProductionTask } from '@/types/bi';
import { BackToHome } from '../BackToHome';
import { DistributionModal } from '../DistributionModal';
import { ProductionDetailModal } from '../ProductionDetailModal';
import { DistributionControlPanel } from './DistributionControlPanel';

// --- SUPPORTING COMPONENTS ---
interface ProductionItem {
    product_name: string;
    baked_at_factory: number;
}

const ProductionDetailView = () => {
    const { data, error, isLoading } = useSWR<ProductionItem[]>(
        '/api/pizza/production-detail',
        (url) => fetch(url, { credentials: 'include' }).then(r => r.json()),
        { refreshInterval: 10000 }
    );

    return (
        <div className="h-full overflow-y-auto custom-scrollbar p-4 bg-[#0B0E14]">
            <div className="rounded-xl border border-white/5 bg-[#141829]/50 overflow-hidden">
                <div className="p-4 border-b border-white/5 bg-white/5 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-lg bg-[#00D4FF]/10 flex items-center justify-center">
                            <ChefHat size={16} className="text-[#00D4FF]" />
                        </div>
                        <h3 className="text-sm font-bold text-white uppercase tracking-wider">Статистика Виробництва</h3>
                    </div>
                    <div className="text-[10px] text-white/40 uppercase font-black tracking-widest">Останні 24 год</div>
                </div>

                {isLoading ? (
                    <div className="flex flex-col items-center justify-center py-20 text-white/30 gap-3">
                        <Loader2 size={32} className="animate-spin text-[#00D4FF]" />
                        <span className="text-xs font-mono uppercase tracking-widest">Завантаження...</span>
                    </div>
                ) : error ? (
                    <div className="flex flex-col items-center justify-center py-20 text-[#E74856] gap-3">
                        <AlertCircle size={32} />
                        <span className="text-sm font-bold">Помилка завантаження</span>
                    </div>
                ) : data && data.length > 0 ? (
                    <table className="w-full text-left border-collapse">
                        <thead className="bg-[#1A1F3A]/50 text-[10px] uppercase font-bold tracking-widest text-white/40 border-b border-white/5">
                            <tr>
                                <th className="p-4">Піца</th>
                                <th className="p-4 text-right">Виготовлено (шт)</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-white/5">
                            {data.map((item, i) => (
                                <tr key={i} className="group hover:bg-white/[0.02] transition-colors">
                                    <td className="p-4 text-sm font-medium text-white/90 group-hover:text-white">
                                        {item.product_name}
                                    </td>
                                    <td className="p-4 text-right">
                                        <span className="inline-flex items-center justify-center px-4 py-1.5 rounded-lg bg-[#00D4FF]/10 text-[#00D4FF] font-mono text-sm font-black min-w-[4rem] border border-[#00D4FF]/20">
                                            {item.baked_at_factory}
                                        </span>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                ) : (
                    <div className="flex flex-col items-center justify-center py-20 text-white/30">
                        <ChefHat size={32} className="mb-3 opacity-20" />
                        <span className="text-sm">Дані відсутні</span>
                    </div>
                )}
            </div>
        </div>
    );
};

interface Props {
    data: ProductionTask[];
    onRefresh: () => void;
    showTabs?: boolean;
}

export const ProductionTabs = ({ data, onRefresh, showTabs = true }: Props) => {
    // UPDATED TABS: 'matrix' replaces old 'distribution', 'logistics' is NEW
    const [activeTab, setActiveTab] = useState<'orders' | 'matrix' | 'production' | 'logistics'>('orders');
    const [isRefreshing, setIsRefreshing] = useState(false);
    const [isUpdatingStock, setIsUpdatingStock] = useState(false);
    const [showDistModal, setShowDistModal] = useState(false);
    const [showProductionModal, setShowProductionModal] = useState(false);

    // 🏭 PRODUCTION SUMMARY
    const { data: productionSummary } = useSWR('/api/pizza/summary', (url) => fetch(url, { credentials: 'include' }).then(r => r.json()), { refreshInterval: 30000 });

    // 🔥 WEBHOOK: Update stock from n8n
    const handleUpdateStock = async () => {
        setIsUpdatingStock(true);
        try {
            const response = await fetch('/api/pizza/update-stock', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ action: 'update_stock', timestamp: new Date().toISOString() })
            });

            if (response.ok) {
                await onRefresh();
            } else {
                console.error('Stock update failed:', response.status);
            }
        } catch (error) {
            console.error('Stock update error:', error);
        } finally {
            setIsUpdatingStock(false);
        }
    };

    const handleManualRefresh = async () => {
        setIsRefreshing(true);
        await onRefresh();
        setTimeout(() => setIsRefreshing(false), 500);
    };

    // 📊 GLOBAL METRICS CALCULATION
    const globalMetrics = useMemo(() => {
        const totalNetworkStock = data.reduce((sum, p) => {
            const prodStock = p.stores?.reduce((sSum, s) => sSum + (Number(s.currentStock) || 0), 0) || 0;
            return sum + prodStock;
        }, 0);

        const totalNetworkMinStock = productionSummary?.total_norm || 0;

        const fillIndex = totalNetworkMinStock > 0
            ? (totalNetworkStock / totalNetworkMinStock) * 100
            : 0;

        return {
            totalNetworkStock,
            totalNetworkMinStock,
            fillIndex
        };
    }, [data, productionSummary]);

    const getIndexColor = (val: number) => {
        if (val >= 96) return "text-emerald-400";
        if (val >= 80) return "text-[#FFB800]";
        return "text-[#E74856]";
    };

    return (
        <div className="flex flex-col h-full w-full bg-[#0B0E14] font-sans">
            {/* 1. HEADER & MONITORING BLOCK */}
            <header className="flex-shrink-0 p-3 pb-2 z-20">
                <div className="rounded-2xl p-4 border border-[#FFB800]/20 bg-[#1A1F3A]/90 backdrop-blur-xl shadow-2xl flex flex-col gap-4">

                    {/* Top Row: Navigation & Title */}
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-4">
                            <BackToHome />

                            <div className="flex items-center gap-3">
                                <div className="w-10 h-10 rounded-xl bg-[#FFB800]/10 flex items-center justify-center border border-[#FFB800]/20">
                                    <ChefHat size={20} className="text-[#FFB800]" />
                                </div>
                                <div>
                                    <h1 className="text-xl font-bold uppercase tracking-wide leading-none text-white">ЦЕХ Піца</h1>
                                    <div className="text-[10px] text-white/50 uppercase tracking-widest mt-1">
                                        Менеджер розподілу
                                    </div>
                                </div>
                            </div>
                        </div>

                        <div className="flex items-center gap-3">
                            <button
                                onClick={handleUpdateStock}
                                disabled={isUpdatingStock}
                                className={cn(
                                    "h-9 px-4 flex items-center gap-2 border rounded-lg text-xs uppercase font-bold tracking-wider transition-all",
                                    isUpdatingStock
                                        ? "bg-[#FFB800]/20 border-[#FFB800]/30 text-[#FFB800] cursor-not-allowed"
                                        : "bg-[#FFB800]/10 hover:bg-[#FFB800]/20 border-[#FFB800]/30 text-[#FFB800] hover:text-[#FFB800]"
                                )}
                            >
                                <RefreshCw size={14} className={cn(isUpdatingStock && "animate-spin")} />
                                <span>Оновити залишки</span>
                            </button>
                        </div>
                    </div>

                    {/* Second Row: Monitoring Cards */}
                    <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-3">
                        <div
                            onClick={() => setActiveTab('production')}
                            className="bg-[#141829]/50 rounded-xl p-4 border border-white/5 flex flex-col justify-center relative overflow-hidden cursor-pointer group hover:bg-[#141829]/80 hover:border-[#00D4FF]/30 transition-all duration-300"
                        >
                            <div className="absolute top-0 right-0 p-3 opacity-10 group-hover:opacity-20 transition-opacity text-[#00D4FF]">
                                <ChefHat size={64} />
                            </div>
                            <div className="flex items-center gap-2 text-white/40 mb-1 relative z-10">
                                <ChefHat size={14} className="text-[#00D4FF]" />
                                <span className="text-[10px] uppercase font-bold tracking-widest text-[#00D4FF]">Виробництво (Піца)</span>
                            </div>
                            <div className="flex items-baseline gap-2 relative z-10">
                                <span className="text-4xl font-mono font-bold text-[#00D4FF] leading-none">
                                    {productionSummary?.total_baked?.toLocaleString() || 0}
                                </span>
                                <span className="text-xs text-white/40 font-bold uppercase">шт.</span>
                            </div>
                        </div>

                        <div className="bg-[#141829]/50 rounded-xl p-4 border border-white/5 flex flex-col justify-center">
                            <div className="flex items-center gap-2 text-white/40 mb-1">
                                <Activity size={14} />
                                <span className="text-[10px] uppercase font-bold tracking-widest">Факт залишок</span>
                            </div>
                            <div className="flex items-baseline gap-2">
                                <span className={cn(
                                    "text-4xl font-mono font-bold leading-none",
                                    globalMetrics.fillIndex >= 96 ? "text-emerald-400" :
                                        globalMetrics.fillIndex >= 80 ? "text-[#FFB800]" : "text-[#E74856]"
                                )}>
                                    {globalMetrics.totalNetworkStock.toLocaleString()}
                                </span>
                                <span className="text-xs text-white/40 font-bold uppercase">шт.</span>
                            </div>
                        </div>

                        <div className="bg-[#141829]/50 rounded-xl p-4 border border-white/5 flex flex-col justify-center">
                            <div className="flex items-center gap-2 text-white/40 mb-1">
                                <CheckCircle size={14} />
                                <span className="text-[10px] uppercase font-bold tracking-widest">Норма</span>
                            </div>
                            <div className="flex items-baseline gap-2">
                                <span className="text-4xl font-mono font-bold text-white leading-none">
                                    {globalMetrics.totalNetworkMinStock.toLocaleString()}
                                </span>
                                <span className="text-xs text-white/40 font-bold uppercase">шт.</span>
                            </div>
                        </div>

                        <div className="bg-[#141829]/50 rounded-xl p-4 border border-white/5 flex flex-col justify-center">
                            <div className="flex items-center gap-2 text-white/40 mb-1">
                                <Percent size={14} />
                                <span className="text-[10px] uppercase font-bold tracking-widest">Індекс заповненостей</span>
                            </div>
                            <div className="flex items-baseline gap-2">
                                <span className={cn("text-4xl font-mono font-bold leading-none", getIndexColor(globalMetrics.fillIndex))}>
                                    {globalMetrics.fillIndex.toFixed(0)}%
                                </span>
                            </div>
                        </div>
                    </div>

                    {/* Third Row: Tabs Container (CONDITIONAL) */}
                    {showTabs && (
                        <div className="flex items-center gap-2 p-1.5 bg-[#0F1220]/80 rounded-2xl border border-white/5 backdrop-blur-md shadow-inner">
                            <button
                                onClick={() => setActiveTab('orders')}
                                className={cn(
                                    "flex-1 h-12 px-6 text-xs font-black uppercase tracking-[0.15em] rounded-xl transition-all duration-500 flex items-center justify-center gap-3 relative overflow-hidden group/tab",
                                    activeTab === 'orders'
                                        ? "bg-gradient-to-r from-[#00D4FF] to-[#0088FF] text-[#0B0E14] shadow-[0_0_25px_rgba(0,212,255,0.4)]"
                                        : "text-white/30 hover:text-white/60 hover:bg-white/5"
                                )}
                            >
                                <div className={cn(
                                    "p-1.5 rounded-lg transition-colors",
                                    activeTab === 'orders' ? "bg-black/10" : "bg-white/5"
                                )}>
                                    <Calculator size={16} strokeWidth={2.5} />
                                </div>
                                <span>ЗАМОВЛЕННЯ</span>
                                {activeTab === 'orders' && (
                                    <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent -translate-x-full animate-[shimmer_2s_infinite] pointer-events-none" />
                                )}
                            </button>

                            <button
                                onClick={() => setActiveTab('matrix')}
                                className={cn(
                                    "flex-1 h-12 px-6 text-xs font-black uppercase tracking-[0.15em] rounded-xl transition-all duration-500 flex items-center justify-center gap-3 relative overflow-hidden group/tab",
                                    activeTab === 'matrix'
                                        ? "bg-gradient-to-r from-[#FFB800] to-[#FF8A00] text-[#0B0E14] shadow-[0_0_25px_rgba(255,184,0,0.4)]"
                                        : "text-white/30 hover:text-white/60 hover:bg-white/5"
                                )}
                            >
                                <div className={cn(
                                    "p-1.5 rounded-lg transition-colors",
                                    activeTab === 'matrix' ? "bg-black/10" : "bg-white/5"
                                )}>
                                    <Activity size={16} strokeWidth={2.5} />
                                </div>
                                <span>МАТРИЦЯ (OLD)</span>
                                {activeTab === 'matrix' && (
                                    <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent -translate-x-full animate-[shimmer_2s_infinite] pointer-events-none" />
                                )}
                            </button>

                            <button
                                onClick={() => setActiveTab('production')}
                                className={cn(
                                    "flex-1 h-12 px-6 text-xs font-black uppercase tracking-[0.15em] rounded-xl transition-all duration-500 flex items-center justify-center gap-3 relative overflow-hidden group/tab",
                                    activeTab === 'production'
                                        ? "bg-gradient-to-r from-[#58A6FF] to-[#1E5FCC] text-white shadow-[0_0_25px_rgba(88,166,255,0.4)]"
                                        : "text-white/30 hover:text-white/60 hover:bg-white/5"
                                )}
                            >
                                <div className={cn(
                                    "p-1.5 rounded-lg transition-colors",
                                    activeTab === 'production' ? "bg-black/20" : "bg-white/5"
                                )}>
                                    <ChefHat size={16} strokeWidth={2.5} />
                                </div>
                                <span>ВИРОБНИЦТВО</span>
                                {activeTab === 'production' && (
                                    <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full animate-[shimmer_2s_infinite] pointer-events-none" />
                                )}
                            </button>

