'use client';

import React, { useState, useEffect } from 'react';
import Link from 'next/link';
import useSWR from 'swr';
import { Activity, ArrowRight, BarChart2, ChefHat, LayoutGrid, Zap, Factory, Store, ShoppingBag } from 'lucide-react';
import { cn } from '@/lib/utils';
import { CriticalCounter, StatusDot, Skeleton } from '@/components/ui';

import { authedFetcher } from '@/lib/authed-fetcher';

const fetcher = authedFetcher;

export default function CommandLevel1() {
  const [hoveredCard, setHoveredCard] = useState<string | null>(null);

  // 🛰️ DATA FETCHING
  const { data: gravitonData } = useSWR('/api/graviton/metrics', fetcher, { refreshInterval: 10000 });
  const { data: pizzaData } = useSWR('/api/pizza/analytics', fetcher, { refreshInterval: 10000 });

  // Simple time for the header
  const [time, setTime] = useState<Date | null>(null);

  useEffect(() => {
    setTime(new Date());
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  return (
    <div className="min-h-screen bg-[#0B0E17] text-white overflow-hidden relative font-sans selection:bg-[#00D4FF]/30">

      {/* 🌌 AMBIENT BACKGROUND */}
      <div className="fixed inset-0 pointer-events-none">
        <div className="absolute top-[-20%] left-[-10%] w-[70vw] h-[70vw] bg-[#00D4FF]/5 blur-[150px] rounded-full mix-blend-screen animate-pulse-slow" />
        <div className="absolute bottom-[-20%] right-[-10%] w-[70vw] h-[70vw] bg-[#7B61FF]/5 blur-[150px] rounded-full mix-blend-screen animate-pulse-slow delay-1000" />
        <div className="absolute top-[50%] left-[50%] -translate-x-1/2 -translate-y-1/2 w-[100vw] h-[100vh] bg-[url('/noise.png')] opacity-[0.03] mix-blend-overlay" />
      </div>

      <div className="relative z-10 flex flex-col min-h-screen">

        {/* 🏆 HEADER */}
        <header className="px-8 py-6 flex justify-between items-center border-b border-white/5 bg-[#0B0E17]/50 backdrop-blur-xl sticky top-0 z-50">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 rounded-lg bg-gradient-to-br from-[#00D4FF] to-[#0066FF] flex items-center justify-center shadow-[0_0_20px_rgba(0,212,255,0.3)]">
              <LayoutGrid className="text-white" size={20} />
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-wider uppercase text-white">Галя Балувана</h1>
              <p className="text-[10px] uppercase tracking-[0.2em] text-white/40 font-bold">Command Center • Level 1</p>
            </div>
          </div>

          <div className="text-right hidden md:block">
            <div className="text-lg font-mono font-bold text-[#00D4FF] drop-shadow-[0_0_8px_rgba(0,212,255,0.5)]">
              {time?.toLocaleTimeString('uk-UA')}
            </div>
            <div className="text-[10px] uppercase tracking-widest text-white/40">
              {time?.toLocaleDateString('uk-UA', { weekday: 'long', day: 'numeric', month: 'long' })}
            </div>
          </div>
        </header>

        {/* 🚀 MAIN CONTENT AREA */}
        <main className="flex-1 flex flex-col items-center justify-center px-4 lg:px-8 py-2">

          {/* Critical Alert */}
          {(gravitonData?.criticalSKU > 0 || (pizzaData?.kpi && Number(pizzaData.kpi.fillLevel) < 50)) && (
            <div className="w-full max-w-[1400px] mb-4 flex items-center justify-center gap-4">
              {gravitonData?.criticalSKU > 0 && (
                <CriticalCounter
                  count={gravitonData.criticalSKU}
                  label="критичних у Гравітоні"
                  onClick={() => window.location.href = '/graviton'}
                />
              )}
              {pizzaData?.kpi && Number(pizzaData.kpi.fillLevel) < 50 && (
                <CriticalCounter
                  count={1}
                  label="низький запас піци"
                  onClick={() => window.location.href = '/pizza'}
                />
              )}
            </div>
          )}

          <div className="w-full max-w-[1400px] grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3 lg:gap-4">

            {/* 🟦 CARD 1: GRAVITON */}
            <WorkshopCard
              href="/graviton"
              title="ЦЕХ Гравітон"
              subtitle="Виробництво заморозки"
              icon={BarChart2}
              color="#00D4FF"
              isHovered={hoveredCard === 'graviton'}
              onMouseEnter={() => setHoveredCard('graviton')}
              onMouseLeave={() => setHoveredCard(null)}
              stats={[
                { label: 'Всього до виробництва', value: gravitonData ? `${Math.round(gravitonData.shopLoad)} кг` : '— кг' },
                {
                  label: 'Критично',
                  value: gravitonData ? `${gravitonData.criticalSKU} SKU` : '— 🔥',
                  valueColor: (gravitonData?.criticalSKU > 0) ? '#FF4D4D' : undefined
                }
              ]}
              actionLabel="Управління замовленням"
            />

            {/* 🟧 CARD 2: PIZZA */}
            <WorkshopCard
              href="/pizza"
              title="ЦЕХ Піца"
              subtitle="Випічка та пакування"
              icon={ChefHat}
              color="#FFB800"
              isHovered={hoveredCard === 'pizza'}
              onMouseEnter={() => setHoveredCard('pizza')}
              onMouseLeave={() => setHoveredCard(null)}
              stats={[
                {
                  label: 'Факт залишок',
                  value: pizzaData?.kpi ? `${pizzaData.kpi.currentStock} шт.` : '— шт.',
                  valueColor: (Number(pizzaData?.kpi?.fillLevel) < 50) ? '#FF4D4D' : undefined
                },
                { label: 'Норма', value: pizzaData?.kpi ? `${pizzaData.kpi.totalTarget} шт.` : '— шт.' },
                {
                  label: 'Індекс заповненості',
                  value: pizzaData?.kpi ? `${pizzaData.kpi.fillLevel}%` : '— %',
                  valueColor: Number(pizzaData?.kpi?.fillLevel) < 50 ? '#FF4D4D' :
                    Number(pizzaData?.kpi?.fillLevel) < 80 ? '#FFA500' : undefined
                }
              ]}
              actionLabel="Розподіл та логістика"
            />

            {/* 🟣 CARD 3: KRAFT BAKERY */}
            <WorkshopCard
              href="#"
              title="Крафтова пекарня"
              subtitle="Випічка хліба та булок"
              icon={Zap}
              color="#A855F7"
              isHovered={hoveredCard === 'bakery'}
              onMouseEnter={() => setHoveredCard('bakery')}
              onMouseLeave={() => setHoveredCard(null)}
              isLocked={true}
              stats={[
                { label: 'План на зміну', value: '— шт.' },
                { label: 'Готовність', value: '— %' }
              ]}
              actionLabel="В розробці"
            />

            {/* 🟢 CARD 4: FLORIDA */}
            <WorkshopCard
              href="#"
              title="ЦЕХ Флорида"
              subtitle="Кондитерські вироби"
              icon={Activity}
              color="#10B981"
              isHovered={hoveredCard === 'florida'}
              onMouseEnter={() => setHoveredCard('florida')}
              onMouseLeave={() => setHoveredCard(null)}
              isLocked={true}
              stats={[
                { label: 'Замовлення', value: '—' },
                { label: 'Статус', value: 'Очікуємо' }
              ]}
              actionLabel="В розробці"
            />

            {/* 🟡 CARD 5: SADOVA */}
            <WorkshopCard
              href="#"
              title="ЦЕХ Садова"
              subtitle="Випічка та кулінарія"
              icon={Factory}
              color="#F59E0B"
              isHovered={hoveredCard === 'sadova'}
              onMouseEnter={() => setHoveredCard('sadova')}
              onMouseLeave={() => setHoveredCard(null)}
              isLocked={true}
              stats={[
                { label: 'План', value: '—' },
                { label: 'Статус', value: 'Очікуємо' }
              ]}
              actionLabel="В розробці"
            />

            {/* 🟣 CARD 6: ENTUZIASTIV */}
            <WorkshopCard
              href="#"
              title="ЦЕХ Ентузіастів"
              subtitle="Виробництво"
              icon={Store}
              color="#EC4899"
              isHovered={hoveredCard === 'entuziastiv'}
              onMouseEnter={() => setHoveredCard('entuziastiv')}
              onMouseLeave={() => setHoveredCard(null)}
              isLocked={true}
              stats={[
                { label: 'План', value: '—' },
                { label: 'Статус', value: 'Очікуємо' }
              ]}
              actionLabel="В розробці"
            />

            {/* 🔵 CARD 7: BULVAR */}
            <WorkshopCard
              href="#"
              title="ЦЕХ Бульвар"
              subtitle="Центральна кухня"
              icon={ShoppingBag}
              color="#6366F1"
              isHovered={hoveredCard === 'bulvar'}
              onMouseEnter={() => setHoveredCard('bulvar')}
              onMouseLeave={() => setHoveredCard(null)}
              isLocked={true}
              stats={[
                { label: 'План', value: '—' },
                { label: 'Статус', value: 'Очікуємо' }
              ]}
              actionLabel="В розробці"
            />

            {/* 🍬 CARD 8: CONFECTIONERY */}
            <WorkshopCard
              href="#"
              title="ЦЕХ Кондитерка"
              subtitle="Солодощі та десерти"
              icon={Zap}
              color="#8B5CF6"
              isHovered={hoveredCard === 'confectionery'}
              onMouseEnter={() => setHoveredCard('confectionery')}
              onMouseLeave={() => setHoveredCard(null)}
              isLocked={true}
              stats={[
                { label: 'План', value: '—' },
                { label: 'Статус', value: 'Очікуємо' }
              ]}
              actionLabel="В розробці"
            />

            {/* 🏛️ CARD 9: HEROIV MAIDANU */}
            <WorkshopCard
              href="#"
              title="ЦЕХ Героїв Майдану"
              subtitle="Виробництво"
              icon={Factory}
              color="#14B8A6"
              isHovered={hoveredCard === 'heroiv'}
              onMouseEnter={() => setHoveredCard('heroiv')}
              onMouseLeave={() => setHoveredCard(null)}
              isLocked={true}
              stats={[
                { label: 'План', value: '—' },
                { label: 'Статус', value: 'Очікуємо' }
              ]}
              actionLabel="В розробці"
            />

          </div>

        </main>

        <footer className="py-4 text-center text-white/20 text-[10px] uppercase tracking-widest font-mono pointer-events-none">
          System v2.0 • Antigravity Module
        </footer>
      </div>
    </div>
  );
}

// ✨ COMPONENT: Workshop Card
function WorkshopCard({
  href,
  title,
  subtitle,
  icon: Icon,
  color,
  isHovered,
  onMouseEnter,
  onMouseLeave,
  stats,
  actionLabel,
  isLocked = false
}: {
  href: string;
  title: string;
  subtitle: string;
  icon: any;
  color: string;
  isHovered: boolean;
  onMouseEnter: () => void;
  onMouseLeave: () => void;
  stats: { label: string; value: string; valueColor?: string }[];
  actionLabel: string;
  isLocked?: boolean;
}) {
  return (
    <Link
      href={isLocked ? '#' : href}
      className={cn(
        "group relative h-[210px] lg:h-[240px] flex flex-col rounded-3xl overflow-hidden transition-all duration-500 hover:scale-[1.02] active:scale-[0.98]",
        isLocked && "cursor-not-allowed opacity-80"
      )}
      onMouseEnter={onMouseEnter}
      onMouseLeave={onMouseLeave}
      style={{
        background: 'rgba(255, 255, 255, 0.02)',
        border: `1px solid ${isHovered ? color : 'rgba(255, 255, 255, 0.08)'}`,
        boxShadow: isHovered
          ? `0 0 60px -20px ${color}40, inset 0 0 20px -5px ${color}20`
          : '0 20px 40px -10px rgba(0,0,0,0.5)',
      }}
    >
      {/* 🔦 Dynamic Glow */}
      <div
        className="absolute inset-0 opacity-0 group-hover:opacity-100 transition-opacity duration-700"
        style={{
          background: `radial-gradient(800px circle at 50% 0%, ${color}15, transparent 60%)`
        }}
      />

      {/* 🖼️ Card Content */}
      <div className="relative z-10 flex-1 p-6 lg:p-8 flex flex-col justify-between">

        {/* Header */}
        <div className="flex justify-between items-start">
          <div>
            <div
              className="w-12 h-12 rounded-xl flex items-center justify-center mb-4 transition-transform duration-500 group-hover:scale-110 group-hover:rotate-3"
              style={{
                background: `${color}15`,
                boxShadow: `0 0 30px ${color}10`,
                border: `1px solid ${color}30`
              }}
            >
              <Icon size={24} style={{ color: color }} />
            </div>

            <h2 className="text-2xl lg:text-3xl font-bold text-white mb-1 leading-tight tracking-tight">
              {title}
            </h2>
            <p className="text-white/40 text-[10px] lg:text-xs font-medium uppercase tracking-widest">
              {subtitle}
            </p>
          </div>

          {isLocked ? (
            <div className="bg-white/5 border border-white/10 px-3 py-1 rounded-full backdrop-blur-md">
              <span className="text-[10px] font-bold text-white/40 uppercase tracking-tighter">🔒 Offline</span>
            </div>
          ) : (
            <div className="flex items-center gap-2 bg-white/5 border border-white/10 px-3 py-1.5 rounded-full backdrop-blur-md">
              <StatusDot status={stats.some(s => s.valueColor === '#FF4D4D') ? 'critical' : 'good'} pulse={stats.some(s => s.valueColor === '#FF4D4D')} />
              <span className="text-[10px] font-bold text-white/60 uppercase tracking-tighter">
                {stats.some(s => s.valueColor === '#FF4D4D') ? 'Увага' : 'Online'}
              </span>
            </div>
          )}
        </div>

        {/* Stats Grid */}
        <div className={cn(
          "grid gap-3 my-4",
          stats.length === 3 ? "grid-cols-3" : "grid-cols-2"
        )}>
          {stats.map((stat, i) => (
            <div key={i} className="bg-white/5 rounded-xl p-3 border border-white/5 group-hover:bg-white/10 group-hover:border-white/10 transition-colors">
              <div className="text-[7px] lg:text-[8px] text-white/40 uppercase tracking-widest font-bold mb-0.5 truncate">
                {stat.label}
              </div>
              <div
                className="text-sm lg:text-lg font-mono font-bold truncate transition-colors duration-300"
                style={{ color: stat.valueColor || '#FFF' }}
              >
                {stat.value}
              </div>
            </div>
          ))}
        </div>

        {/* Action Button */}
        <div
          className="flex items-center justify-between py-3 px-5 rounded-xl transition-all duration-300 transform group-hover:translate-x-2"
          style={{
            background: isHovered && !isLocked ? color : 'rgba(255, 255, 255, 0.05)',
            color: isHovered && !isLocked ? '#000' : '#FFF'
          }}
        >
          <span className="font-bold uppercase tracking-widest text-[10px]">
            {actionLabel}
          </span>
          <ArrowRight size={16} className={cn("transition-transform duration-300", isHovered && "translate-x-1")} />
        </div>

      </div>

      {/* 🏗️ IN DEVELOPMENT OVERLAY */}
      {isLocked && (
        <div className="absolute inset-0 z-20 flex items-center justify-center bg-[#0B0E17]/60 backdrop-blur-[2px] pointer-events-none group-hover:backdrop-blur-none transition-all duration-500">
          <div className="px-6 py-3 border-y-2 border-white/10 bg-white/5 flex flex-col items-center gap-1 -rotate-6 shadow-[0_0_50px_rgba(255,255,255,0.05)]">
            <span className="text-3xl lg:text-4xl font-black text-white/90 tracking-tighter uppercase text-center drop-shadow-2xl">
              В РОЗРОБЦІ
            </span>
            <div className="flex items-center gap-2">
              <Zap size={14} className="text-[#00D4FF] animate-pulse" />
              <span className="text-[10px] font-bold text-[#00D4FF] uppercase tracking-[0.3em]">System Level 2</span>
            </div>
          </div>
        </div>
      )}
    </Link>
  );
}

'use client';

import React from 'react';
import useSWR from 'swr';
import { DashboardLayout } from '@/components/layout';
import { transformPizzaData } from '@/lib/transformers';
import { ProductionOpsTable } from '@/components/production/ProductionOrderTable';
import { ChefHat } from 'lucide-react';

import { authedFetcher } from '@/lib/authed-fetcher';

const fetcher = authedFetcher;

export default function OrderFormPage() {
    // Reuse existing API to get full stats including stores and deficits
    const { data: allProductsData, error, isLoading, mutate } = useSWR<any[]>(
        '/api/pizza/orders',
        fetcher,
        { refreshInterval: 60000 }
    );

    const handleRefresh = React.useCallback(async () => {
        await mutate();
    }, [mutate]);

    const productQueue = React.useMemo(() => {
        if (!allProductsData) return [];
        return transformPizzaData(allProductsData);
    }, [allProductsData]);

    if (error) {
        return (
            <div className="flex items-center justify-center min-h-screen bg-[#0F1220] text-[#E74856] font-bold uppercase tracking-widest">
                Помилка завантаження даних
            </div>
        );
    }

    if (isLoading || !allProductsData) {
        return (
            <div className="flex items-center justify-center min-h-screen bg-[#0F1220]">
                <div className="flex flex-col items-center gap-4">
                    <ChefHat size={48} className="text-[#FFB800] animate-bounce" />
                    <span className="text-white/40 font-bold uppercase tracking-widest animate-pulse">
                        Завантаження...
                    </span>
                </div>
            </div>
        );
    }

    return (
        <DashboardLayout fullHeight={true}>
            <div className="h-full p-4 flex flex-col gap-4">
                <div className="flex items-center justify-between">
                    <h1 className="text-xl font-bold text-white uppercase tracking-wider">
                        📋 Формування замовлення
                    </h1>
                    <div className="text-xs text-white/40 font-mono">
                        {new Date().toLocaleDateString()}
                    </div>
                </div>

                <div className="flex-1 overflow-hidden">
                    <ProductionOpsTable data={productQueue} onRefresh={handleRefresh} />
                </div>
            </div>
        </DashboardLayout>
    );
}

'use client';

import React from 'react';
import useSWR from 'swr';
import { ProductionTabs } from '@/components/production/ProductionTabs';
import { DashboardLayout } from '@/components/layout';
import { transformPizzaData } from '@/lib/transformers';
import { ChefHat } from 'lucide-react';

import { authedFetcher } from '@/lib/authed-fetcher';

const fetcher = authedFetcher;

export default function PizzaDashboard() {
    const { data: allProductsData, error, isLoading, mutate } = useSWR<any[]>(
        '/api/pizza/orders',
        fetcher,
        { refreshInterval: 60000 }
    );

    const handleRefresh = React.useCallback(async () => {
        await mutate();
    }, [mutate]);

    const productQueue = React.useMemo(() => {
        if (!allProductsData) return [];
        return transformPizzaData(allProductsData);
    }, [allProductsData]);

    if (error) {
        return (
            <div className="flex items-center justify-center min-h-screen bg-[var(--background)] text-[#E74856] font-bold uppercase tracking-widest">
                Помилка завантаження даних
            </div>
        );
    }

    if (isLoading || !allProductsData) {
        return (
            <div className="flex items-center justify-center min-h-screen bg-[var(--background)]">
                <div className="flex flex-col items-center gap-4">
                    <ChefHat size={48} className="text-[#FFB800] animate-bounce" />
                    <span className="text-white/40 font-bold uppercase tracking-widest animate-pulse">
                        Завантаження піци...
                    </span>
                </div>
            </div>
        );
    }

    return (
        <DashboardLayout
            fullHeight={true}
        >
            <ProductionTabs data={productQueue} onRefresh={handleRefresh} showTabs={true} />
        </DashboardLayout>
    );
}

'use client';

import React, { useMemo, useEffect, useState } from 'react';
import useSWR from 'swr';
import { DashboardLayout } from '@/components/layout';
import { TaskCard } from '@/components/TaskCard';
import { ProductionTask, BI_Metrics, SupabaseDeficitRow, SKUCategory } from '@/types/bi';
import { transformDeficitData } from '@/lib/transformers';
import { ErrorBoundary } from '@/components/ErrorBoundary';
import { RotateCw, Globe } from 'lucide-react';
import { UI_TOKENS } from '@/lib/design-tokens';
import { useStore } from '@/context/StoreContext';

import { authedFetcher } from '@/lib/authed-fetcher';

const fetcher = authedFetcher;

const HeaderKPI = ({ label, value }: { label: string; value: string | number }) => (
    <div className="px-5 py-3 bg-[#141C27] rounded-[10px] min-w-[150px] border border-[#1F2630] flex flex-col justify-center">
        <span className="text-[11px] font-bold text-[#8B949E] uppercase tracking-widest mb-1">{label}</span>
        <span className="text-[14px] font-black text-[#E6EDF3]">{value}</span>
    </div>
);

const LegendItem = ({ color, label }: { color: string; label: string }) => (
    <div className="flex items-center gap-2 px-2">
        <div className="w-3 h-3 rounded-full shadow-[0_0_8px_rgba(0,0,0,0.5)]" style={{ backgroundColor: color }} />
        <span className="text-[12px] font-medium text-[#E6EDF3] tracking-tight">{label}</span>
    </div>
);

export default function ProductionPage() {
    const { currentCapacity } = useStore();
    const { data: deficitData, error: deficitError, mutate: mutateDeficit } = useSWR<SupabaseDeficitRow[]>(
        '/api/graviton/deficit',
        fetcher,
        { refreshInterval: 30000 }
    );

    const { data: metrics, error: metricsError, mutate: mutateMetrics } = useSWR<BI_Metrics>(
        '/api/graviton/metrics',
        fetcher,
        { refreshInterval: 30000 }
    );

    const [isRefreshing, setIsRefreshing] = React.useState(false);
    const [now, setNow] = useState(new Date());

    const tasks = useMemo((): ProductionTask[] => {
        if (!deficitData || !Array.isArray(deficitData)) return [];
        return transformDeficitData(deficitData);
    }, [deficitData]);

    useEffect(() => {
        const timer = setInterval(() => setNow(new Date()), 1000);
        return () => clearInterval(timer);
    }, []);

    const tasksByCategory = useMemo(() => {
        const grouped: Record<string, ProductionTask[]> = {};
        tasks.forEach(task => {
            if (!grouped[task.category]) grouped[task.category] = [];
            grouped[task.category].push(task);
        });
        return grouped;
    }, [tasks]);

    const formattedDate = now.toLocaleDateString('uk-UA', { weekday: 'long', day: 'numeric', month: 'long' });
    const formattedTime = now.toLocaleTimeString('uk-UA', { hour: '2-digit', minute: '2-digit' });

    const handleRefresh = async () => {
        setIsRefreshing(true);
        try {
            const response = await fetch('http://localhost:5678/webhook-test/operator', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ action: 'refresh_stock', timestamp: new Date().toISOString() })
            });

            if (response.ok) {
                await new Promise(resolve => setTimeout(resolve, 2000));
                await Promise.all([mutateDeficit(), mutateMetrics()]);
            }
        } catch (err) {
            console.error('Refresh error:', err);
        } finally {
            setIsRefreshing(false);
        }
    };

    const handleStatusChange = (taskId: string, status: ProductionTask['status']) => {
        console.log(`Task ${taskId} status changed to ${status}`);
    };

    if (deficitError || metricsError) {
        return <div className="p-10 text-red-500 font-bold">Помилка завантаження даних виробництва.</div>;
    }

    if (!metrics || !deficitData) {
        return <div className="p-10 text-slate-500 animate-pulse uppercase font-bold">Синхронізація двигуна виробництва...</div>;
    }

    return (
        <DashboardLayout currentWeight={metrics.shopLoad} maxWeight={currentCapacity}>
            <div className="max-w-[1200px] mx-auto min-h-[calc(100vh-160px)]">
                {/* Outer Panel like SVG */}
                <div className="bg-[#0B0F14] rounded-[16px] border border-[#1F2630] p-6 lg:p-10 shadow-2xl h-full flex flex-col">

                    {/* Header Shell according to SVG */}
                    <div className="bg-[#111823] rounded-xl border border-[#202938] px-8 py-5 mb-6 flex flex-col md:flex-row justify-between items-center gap-6 shadow-xl relative overflow-hidden">
                        {/* Interactive Background Glow */}
                        <div className="absolute top-0 left-0 w-full h-[1px] bg-gradient-to-r from-transparent via-[#58A6FF]/20 to-transparent" />

                        <div className="flex flex-col gap-1">
                            <div className="flex items-center gap-3">
                                <h1 className="text-[18px] font-black text-[#E6EDF3] tracking-tighter uppercase whitespace-nowrap">
                                    Галя Балувана <span className="text-[#8B949E] px-1">•</span> <span className="text-[#58A6FF]">Центр управління</span>
                                </h1>
                                <div className="bg-[#1F6FEB] px-2 py-0.5 rounded-full flex items-center gap-1 shadow-[0_0_15px_rgba(31,111,235,0.3)]">
                                    <div className="w-1.5 h-1.5 rounded-full bg-white animate-pulse" />
                                    <span className="text-[10px] font-black text-white uppercase tracking-widest">LIVE</span>
                                </div>
                            </div>
                            <div className="flex items-center gap-2 text-[11px] font-bold text-[#8B949E] uppercase tracking-[0.1em]">
                                <span>{formattedDate}</span>
                                <span className="text-[#3FB950]">•</span>
                                <span className="text-[#E6EDF3]">{formattedTime}</span>
                                <span className="text-[#3FB950]">•</span>
                                <span className="text-[#3FB950]">ОНЛАЙН</span>
                            </div>
                        </div>

                        <div className="flex flex-wrap gap-3">
                            <HeaderKPI label="Дефіцит кг" value="1.2k кг" />
                            <HeaderKPI label="Критичні SKU" value={metrics.criticalSKU} />
                            <HeaderKPI label="Завантаження" value={`${Math.round(metrics.shopLoad / ((currentCapacity || 450) / 100))}%`} />
                            <HeaderKPI label="Зміна / SLA" value="98%" />
                        </div>
                    </div>

                    {/* Legend Bar matching SVG */}
                    <div className="bg-[#111823] rounded-xl border border-[#1F2630] px-6 py-4 mb-8 flex items-center gap-8 shadow-sm">
                        <span className="text-[11px] font-black text-[#8B949E] uppercase tracking-[0.15em]">Легенда:</span>
                        <div className="flex items-center gap-8">
                            <LegendItem color={UI_TOKENS.colors.priority.critical} label="Critical" />
                            <LegendItem color={UI_TOKENS.colors.priority.high} label="High" />
                            <LegendItem color={UI_TOKENS.colors.priority.reserve} label="Reserve" />
                            <LegendItem color={UI_TOKENS.colors.priority.normal} label="Normal" />
                        </div>
                    </div>

                    {/* Main Content Columns matching SVG */}
                    <div className="flex-1 grid grid-cols-12 gap-8">
                        {/* Column 1: Queue */}
                        <div className="col-span-12 lg:col-span-4 flex flex-col">
                            <div className="flex items-center gap-3 mb-6 px-2">
                                <h2 className="text-[14px] font-black text-[#E6EDF3] tracking-tight">Production Queue</h2>
                                <div className="flex-1 h-px bg-gradient-to-r from-[#1F2630] to-transparent" />
                            </div>
                            <div className="flex-1 overflow-y-auto custom-scrollbar space-y-6 pr-2">
                                <ErrorBoundary>
                                    {Object.entries(tasksByCategory).map(([category, catTasks]) => (
                                        <div key={category} className="space-y-3">
                                            <h3 className="text-[10px] font-black text-[#8B949E] uppercase tracking-[0.2em] flex items-center gap-2">
                                                <div className="w-1 h-3 bg-[#58A6FF] rounded-full" />
                                                {category}
                                            </h3>
                                            <div className="space-y-4">
                                                {catTasks.map(task => (
                                                    <TaskCard key={task.id} task={task} onStatusChange={handleStatusChange} />
                                                ))}
                                            </div>
                                        </div>
                                    ))}
                                </ErrorBoundary>
                            </div>
                        </div>

                        {/* Column 2: Analytics */}
                        <div className="col-span-12 lg:col-span-4 flex flex-col border-x border-[#1F2630] border-dashed px-4">
                            <div className="flex items-center gap-3 mb-6 px-2">
                                <h2 className="text-[14px] font-black text-[#E6EDF3] tracking-tight">Network Analytics</h2>
                                <div className="flex-1 h-px bg-gradient-to-r from-[#1F2630] to-transparent" />
                            </div>
                            <div className="space-y-6">
                                <div className="bg-[#0F1622] rounded-xl border border-[#1E2A3A] p-6 h-[170px] shadow-sm">
                                    <h3 className="text-[12px] font-bold text-[#8B949E] uppercase tracking-widest mb-4">Top deficit by category</h3>
                                    <div className="h-full opacity-20 border-t border-dashed border-[#1E2A3A] mt-8" />
                                </div>
                                <div className="bg-[#0F1622] rounded-xl border border-[#1E2A3A] p-6 h-[190px] shadow-sm">
                                    <h3 className="text-[12px] font-bold text-[#8B949E] uppercase tracking-widest mb-4">Store risk heatmap</h3>
                                    <div className="grid grid-cols-6 gap-2 mt-4">
                                        {Array.from({ length: 18 }).map((_, i) => (
