                                <div className="bg-[#0F1622] rounded-xl border border-[#1E2A3A] p-6 flex-1 min-h-[230px] shadow-sm">
                                    <h3 className="text-[12px] font-bold text-[#8B949E] uppercase tracking-widest mb-6">Action panel</h3>
