                                                                </span>
                                                            </td>
                                                        </tr>
                                                    );
                                                })}
                                            </tbody>
                                        </table>
                                    </div>
                                </div>
                            </div>
                        )}

                        {/* CATALOG TAB (SKU Drill-down) */}
                        {activeTab === 'catalog' && (
                            <div className="space-y-6 flex-1 h-full animate-in fade-in slide-in-from-bottom-4 duration-500 flex flex-col">
