// eslint-disable-next-line @typescript-eslint/no-unused-vars
import { BackToHome } from '@/components/BackToHome';
import { DistributionModal } from './DistributionModal';
import { ProductionDetailModal } from './ProductionDetailModal';
import { ProductDetailDrawer } from './production/ProductDetailDrawer';
import { StoreDetailDrawer } from './production/StoreDetailDrawer';

// 🟢 PIZZA LOGIC CONSTANTS
// eslint-disable-next-line @typescript-eslint/no-unused-vars
const SAFETY_BUFFER = 2; // Days

interface Props {
    data: ProductionTask[];
    onRefresh: () => void;
    initialViewMode?: 'products' | 'stores';
}

// Internal Component for Distribution Logic per Accordion Item
// eslint-disable-next-line @typescript-eslint/no-unused-vars
const ProductAccordionItem = ({
    product,
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    planningDays,
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    isExpanded,
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    onToggle
}: {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    product: any,
    planningDays: number,
    isExpanded: boolean,
    onToggle: () => void
}) => {
    const [totalBaked, setTotalBaked] = useState<number>(0);
    const [distributionPlan, setDistributionPlan] = useState<Record<number, number>>({});
    const [isDistributing, setIsDistributing] = useState(false);

    // Distribution Algorithm
    const handleDistribute = (e: React.MouseEvent) => {
        e.stopPropagation(); // Prevent accordion toggle
        setIsDistributing(true);

        setTimeout(() => { // Small fake delay for UX
            let remaining = totalBaked;
            const newPlan: Record<number, number> = {};

            const add = (storeId: number, amount: number) => {
                newPlan[storeId] = (newPlan[storeId] || 0) + amount;
                remaining -= amount;
            };

            const stores = product.stores;

            // STEP 1: CRITICAL (Stock < Min Stock)
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            const totalCriticalNeed = stores.reduce((sum: number, s: any) => sum + s.computed.urgentDeficit, 0);

            if (totalCriticalNeed > 0) {
                if (remaining >= totalCriticalNeed) {
                    // eslint-disable-next-line @typescript-eslint/no-explicit-any
                    stores.forEach((s: any) => { if (s.computed.urgentDeficit > 0) add(s.storeId, s.computed.urgentDeficit); });
                } else {
                    // eslint-disable-next-line @typescript-eslint/no-explicit-any
                    stores.forEach((s: any) => {
                        if (s.computed.urgentDeficit > 0) {
                            const share = Math.floor((s.computed.urgentDeficit / totalCriticalNeed) * remaining);
                            if (share > 0) add(s.storeId, share);
                        }
                    });
                }
            }

            // STEP 2: REMAINING (Proportional to Avg Sales)
            if (remaining > 0) {
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                const totalAvg = stores.reduce((sum: number, s: any) => sum + s.computed.avg, 0);
                if (totalAvg > 0) {
                    const step2Pool = remaining;
                    // eslint-disable-next-line @typescript-eslint/no-explicit-any
                    stores.forEach((s: any) => {
                        const rawShare = (s.computed.avg / totalAvg) * step2Pool;
                        add(s.storeId, Math.floor(rawShare));
                    });
                }
            }

            // STEP 3: ROUNDING
            while (remaining > 0) {
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                const sorted = [...stores].sort((a: any, b: any) => a.computed.stock - b.computed.stock);
                for (const s of sorted) {
                    if (remaining <= 0) break;
                    add(s.storeId, 1);
                }
                if (remaining > 0) break;
            }

            setDistributionPlan(newPlan);
            setIsDistributing(false);
        }, 100);
    };

    const totalDistributed = Object.values(distributionPlan).reduce((a, b) => a + b, 0);
    // eslint-disable-next-line @typescript-eslint/no-unused-vars, @typescript-eslint/no-explicit-any
    const criticalStoresCount = product.stores.filter((s: any) => s.computed.isUrgent).length;

    return (
        <div className="border-t border-slate-100 p-2">
            {/* STORES GRID */}
            <div className="grid grid-cols-3 md:grid-cols-4 xl:grid-cols-6 gap-2 mb-3">
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                {[...product.stores].sort((a: any, b: any) => b.computed.avg - a.computed.avg).map((store: any) => {

                    const isLowStock = store.computed.stock < store.computed.minStock;
                    const planVal = distributionPlan[store.storeId] || 0;

                    // SOFT COLORS
                    const cardBg = isLowStock
                        ? "bg-red-50/50 border-red-100"
                        : "bg-emerald-50/50 border-emerald-100";

                    return (
                        <div
                            key={`${product.productCode}-${store.storeName}`}
                            className={cn(
                                "rounded-lg p-2 border flex flex-col gap-1 transition-colors",
                                cardBg
                            )}
                        >
                            {/* Store Name - Compact */}
                            <div className="text-xs font-bold uppercase tracking-wide truncate saas-text-primary text-center" title={store.storeName}>
                                {store.storeName.replace('Магазин ', '').replace('"', '').replace('"', '')}
                            </div>

                            {/* Metrics Row - Compact */}
                            <div className="grid grid-cols-3 gap-1 text-[10px] font-mono leading-none mt-0.5">
                                <div className="flex flex-col gap-0.5">
                                    <span className="text-[9px] saas-text-secondary uppercase font-bold">Факт</span>
                                    <span className={cn("font-bold text-lg", isLowStock ? "text-[#E74856]" : "text-emerald-500")}>
                                        {store.computed.stock.toFixed(0)}
                                    </span>
                                </div>
                                <div className="flex flex-col gap-0.5 text-center">
                                    <span className="text-[9px] saas-text-secondary uppercase font-bold">Мін</span>
                                    <span className="font-bold text-lg text-[#2b80ff]">{store.computed.minStock.toFixed(0)}</span>
                                </div>
                                <div className="flex flex-col gap-0.5 text-right">
                                    <span className="text-[9px] saas-text-secondary uppercase font-bold">Сер</span>
                                    <span className="font-bold text-lg text-amber-500">{store.computed.avg.toFixed(1)}</span>
                                </div>
                            </div>

                            {/* Input Field - Reduced */}
                            <div className="pt-1.5 border-t border-slate-100 mt-0.5 flex items-center justify-between">
                                <span className="text-[9px] text-amber-500 font-bold uppercase">План</span>
                                <input
                                    type="number"
                                    value={planVal || ''}
                                    onChange={(e) => {
                                        const val = Number(e.target.value);
                                        setDistributionPlan(prev => ({ ...prev, [store.storeId]: val }));
                                    }}
                                    onClick={(e) => e.stopPropagation()}
                                    className={cn(
                                        "w-14 bg-white border border-slate-200 rounded h-6 text-center font-mono font-bold text-base focus:outline-none focus:border-amber-400",
                                        planVal > 0 ? "text-amber-500 shadow-sm" : "saas-text-secondary"
                                    )}
                                    placeholder="-"
                                />
                            </div>
                        </div>
                    );
                })}
            </div>

            {/* CONTROLS */}
            <div className="p-3 bg-slate-50 rounded-lg border border-slate-200 flex items-center gap-4">
                <div className="flex-1 max-w-xs">
                    <label className="text-[10px] saas-text-secondary uppercase font-bold tracking-widest block mb-1">
                        Скільки випечено (шт)
                    </label>
                    <input
                        type="number"
                        value={totalBaked || ''}
                        onChange={(e) => setTotalBaked(Number(e.target.value))}
                        onClick={(e) => e.stopPropagation()}
                        className="w-full bg-white border border-slate-200 rounded-lg h-10 px-3 font-mono saas-text-primary text-xl font-bold focus:outline-none focus:border-amber-400 focus:ring-1 focus:ring-amber-400 shadow-sm"
                        placeholder="0"
                    />
                </div>

                <button
                    onClick={handleDistribute}
                    disabled={!totalBaked || isDistributing}
                    className="h-10 px-6 bg-amber-400 hover:bg-amber-500 text-white shadow font-bold uppercase text-xs tracking-wider rounded-lg transition-all disabled:opacity-50 mt-4 flex items-center gap-2"
                >
                    <RotateCcw size={16} className={isDistributing ? "animate-spin" : ""} />
                    Розподілити
                </button>

                <div className="ml-auto mt-4 text-right">
                    <div className="text-[10px] saas-text-secondary uppercase tracking-widest font-bold">Нерозподілено</div>
                    <div className={cn("font-mono font-bold text-xl", (totalBaked - totalDistributed) < 0 ? "text-red-500" : "saas-text-primary")}>
                        {(totalBaked - totalDistributed).toFixed(0)}
                    </div>
                </div>
            </div>
        </div>
    );
};

export const PizzaPowerMatrix = ({ data, onRefresh, initialViewMode = 'products' }: Props) => {
    // STATE
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    const [planningDays, setPlanningDays] = useState<number>(3);
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    const [isRefreshing, setIsRefreshing] = useState(false);
    const [viewMode, setViewMode] = useState<'products' | 'stores'>(initialViewMode);
    const [selectedDrawerProductCode, setSelectedDrawerProductCode] = useState<number | null>(null);
    const [selectedDrawerStoreId, setSelectedDrawerStoreId] = useState<number | null>(null);
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    const [isUpdatingStock, setIsUpdatingStock] = useState(false);

    const [showDistModal, setShowDistModal] = useState(false);
    const [showProductionModal, setShowProductionModal] = useState(false);

    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    const handleRefresh = async () => {
        setIsRefreshing(true);
        await onRefresh();
        setTimeout(() => setIsRefreshing(false), 500);
    };

    // 🏭 PRODUCTION SUMMARY
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    const { data: productionSummary } = useSWR('/api/pizza/summary', (url) => fetch(url, { credentials: 'include' }).then(r => r.json()), { refreshInterval: 30000 });

    // 🔥 WEBHOOK: Update stock from n8n
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    const handleUpdateStock = async () => {
        setIsUpdatingStock(true);
        try {
            const response = await fetch('/api/pizza/update-stock', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ action: 'update_stock', timestamp: new Date().toISOString() })
            });

            if (response.ok) {
                // Refresh data after stock update
                await onRefresh();
            } else {
                console.error('Stock update failed:', response.status);
            }
        } catch (error) {
            console.error('Stock update error:', error);
        } finally {
            setIsUpdatingStock(false);
        }
    };


    const handleCardClick = (code: number) => {
        setSelectedDrawerProductCode(code);
    };

    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    const expandOne = (code: number) => {
        setSelectedDrawerProductCode(code);
    };

    // 1. CALCULATE PRODUCT LEVEL AGGREGATES
    const products = useMemo(() => {
        return data.map(product => {
            let totalAvg = 0;
            let totalStock = 0;
            let totalRecommended = 0;
            let totalUrgentDeficit = 0;
            let totalMinStock = 0;

            const storesWithStats = product.stores.map(store => {
                const avg = (Number(store.avgSales) || 0); // No Multiplier x1000
                const stock = Number(store.currentStock) || 0;

                // Formulas per store
                const minStock = Number(store.minStock) || 0;

                const urgent = Math.max(0, minStock - stock);

                const target = Math.ceil((avg * planningDays) + minStock);
                const recommended = Math.max(0, target - stock);

                totalAvg += avg;
                totalStock += stock;
                totalMinStock += minStock;
                totalRecommended += recommended;
                totalUrgentDeficit += urgent;

                return {
                    ...store,
                    computed: {
                        avg,
                        stock,
                        minStock,
                        recommended,
                        urgentDeficit: urgent,
                        isUrgent: urgent > 0
                    }
                };
            });

            return {
                ...product,
                stores: storesWithStats.sort((a, b) => b.computed.urgentDeficit - a.computed.urgentDeficit),
                computed: {
                    totalAvg,
                    totalStock,
                    totalMinStock,
                    totalRecommended,
                    totalUrgentDeficit
                }
            };
        }).sort((a, b) => {
            if (b.computed.totalUrgentDeficit !== a.computed.totalUrgentDeficit) {
                return b.computed.totalUrgentDeficit - a.computed.totalUrgentDeficit;
            }
            return b.name.localeCompare(a.name);
        });

    }, [data, planningDays]);

    // 1.5 GROUP BY STORES (inverted view)
    const storesGrouped = useMemo(() => {
        const storeMap = new Map<string, {
            storeName: string;
            storeId: number;
            products: Array<{
                productName: string;
                productCode: number;
                stock: number;
                avg: number;
                minStock: number;
                recommended: number;
                urgentDeficit: number;
                isUrgent: boolean;
            }>;
            totalStock: number;
            totalMinStock: number;
            totalUrgentDeficit: number;
            criticalProducts: number;
            totalAvgSales: number;
        }>();

        products.forEach(product => {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            product.stores.forEach((store: any) => {
                const storeName = store.storeName || 'Unknown';

                if (!storeMap.has(storeName)) {
                    storeMap.set(storeName, {
                        storeName,
                        storeId: store.storeId,
                        products: [],
                        totalStock: 0,
                        totalMinStock: 0,
                        totalUrgentDeficit: 0,
                        criticalProducts: 0,
                        totalAvgSales: 0
                    });
                }

                const entry = storeMap.get(storeName)!;
                entry.products.push({
                    productName: product.name,
                    productCode: product.productCode,
                    stock: store.computed.stock,
                    avg: store.computed.avg,
                    minStock: store.computed.minStock,
                    recommended: store.computed.recommended,
                    urgentDeficit: store.computed.urgentDeficit,
                    isUrgent: store.computed.isUrgent
                });
                entry.totalStock += store.computed.stock;
                entry.totalMinStock += store.computed.minStock;
                entry.totalUrgentDeficit += store.computed.urgentDeficit;
                if (store.computed.isUrgent) entry.criticalProducts++;
                entry.totalAvgSales += store.computed.avg;
            });
        });

        return Array.from(storeMap.values()).sort((a, b) => b.totalAvgSales - a.totalAvgSales);
    }, [products]);

    return (
        <div className="flex flex-col h-full w-full font-sans text-text-primary bg-bg-primary min-h-screen">

            {/* HEADER TOGGLE */}
            <div className="px-6 py-4 flex items-center justify-start border-b border-white/5 z-10 sticky top-0 bg-[#0A1931]/80 backdrop-blur-md transition-colors duration-300 mt-2">
                <div className="flex items-center gap-2 p-1 bg-[#112240]/60 rounded-xl border border-[#1A3D63]">
                    <button
                        onClick={() => setViewMode('products')}
                        className={cn(
                            "px-4 py-2 rounded-lg text-sm font-medium transition-all focus:outline-none uppercase font-[family-name:var(--font-chakra)]",
                            viewMode === 'products'
                                ? "bg-[#00E0FF]/20 text-[#00E0FF] shadow-[0_0_15px_rgba(0,224,255,0.15)] border border-[#00E0FF]/30"
                                : "text-slate-400 hover:text-white hover:bg-white/5 border border-transparent"
                        )}
                    >
                        Products
                    </button>
                    <button
                        onClick={() => setViewMode('stores')}
                        className={cn(
                            "px-4 py-2 rounded-lg text-sm font-medium transition-all focus:outline-none uppercase font-[family-name:var(--font-chakra)]",
                            viewMode === 'stores'
                                ? "bg-[#00E0FF]/20 text-[#00E0FF] shadow-[0_0_15px_rgba(0,224,255,0.15)] border border-[#00E0FF]/30"
                                : "text-slate-400 hover:text-white hover:bg-white/5 border border-transparent"
                        )}
                    >
                        Locations
                    </button>
                </div>
            </div>

            {/* 🔥 CARD GRID LAYOUT */}
            <main className="flex-1 overflow-y-auto custom-scrollbar p-6">
                {viewMode === 'products' ? (
                    /* PRODUCTS VIEW */
                    <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 2xl:grid-cols-6 gap-3 pb-20 mt-4">
                        {products.map(product => {
                            // eslint-disable-next-line @typescript-eslint/no-explicit-any
                            const criticalStores = product.stores.filter((s: any) => s.computed.isUrgent).length;
                            const hasIssues = criticalStores > 0;
                            const isOutOfStock = product.computed.totalStock === 0 && product.computed.totalRecommended > 0;

                            const dotColorClass = hasIssues ? "bg-status-critical shadow-[0_0_8px_rgba(244,63,94,0.6)]" : "bg-status-success shadow-[0_0_8px_rgba(16,185,129,0.4)]";
                            const actualColorClass = hasIssues ? "text-status-critical" : "text-white";
                            const progressColorClass = hasIssues ? "bg-status-critical shadow-[0_0_10px_rgba(244,63,94,0.4)]" : "bg-status-success shadow-[0_0_10px_rgba(16,185,129,0.3)]";
                            const fillPercent = Math.min(100, (product.computed.totalStock / (Math.max(1, product.computed.totalMinStock) * 1.5)) * 100);

                            return (
                                <div
                                    key={product.id}
                                    id={`product-${product.productCode}`}
                                    onClick={() => handleCardClick(product.productCode)}
                                    className="glass-panel p-4 rounded-xl transition-all flex flex-col gap-2 group hover:shadow-[0_0_20px_rgba(0,224,255,0.15)] hover:border-[#00E0FF]/30 cursor-pointer min-h-[120px] bg-[#131B2C] relative overflow-hidden"
                                >
                                    <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-b from-transparent via-[#00E0FF]/50 to-transparent opacity-0 group-hover:opacity-100 animate-scan pointer-events-none"></div>
                                    <div className="flex justify-between items-start relative z-10">
                                        <h3 className="text-sm font-bold text-white tracking-tight group-hover:text-[#00E0FF] transition-colors leading-tight line-clamp-2 font-[family-name:var(--font-chakra)] uppercase">
                                            {product.name}
                                        </h3>
                                        <div className={`w-2 h-2 rounded-full ${dotColorClass} flex-shrink-0 mt-1`}></div>
                                    </div>

                                    {isOutOfStock ? (
                                        <div className="flex-1 flex items-center justify-center italic text-[10px] text-status-critical/80 font-medium font-[family-name:var(--font-jetbrains)] uppercase tracking-[0.2em] text-center">
                                            Out of stock / Deficit
                                        </div>
                                    ) : (
                                        <>
                                            <div className="grid grid-cols-2 gap-2 my-1 relative z-10">
                                                <div className="flex flex-col">
                                                    <span className="text-[9px] uppercase font-bold text-slate-500 mb-0 font-[family-name:var(--font-jetbrains)] tracking-widest">Act</span>
                                                    <span className={`text-2xl font-bold font-[family-name:var(--font-jetbrains)] ${actualColorClass} leading-none`}>
                                                        {product.computed.totalStock.toFixed(0)}
                                                    </span>
                                                </div>
                                                <div className="flex flex-col items-end">
                                                    <span className="text-[9px] uppercase font-bold text-slate-500 mb-0 font-[family-name:var(--font-jetbrains)] tracking-widest">Tgt</span>
                                                    <span className="text-2xl font-bold text-slate-300 font-[family-name:var(--font-jetbrains)] leading-none">
                                                        {product.computed.totalRecommended.toFixed(0)}
                                                    </span>
                                                </div>
                                            </div>

                                            <div className="space-y-2 pt-2 border-t border-white/5 mt-auto relative z-10">
                                                <div className="flex justify-between items-center text-xs">
                                                    <span className="text-slate-400 font-[family-name:var(--font-jetbrains)] uppercase text-[9px] tracking-widest">Min. Stock</span>
                                                    <span className="font-medium text-slate-200 bg-white/5 px-1.5 py-0.5 rounded font-[family-name:var(--font-jetbrains)] text-[10px]">
                                                        {product.computed.totalMinStock.toFixed(0)}
                                                    </span>
                                                </div>
                                                <div className="relative pt-0.5">
                                                    <div className="h-1.5 w-full bg-slate-800 rounded-full overflow-hidden border border-white/5">
                                                        <div
                                                            className={`h-full rounded-full transition-all duration-500 ${progressColorClass}`}
                                                            style={{ width: `${fillPercent}%` }}
                                                        />
                                                    </div>
                                                </div>
                                            </div>
                                        </>
                                    )}
                                </div>
                            );
                        })}

                        <div className="glass-panel bg-[#131B2C]/40 p-4 rounded-xl flex flex-col justify-center items-center gap-2 border-dashed border-2 border-white/10 hover:border-[#00E0FF]/30 hover:shadow-[0_0_15px_rgba(0,224,255,0.1)] transition-all cursor-pointer group min-h-[120px]">
                            <div className="w-10 h-10 rounded-full bg-white/5 flex items-center justify-center group-hover:bg-[#00E0FF]/20 transition-colors">
                                <span className="text-slate-400 group-hover:text-[#00E0FF] text-xl font-light">+</span>
                            </div>
                            <span className="text-xs font-medium text-slate-400 group-hover:text-white mt-1 font-[family-name:var(--font-chakra)] uppercase tracking-wider text-center">Add Product</span>
                        </div>
                    </div>
                ) : (
                    /* STORES VIEW */
                    <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-6 gap-3 pb-20">
                        {storesGrouped.map(store => {
                            const hasIssues = store.criticalProducts > 0;
                            const fillPercent = store.totalMinStock > 0
                                ? (store.totalStock / store.totalMinStock) * 100
                                : 100;

                            return (
                                <div
                                    key={store.storeName}
                                    id={`store-${store.storeId}`}
                                    onClick={() => setSelectedDrawerStoreId(store.storeId)}
                                    className="glass-panel rounded-2xl transition-all duration-300 overflow-hidden group hover:shadow-[0_0_20px_rgba(0,224,255,0.15)] hover:border-[#00E0FF]/30 bg-[#131B2C] cursor-pointer"
                                >
                                    {/* STORE CARD HEADER */}
                                    <div
                                        className={cn(
                                            "p-4 transition-colors relative",
                                            "hover:bg-white/[0.05]",
                                            hasIssues && "bg-status-critical/[0.05]"
                                        )}
                                    >
                                        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-b from-transparent via-[#00E0FF]/50 to-transparent opacity-0 group-hover:opacity-100 animate-scan pointer-events-none"></div>
                                        <div className="flex items-center justify-between mb-2 relative z-10">
                                            <h3 className="text-base font-semibold text-white tracking-widest leading-tight truncate pr-2 uppercase font-[family-name:var(--font-chakra)] group-hover:text-[#00E0FF] transition-colors">
                                                {store.storeName.replace('Магазин ', '').replace(/"/g, '')}
                                            </h3>
                                        </div>

                                        <div className="grid grid-cols-3 gap-2 relative z-10">
                                            <div className="bg-white/5 rounded-xl p-2 text-center">
                                                <div className="text-[9px] text-slate-400 uppercase tracking-widest mb-0.5 font-[family-name:var(--font-jetbrains)] font-bold">Stock</div>
                                                <div className={cn(
                                                    "text-xl font-bold font-[family-name:var(--font-jetbrains)]",
                                                    hasIssues ? "text-status-critical drop-shadow-[0_0_8px_rgba(244,63,94,0.5)]" : "text-status-success drop-shadow-[0_0_8px_rgba(16,185,129,0.3)]"
                                                )}>
                                                    {store.totalStock.toFixed(0)}
                                                </div>
                                            </div>
                                            <div className={cn(
                                                "rounded-xl p-2 text-center border",
                                                store.criticalProducts > 0 ? "bg-status-critical/10 border-status-critical/20" : "bg-status-success/5 border-status-success/20"
                                            )}>
                                                <div className="text-[9px] text-slate-400 uppercase tracking-widest mb-0.5 font-[family-name:var(--font-jetbrains)] font-bold">Critical</div>
                                                <div className={cn(
                                                    "text-xl font-bold font-[family-name:var(--font-jetbrains)]",
                                                    store.criticalProducts > 0 ? "text-status-critical drop-shadow-[0_0_8px_rgba(244,63,94,0.5)]" : "text-status-success drop-shadow-[0_0_8px_rgba(16,185,129,0.3)]"
                                                )}>
                                                    {store.criticalProducts}
                                                </div>
                                            </div>

                                            {/* AVG SALES METRIC */}
                                            <div className="bg-[#00E0FF]/10 rounded-xl p-2 text-center border border-[#00E0FF]/20 flex flex-col justify-center">
                                                <div className="flex items-center justify-center gap-1 text-[8px] text-[#00E0FF] uppercase tracking-widest font-[family-name:var(--font-jetbrains)] font-bold mb-0.5 whitespace-nowrap">
                                                    <TrendingUp size={10} />
                                                    <span>Sales/Day</span>
                                                </div>
                                                <div className="text-xl font-bold text-[#00E0FF] leading-none drop-shadow-[0_0_8px_rgba(0,224,255,0.4)] font-[family-name:var(--font-jetbrains)]">
                                                    {store.totalAvgSales.toFixed(0)}
                                                </div>
                                            </div>
                                        </div>

                                        <div className="mt-3 relative z-10">
                                            <div className="h-1.5 bg-slate-800 rounded-full overflow-hidden border border-white/5">
                                                <div
                                                    className={cn(
                                                        "h-full rounded-full transition-all",
                                                        fillPercent >= 100 ? "bg-status-success shadow-[0_0_10px_rgba(16,185,129,0.4)]" :
                                                            fillPercent < 50 ? "bg-status-critical shadow-[0_0_10px_rgba(244,63,94,0.5)]" : "bg-status-warning shadow-[0_0_10px_rgba(251,191,36,0.5)]"
                                                    )}
                                                    style={{ width: `${Math.min(100, fillPercent)}%` }}
                                                />
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                )}
            </main>

            {/* DISTRIBUTION MODAL */}
            <DistributionModal
                isOpen={showDistModal}
                onClose={() => setShowDistModal(false)}
                products={data}
            />

            {/* PRODUCTION MODAL */}
            <ProductionDetailModal
                isOpen={showProductionModal}
                onClose={() => setShowProductionModal(false)}
            />

            {/* PRODUCT DETAIL SIDE DRAWER */}
            <ProductDetailDrawer
                isOpen={selectedDrawerProductCode !== null}
                onClose={() => setSelectedDrawerProductCode(null)}
                product={products.find(p => p.productCode === selectedDrawerProductCode)}
            />

            {/* STORE DETAIL DRAWER */}
            <StoreDetailDrawer
                isOpen={selectedDrawerStoreId !== null}
                onClose={() => setSelectedDrawerStoreId(null)}
                store={storesGrouped.find(s => s.storeId === selectedDrawerStoreId)}
            />
        </div>
    );
};

'use client';

import React, { useState, useMemo } from 'react';
import { Send, Download, Copy, Check } from 'lucide-react';
import { OrderItem, SharePlatform } from '@/types/order';
import { formatOrderMessage } from '@/lib/messageFormatter';
import { groupItemsByCategory, generateExcel, prepareWorkbook } from '@/lib/order-export';
import { auditLog } from '@/lib/logger';
import { Modal, ModalHeader, ModalBody, ModalFooter, ModalButton } from '@/components/ui/Modal';

interface ShareOptionsModalProps {
    isOpen: boolean;
    items: OrderItem[];
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    orderData: any;
    onClose: () => void;
    onShare: (platform: SharePlatform['id']) => void;
}

// eslint-disable-next-line @typescript-eslint/no-unused-vars
export const ShareOptionsModal = ({ isOpen, items, orderData, onClose, onShare }: ShareOptionsModalProps) => {
    const [copied, setCopied] = useState(false);

    const handleDownloadExcel = async () => {
        // Log export action
        await auditLog('EXPORT_EXCEL', 'ShareOptionsModal', {
            date: orderData.date,
            totalKg: orderData.totalKg,
            itemCount: items.length
        });

        const fileName = await generateExcel(orderData);
        alert(`Файл збережено: ${fileName}`);
    };

    const handleShareExcel = async () => {
        try {
            // Log share action
            await auditLog('SHARE_ORDER', 'ShareOptionsModal', {
                date: orderData.date,
                totalKg: orderData.totalKg,
                itemCount: items.length
            });

            const workbook = await prepareWorkbook(orderData);
            const buffer = await workbook.xlsx.writeBuffer();
            const fileName = `Graviton_${orderData.date.replace(/\./g, '-')}.xlsx`;
            const shareText = `Замовлення GRAVITON на ${orderData.date}\nЗагальна вага: ${orderData.totalKg} кг`;
            const file = new File(
                [buffer],
                fileName,
                { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' }
            );

            const downloadFile = () => {
                const blob = new Blob([buffer], {
                    type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
                });
                const url = window.URL.createObjectURL(blob);
                const link = document.createElement('a');
                link.href = url;
                link.download = fileName;
                link.click();
                window.URL.revokeObjectURL(url);
            };

            const hasShareApi = typeof navigator !== 'undefined' && typeof navigator.share === 'function';
            const canShareFiles = hasShareApi
                && typeof navigator.canShare === 'function'
                && navigator.canShare({ files: [file] });

            if (canShareFiles) {
                await navigator.share({
                    files: [file],
                    title: 'Виробниче замовлення',
                    text: shareText
                });
                return;
            }

            if (hasShareApi) {
                try {
                    await navigator.share({
                        title: 'Виробниче замовлення',
                        text: shareText
                    });
                } catch (shareError) {
                    console.warn('Text share failed:', shareError);
                }
            }

            downloadFile();
            alert('Ваш браузер не підтримує надсилання файлів. Файл завантажено, додайте його в Telegram/WhatsApp/Viber вручну.');
        } catch (error) {
            console.error('Помилка при поділитися:', error);
            await auditLog('ERROR', 'ShareOptionsModal', { error: String(error) });
            alert('Помилка при поділитися файлом');
        }
    };


    const messagePreview = useMemo(() => {
        return formatOrderMessage(items);
    }, [items]);

    const groupedByCategory = useMemo(() => {
        return groupItemsByCategory(items);
    }, [items]);

    const handleCopy = () => {
        navigator.clipboard.writeText(messagePreview);
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
    };

    return (
        <Modal isOpen={isOpen} onClose={onClose} size="md">
            {/* Header */}
            <ModalHeader icon={<Send size={20} />}>
                <h2 className="text-[16px] font-black uppercase tracking-tight text-white">
                    Поділитися замовленням
                </h2>
                <p className="text-[11px] text-white/40 mt-1">
                    Оберіть спосіб надсилання
                </p>
            </ModalHeader>

            {/* Content */}
            <ModalBody className="space-y-6">
                {/* Action Buttons */}
                <div className="space-y-4">
                    <h3 className="text-[11px] font-bold uppercase text-white/40 tracking-widest text-center">
                        Оберіть дію
                    </h3>

                    <div className="flex gap-3">
                        {/* Share Button */}
                        <button
                            onClick={handleShareExcel}
                            className="flex-1 flex items-center justify-center gap-2.5 px-6 py-4 rounded-xl font-bold text-[13px] transition-all hover:scale-[1.02] active:scale-[0.98] bg-gradient-to-r from-[#0088FF] to-[#00D4FF] text-white shadow-lg shadow-[#0088FF]/20 hover:shadow-xl hover:shadow-[#00D4FF]/30"
                        >
                            <Send size={18} />
                            Поділитися
                        </button>

                        {/* Download Button */}
                        <button
                            onClick={handleDownloadExcel}
                            className="flex-1 flex items-center justify-center gap-2.5 px-6 py-4 rounded-xl font-bold text-[13px] transition-all hover:scale-[1.02] active:scale-[0.98] bg-white/5 border border-white/10 hover:bg-white/10 hover:border-white/20 text-white"
                        >
                            <Download size={18} className="text-[#00D4FF]" />
                            Завантажити
                        </button>
                    </div>
                </div>

                {/* Message Preview */}
                <div>
                    <div className="flex items-center justify-between mb-3">
                        <h3 className="text-[11px] font-bold uppercase text-white/40 tracking-widest">
                            Попередній перегляд
                        </h3>
                        <button
                            onClick={handleCopy}
                            className="flex items-center gap-2 px-3 py-1.5 bg-white/5 border border-white/10 rounded-lg text-[11px] font-bold text-white/70 hover:text-white hover:border-white/20 hover:bg-white/10 transition-all"
                        >
                            {copied ? (
                                <>
                                    <Check size={12} className="text-[#10B981]" />
                                    Скопійовано
                                </>
                            ) : (
                                <>
                                    <Copy size={12} />
                                    Копіювати
                                </>
                            )}
                        </button>
                    </div>

                    <div className="bg-black/30 border border-white/5 rounded-xl p-5 font-sans text-[13px] text-white/80 leading-relaxed max-h-[280px] overflow-y-auto custom-scrollbar">
                        <div className="space-y-4">
                            // eslint-disable-next-line @typescript-eslint/no-explicit-any
                            {Object.entries(groupedByCategory).map(([category, data]: any) => (
                                <div key={category} className="space-y-1">
                                    <div className="font-black text-[#00D4FF] border-b border-white/5 pb-1 mb-2">
                                        {category.toUpperCase()}: {data.totalKg} кг
                                    </div>
                                    <div className="pl-2 space-y-1.5 opacity-90">
                                        // eslint-disable-next-line @typescript-eslint/no-explicit-any
                                        {data.items.map((item: any, idx: number) => (
                                            <div key={idx} className="flex justify-between items-center text-[12px]">
                                                <span className="text-white/70">• {item.productName}</span>
                                                <span className="font-bold text-[#00D4FF]">{item.kg} кг</span>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            ))}
                            {Object.keys(groupedByCategory).length === 0 && (
                                <p className="text-center opacity-40 py-8">Немає вибраних товарів</p>
                            )}
                        </div>
                    </div>
                </div>
            </ModalBody>

            {/* Footer */}
            <ModalFooter>
                <div className="flex justify-center">
                    <ModalButton variant="secondary" onClick={onClose} className="w-full">
                        Закрити
                    </ModalButton>
                </div>
            </ModalFooter>
        </Modal>
    );
};

import React, { useState, useMemo, useEffect } from 'react';
import { ProductionTask } from '@/types/bi';
import { StoreProductCard } from './graviton/StoreProductCard';
import { Package, X, Store, ArrowRight } from 'lucide-react';
import { cn } from '@/lib/utils';
import { AnimatePresence, motion } from 'framer-motion';

interface Props {
    queue: ProductionTask[];
    storeName: string;
}

export const StoreSpecificView = ({ queue, storeName }: Props) => {
    const [selectedCategory, setSelectedCategory] = useState<string | null>(null);

    // Group items by broad category based on naming conventions
    const categoriesMap = useMemo(() => {
        const map = new Map<string, {
            categoryName: string;
            items: ProductionTask[];
            totalKg: number;
            totalFact: number;
            itemsCount: number;
        }>();

        queue.forEach(item => {
            let cat = 'Інше';
            const nameLower = item.name.toLowerCase();

            if (nameLower.includes('вареники')) cat = 'Вареники';
            else if (nameLower.includes('млинці')) cat = 'Млинці';
            else if (nameLower.includes('котлети')) cat = 'Котлети';
            else if (nameLower.includes('сирники')) cat = 'Сирники';
            else if (nameLower.includes('хінкалі')) cat = 'Хінкалі';
            else if (nameLower.includes('пельмені')) cat = 'Пельмені';
            else if (nameLower.includes('зрази')) cat = 'Зрази';
            else if (nameLower.includes('ковбас')) cat = 'Ковбаси';
            else if (nameLower.includes('голубці')) cat = 'Голубці';
            else if (nameLower.includes('деруни')) cat = 'Деруни';
            else if (nameLower.includes('м\'ясо') || nameLower.includes('куряч')) cat = 'М\'ясні вироби';

            if (!map.has(cat)) {
                map.set(cat, {
                    categoryName: cat,
                    items: [],
                    totalKg: 0,
                    totalFact: 0,
                    itemsCount: 0
                });
            }

            const c = map.get(cat)!;
            c.items.push(item);
            c.itemsCount += 1;
            c.totalKg += item.recommendedQtyKg || 0;
            c.totalFact += item.stores[0]?.currentStock || 0;
        });

        // Filter out empty categories and sort by totalKg descending
        return Array.from(map.values())
            .filter(c => c.itemsCount > 0)
            .sort((a, b) => b.totalKg - a.totalKg);

    }, [queue]);

    // Handle escape key to close modal
    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if (e.key === 'Escape') {
                setSelectedCategory(null);
            }
        };
        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, []);

    const selectedCategoryData = useMemo(() => {
        if (!selectedCategory) return null;
        return categoriesMap.find(c => c.categoryName === selectedCategory) || null;
    }, [selectedCategory, categoriesMap]);

    const totalStoreKg = useMemo(() => categoriesMap.reduce((sum, c) => sum + c.totalKg, 0), [categoriesMap]);

    return (
        <div className="flex flex-col h-full overflow-hidden bg-bg-primary font-sans text-text-primary">

            {/* STICKY HEADER */}
            <div className="px-6 py-4 flex items-center justify-between border-b border-white/5 z-10 sticky top-0 bg-[#0A1931]/80 backdrop-blur-md">
                <div className="flex items-center gap-3">
                    <div className="p-2 bg-gradient-to-br from-[#00E0FF]/20 to-[#00E0FF]/5 border border-[#00E0FF]/20 rounded-xl">
                        <Store size={20} className="text-[#00E0FF]" />
                    </div>
                    <div>
                        <h2 className="text-xl font-bold uppercase tracking-widest text-white font-display">
                            {storeName}
                        </h2>
                    </div>
                </div>

                <div className="flex items-center gap-6">
                    <div className="flex flex-col items-end">
                        <span className="text-[10px] text-white/40 font-bold uppercase tracking-widest font-display mb-0.5">Сумарний дефіцит</span>
                        <div className="flex items-baseline gap-1">
                            <span className="text-2xl font-bold text-[#00E0FF] font-[family-name:var(--font-jetbrains)]">{totalStoreKg.toFixed(0)}</span>
                            <span className="text-[10px] text-[#00E0FF]/60 uppercase font-bold font-display tracking-widest">кг</span>
                        </div>
                    </div>
                </div>
            </div>

            {/* CATEGORY CARDS GRID */}
            <div className="flex-1 overflow-y-auto p-6 custom-scrollbar">
                <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 2xl:grid-cols-5 gap-4 pb-20">
                    {categoriesMap.map((category) => {
                        const hasDeficit = category.totalKg > 0;
                        const fillPercent = Math.min(100, (category.totalKg / 100) * 100);

                        return (
                            <div
                                key={category.categoryName}
                                onClick={() => setSelectedCategory(category.categoryName)}
                                className={cn(
                                    "glass-panel p-4 rounded-xl transition-all flex flex-col justify-between group cursor-pointer min-h-[140px] relative overflow-hidden",
                                    hasDeficit ? "bg-[#131B2C] hover:shadow-[0_0_20px_rgba(0,224,255,0.15)] hover:border-[#00E0FF]/30" : "bg-[#161B22]/60 opacity-60 hover:opacity-100"
                                )}
                            >
                                <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-b from-transparent via-[#00E0FF]/50 to-transparent opacity-0 group-hover:opacity-100 animate-scan pointer-events-none"></div>

                                <div className="flex items-start justify-between relative z-10 mb-4">
                                    <div className="flex items-center gap-3">
                                        <div className={cn("p-2 rounded-lg border transition-colors", hasDeficit ? "bg-[#00E0FF]/10 border-[#00E0FF]/20 text-[#00E0FF]" : "bg-white/5 border-white/10 text-white/40")}>
                                            <Package size={18} />
                                        </div>
                                        <div className="flex flex-col">
                                            <h3 className="text-sm font-black uppercase text-white tracking-widest font-[family-name:var(--font-chakra)] group-hover:text-[#00E0FF] transition-colors">
                                                {category.categoryName}
                                            </h3>
                                            <span className="text-[9px] text-white/40 uppercase font-bold font-display tracking-widest">
                                                {category.itemsCount} позицій
                                            </span>
                                        </div>
                                    </div>
                                    <ArrowRight size={16} className="text-white/20 group-hover:text-[#00E0FF] transition-colors group-hover:translate-x-1" />
                                </div>

                                <div className="mt-auto border-t border-white/5 pt-3 relative z-10">
                                    <span className="text-[8px] uppercase tracking-[0.2em] font-bold text-white/30 mb-1 block font-display">Треба виготовити</span>
                                    <div className="flex items-end justify-between">
                                        <div className="flex items-baseline gap-1">
                                            <span className={cn("text-2xl font-bold font-[family-name:var(--font-jetbrains)] leading-none", hasDeficit ? "text-[#00E0FF]" : "text-white/20")}>
                                                {category.totalKg.toFixed(0)}
                                            </span>
                                            <span className="text-[9px] text-[#00E0FF]/60 uppercase font-bold font-display tracking-widest">кг</span>
                                        </div>

                                        {hasDeficit && (
                                            <div className="w-16 h-1.5 bg-black/40 rounded-full overflow-hidden mb-1">
                                                <div className="h-full bg-[#00E0FF] shadow-[0_0_8px_rgba(0,224,255,0.6)]" style={{ width: `${Math.max(5, fillPercent)}%` }} />
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>

            {/* PRODUCT MODAL OVERLAY */}
            <AnimatePresence>
                {selectedCategory && selectedCategoryData && (
                    <motion.div
                        className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-md transition-opacity p-4 lg:p-8"
                        onClick={(e) => {
                            if (e.target === e.currentTarget) setSelectedCategory(null);
                        }}
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                    >
                        <motion.div
                            initial={{ scale: 0.95, opacity: 0 }}
                            animate={{ scale: 1, opacity: 1 }}
                            exit={{ scale: 0.95, opacity: 0 }}
                            className="w-full max-w-[1400px] h-auto max-h-[90vh] rounded-2xl overflow-hidden bg-[#112240]/95 backdrop-blur-md border border-[#00E0FF]/20 shadow-[0_0_30px_rgba(0,224,255,0.15)] flex flex-col"
                            onClick={e => e.stopPropagation()}
                        >
                            {/* MODAL HEADER */}
                            <div className="flex items-start justify-between p-5 px-8 border-b border-[#00E0FF]/10 shrink-0 bg-[#112240]/80 shadow-lg">
                                <div className="flex items-center gap-6 lg:gap-12">
                                    <div className="flex flex-col justify-center">
                                        <div className="text-[10px] text-[#00E0FF] font-bold uppercase tracking-[0.2em] flex items-center gap-2 font-[family-name:var(--font-jetbrains)]">
                                            <span>Магазин "{storeName}"</span>
                                        </div>
                                        <h2 className="text-2xl md:text-3xl font-bold text-white uppercase tracking-wider leading-none mt-2 font-[family-name:var(--font-chakra)]">
                                            {selectedCategoryData.categoryName} <span className="text-white/30 text-lg md:text-xl font-display">/ {selectedCategoryData.itemsCount} тов.</span>
                                        </h2>
                                    </div>

                                    {/* Summary Metrics Inline with Title */}
                                    <div className="flex items-center gap-4 lg:gap-8 mt-2">
                                        <div className="flex flex-col justify-end">
                                            <div className="text-[9px] md:text-[10px] uppercase font-bold text-slate-400 tracking-[0.2em] mb-2 font-[family-name:var(--font-jetbrains)]">Факт Залишок</div>
                                            <div className={cn(
                                                "text-2xl md:text-3xl font-mono font-black leading-none flex items-baseline gap-1 font-[family-name:var(--font-jetbrains)]",
                                                selectedCategoryData.totalKg > 0 ? "text-status-critical drop-shadow-[0_0_8px_rgba(255,42,85,0.5)]" : "text-status-success drop-shadow-[0_0_8px_rgba(16,185,129,0.3)]"
                                            )}>
                                                {selectedCategoryData.totalFact.toFixed(0)} <span className="text-[9px] md:text-[11px] font-bold text-slate-500 font-[family-name:var(--font-jetbrains)] uppercase tracking-wider">шт</span>
                                            </div>
                                        </div>
                                        <div className="w-px h-10 bg-white/10 hidden sm:block"></div>
                                        <div className="flex flex-col justify-end">
                                            <div className="text-[9px] md:text-[10px] uppercase font-bold text-slate-400 tracking-[0.2em] mb-2 font-[family-name:var(--font-jetbrains)]">Треба (Ціль)</div>
                                            <div className="text-2xl md:text-3xl font-mono font-black text-[#00E0FF] leading-none flex items-baseline gap-1 font-[family-name:var(--font-jetbrains)] drop-shadow-[0_0_8px_rgba(0,224,255,0.4)]">
                                                {selectedCategoryData.totalKg.toFixed(0)} <span className="text-[9px] md:text-[11px] font-bold text-[#00E0FF]/50 font-[family-name:var(--font-jetbrains)] uppercase tracking-wider">кг</span>
                                            </div>
                                        </div>
                                    </div>
                                </div>

                                <button
                                    onClick={() => setSelectedCategory(null)}
                                    className="p-3 rounded-xl bg-panel-border/30 text-text-muted hover:text-text-primary hover:bg-panel-border/50 transition-colors mt-2"
                                >
                                    <X size={20} />
                                </button>
                            </div>

                            {/* MODAL CONTENT: PRODUCTS GRID */}
                            <motion.div
                                initial={{ y: 20, opacity: 0 }}
                                animate={{ y: 0, opacity: 1 }}
                                transition={{ delay: 0.1 }}
                                className="flex-1 overflow-y-auto p-6 md:p-8 custom-scrollbar"
                            >
                                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-3">
                                    {selectedCategoryData.items.map((item) => (
                                        <StoreProductCard key={item.id} item={item} />
                                    ))}
                                </div>
                            </motion.div>
                        </motion.div>
                    </motion.div>
                )}
            </AnimatePresence>

        </div>
    );
};

