                                </div>
                            </div>
                            <div className="w-px h-10 bg-white/10 hidden md:block"></div>
                            <div className="flex flex-col justify-end">
                                <div className="text-[10px] uppercase font-bold text-slate-400 tracking-[0.2em] mb-2 font-[family-name:var(--font-jetbrains)]">Треба (Ціль)</div>
                                <div className="text-3xl font-mono font-black text-[#00E0FF] leading-none flex items-baseline gap-1 font-[family-name:var(--font-jetbrains)] drop-shadow-[0_0_8px_rgba(0,224,255,0.4)]">
                                    {product.computed.totalRecommended.toFixed(0)} <span className="text-[11px] font-bold text-[#00E0FF]/50 font-[family-name:var(--font-jetbrains)] uppercase tracking-wider">шт</span>
                                </div>
                            </div>
                        </div>
                    </div>

                    <button
                        onClick={onClose}
                        className="p-3 rounded-xl bg-panel-border/30 text-text-muted hover:text-text-primary hover:bg-panel-border/50 transition-colors mt-2"
                    >
                        <X size={20} />
                    </button>
                </div>
                {/* SHOPS GRID */}
                <div className="flex-1 overflow-y-auto custom-scrollbar p-6">
                    <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-3">
                        // eslint-disable-next-line @typescript-eslint/no-explicit-any
                        {stores.map((store: any, index: number) => {
                            const isLowStock = store.computed.stock < store.computed.minStock;

                            return (
                                <div
                                    key={store.storeName || index}
                                    className={cn(
                                        "rounded-xl p-4 flex flex-col gap-2 transition-all duration-300 relative overflow-hidden group hover:shadow-[0_0_20px_rgba(0,224,255,0.15)]",
                                        isLowStock
                                            ? "bg-status-critical/5 border border-status-critical/30 shadow-[0_0_15px_rgba(255,42,85,0.1)] hover:border-status-critical/50"
                                            : "bg-[#0A1931]/60 border border-[#00E0FF]/10 shadow-[0_0_15px_rgba(16,185,129,0.05)] hover:border-[#00E0FF]/30"
                                    )}
                                >
                                    <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-b from-transparent via-white/20 to-transparent opacity-0 group-hover:opacity-100 animate-scan pointer-events-none"></div>
                                    {/* Store Name */}
                                    <div
                                        className="text-sm font-semibold text-white uppercase tracking-wider truncate text-center font-[family-name:var(--font-chakra)]"
                                        title={store.storeName}
                                    >
                                        {store.storeName.replace('Магазин ', '')}
                                    </div>

                                    {/* Metrics Row */}
                                    <div className="grid grid-cols-3 gap-2 mt-2">
                                        <div className="flex flex-col items-center">
                                            <span className="text-[9px] font-bold tracking-[0.2em] text-slate-400 mb-1 uppercase font-[family-name:var(--font-jetbrains)]">Факт</span>
                                            <span className={cn(
                                                "text-lg font-bold font-[family-name:var(--font-jetbrains)] leading-none",
                                                isLowStock ? "text-status-critical drop-shadow-[0_0_8px_rgba(255,42,85,0.5)]" : "text-status-success drop-shadow-[0_0_8px_rgba(16,185,129,0.3)]"
                                            )}>
                                                {store.computed.stock.toFixed(0)}
                                            </span>
                                        </div>
                                        <div className="flex flex-col items-center">
                                            <span className="text-[9px] font-bold tracking-[0.2em] text-slate-400 mb-1 uppercase font-[family-name:var(--font-jetbrains)]">Мін</span>
                                            <span className="text-lg font-bold font-[family-name:var(--font-jetbrains)] leading-none text-slate-300">
                                                {store.computed.minStock.toFixed(0)}
                                            </span>
                                        </div>
                                        <div className="flex flex-col items-center">
                                            <span className="text-[9px] font-bold tracking-[0.2em] text-slate-400 mb-1 uppercase font-[family-name:var(--font-jetbrains)]">Сер</span>
                                            <span className="text-lg font-bold font-[family-name:var(--font-jetbrains)] leading-none text-[#00E0FF]">
                                                {store.computed.avg.toFixed(1)}
                                            </span>
                                        </div>
                                    </div>

                                </div>
                            );
                        })}
                    </div>
                </div>
            </div>
        </div>
    );
}

'use client';

import React, { useState } from 'react';
import useSWR from 'swr';
import { ProductionTask } from '@/types/bi';
import { cn } from '@/lib/utils';
import { generateProductionPlanExcel } from '@/lib/order-export';
// eslint-disable-next-line @typescript-eslint/no-unused-vars
import { Activity, Percent, TrendingUp, Calculator, Package, AlertTriangle, ChevronDown, FileSpreadsheet, Loader2 } from 'lucide-react';

interface Props {
    data: ProductionTask[];
    onRefresh: () => void;
}

// eslint-disable-next-line @typescript-eslint/no-unused-vars
export const ProductionOpsTable = ({ data, onRefresh }: Props) => {
    // 2. State
    const [days, setDays] = useState(1);
    const [isShiftMode, setIsShiftMode] = useState(false);
    const [selectedPizza, setSelectedPizza] = useState<string | null>(null);
    const [notification, setNotification] = useState<string | null>(null);

    // 3. Execution State
    const [isLoading, setIsLoading] = useState(false);
    const [isExporting, setIsExporting] = useState(false);
    const [isCalculated, setIsCalculated] = useState(false);
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const [planData, setPlanData] = useState<any[]>([]);

    // 4. Shop Stats
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const { data: shopStats } = useSWR<any[]>(
        selectedPizza ? `/api/pizza/shop-stats?pizza=${encodeURIComponent(selectedPizza)}` : null,
        (url: string) => fetch(url).then(r => r.json())
    );

    const handleGenerateOrder = async () => {
        setIsLoading(true);
        setPlanData([]);
        setIsCalculated(false);
        setSelectedPizza(null);

        try {
            const queryParams = new URLSearchParams({
                days: isShiftMode ? '3' : days.toString()
            });

            const response = await fetch(`/api/pizza/order-plan?${queryParams}`);

            if (!response.ok) throw new Error('API Error');

            const data = await response.json();
            setPlanData(data);
            setIsCalculated(true);

        } catch (error) {
            console.error("Calculation failed:", error);
            alert("Помилка розрахунку");
        } finally {
            setIsLoading(false);
        }
    };

    const handleExportExcel = async () => {
        if (planData.length === 0) return;
        setIsExporting(true);
        try {
            await generateProductionPlanExcel(planData, isShiftMode ? 3 : days);
            setNotification('Файл успішно збережено!');
            setTimeout(() => setNotification(null), 3000);
        } catch (error) {
            console.error('Export failed:', error);
            alert('Помилка експорту');
        } finally {
            setIsExporting(false);
        }
    };

    return (
        <div className="h-full flex flex-col bg-[#0B0E14] overflow-hidden font-sans">
            {/* 1. MANAGEMENT BLOCK (Control Panel) */}
            <div className="px-8 py-6 bg-[#141829] border-b border-white/5 shrink-0 relative flex items-center gap-10 z-20 shadow-[0_4px_20px_rgba(0,0,0,0.5)] transition-all">
                {/* Subtle grid pattern for the top bar */}
                <div className="absolute inset-0 bg-[linear-gradient(rgba(255,255,255,0.02)_1px,transparent_1px),linear-gradient(90deg,rgba(255,255,255,0.02)_1px,transparent_1px)] bg-[size:32px_32px] pointer-events-none" />

                {/* Notification Toast */}
                {notification && (
                    <div className="absolute top-2 right-8 bg-[#00D4FF]/20 text-[#00D4FF] border border-[#00D4FF]/30 px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest animate-in fade-in slide-in-from-top-2 z-30 shadow-[0_0_15px_rgba(0,212,255,0.3)] backdrop-blur-md">
                        {notification}
                    </div>
                )}

                {/* Days Input Group */}
                <div className="flex items-center gap-4 group/input z-10">
                    <div className="flex flex-col">
                        <label className={cn(
                            "text-[10px] font-black uppercase tracking-[0.2em] mb-1.5 transition-colors",
                            isShiftMode ? "text-white/20" : "text-white/40 group-hover/input:text-[#00D4FF]"
                        )}>
                            Планування
                        </label>
                        <div className="flex items-center gap-3">
                            <input
                                type="number"
                                min="1"
                                max="30"
                                value={isShiftMode ? 3 : days}
                                disabled={isShiftMode}
                                onChange={(e) => {
                                    const val = parseInt(e.target.value);
                                    if (!isNaN(val)) setDays(Math.max(1, val));
                                }}
                                className={cn(
                                    "w-24 h-12 bg-[#0B0E14] border border-white/10 rounded-xl text-center font-mono font-black text-xl text-white focus:outline-none transition-all duration-300",
                                    isShiftMode
                                        ? "border-transparent text-white/20 cursor-not-allowed"
                                        : "focus:border-[#00D4FF] focus:shadow-[0_0_15px_rgba(0,212,255,0.3)] hover:border-white/20 shadow-inner"
                                )}
                            />
                            <span className={cn(
                                "text-xs font-bold uppercase tracking-widest",
                                isShiftMode ? "text-white/20" : "text-white/40"
                            )}>Днів</span>
                        </div>
                    </div>
                </div>

                <div className="h-10 w-px bg-white/10 z-10" />

                {/* 3x3 Toggle Segment */}
                <div className="flex flex-col z-10">
                    <label className="text-[10px] font-black uppercase tracking-[0.2em] mb-1.5 text-white/40">
                        Режим роботи
                    </label>
                    <div
                        onClick={() => setIsShiftMode(!isShiftMode)}
                        className="flex items-center gap-4 cursor-pointer group select-none bg-[#0B0E14] border border-white/10 hover:border-white/20 px-4 py-2 rounded-xl transition-all h-12 shadow-inner"
                    >
                        <div className={cn(
                            "relative w-12 h-6 rounded-full transition-all duration-500",
                            isShiftMode ? "bg-[#00D4FF] shadow-[0_0_10px_rgba(0,212,255,0.5)]" : "bg-white/10"
                        )}>
                            <div className={cn(
                                "absolute top-1 left-1 w-4 h-4 rounded-full bg-white transition-transform duration-500 shadow-sm",
                                isShiftMode ? "translate-x-6" : "translate-x-0"
                            )} />
                        </div>
                        <span className={cn(
                            "text-xs font-black uppercase tracking-widest transition-colors",
                            isShiftMode ? "text-white drop-shadow-[0_0_5px_rgba(255,255,255,0.5)]" : "text-white/40 group-hover:text-white/60"
                        )}>
                            Режим 3х3
                        </span>
                    </div>
                </div>

                <div className="flex-1" />

                {/* EXPORT BUTTON */}
                {isCalculated && (
                    <button
                        onClick={handleExportExcel}
                        disabled={isExporting}
                        className={cn(
                            "relative z-10 flex items-center gap-3 px-6 py-4 bg-emerald-500/10 border border-emerald-500/30 hover:bg-emerald-500/20 active:scale-95 text-emerald-400 font-black uppercase tracking-[0.2em] text-xs rounded-2xl transition-all mr-4 disabled:opacity-50 disabled:cursor-not-allowed",
                            isExporting && "animate-pulse"
                        )}
                    >
                        {isExporting ? <Loader2 size={16} className="animate-spin" /> : <FileSpreadsheet size={18} strokeWidth={2.5} />}
                        {isExporting ? "Експорт..." : "Excel звір"}
                    </button>
                )}

                {/* Action Button */}
                <button
                    onClick={handleGenerateOrder}
                    disabled={isLoading}
                    className={cn(
                        "relative z-10 group overflow-hidden flex items-center gap-4 px-10 py-4 bg-[#00D4FF] hover:bg-[#33DDFF] active:scale-95 text-[#0B0E14] font-black uppercase tracking-[0.2em] text-sm rounded-2xl transition-all shadow-[0_0_20px_rgba(0,212,255,0.3)] disabled:opacity-50 disabled:cursor-not-allowed",
                        isLoading && "animate-pulse"
                    )}
                >
                    <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/40 to-transparent translate-x-[-150%] skew-x-[-45deg] group-hover:transition-transform group-hover:duration-700 group-hover:translate-x-[150%]" />
                    <Calculator size={20} strokeWidth={3} />
                    {isLoading ? "Розрахунок..." : "Розрахувати"}
                </button>
            </div>

            {/* 2. RESULTS GRID */}
            <div className="flex-1 overflow-auto bg-[#0B0E14] relative text-white px-8 py-6 custom-scrollbar">

                {/* LOADING / EMPTY STATES */}
                {isLoading && (
                    <div className="absolute inset-0 flex items-center justify-center bg-[#0B0E14]/80 z-30 backdrop-blur-sm">
                        <div className="flex flex-col items-center gap-6">
                            <div className="relative">
                                <Calculator className="animate-[spin_3s_linear_infinite] text-[#00D4FF] relative z-10 drop-shadow-[0_0_15px_rgba(0,212,255,0.8)]" size={64} />
                                <div className="absolute inset-0 bg-[#00D4FF]/20 blur-xl rounded-full animate-pulse" />
                            </div>
                            <div className="flex flex-col items-center">
                                <span className="text-xl font-black uppercase tracking-[0.3em] text-white drop-shadow-[0_0_10px_rgba(255,255,255,0.5)]">Аналіз даних</span>
                                <span className="text-[10px] font-bold uppercase tracking-widest text-[#00D4FF]/60 mt-2">Формування оптимального замовлення</span>
                            </div>
                        </div>
                    </div>
                )}

                {!isCalculated && !isLoading && (
                    <div className="h-full flex flex-col items-center justify-center opacity-60 select-none">
                        <div className="w-24 h-24 rounded-full border-2 border-dashed border-white/20 flex items-center justify-center mb-6">
                            <Activity size={40} className="animate-pulse text-white/40" />
                        </div>
                        <h3 className="text-lg font-black uppercase tracking-[0.2em] mb-2 text-white/60">Готовий до розрахунку</h3>
                        <p className="text-xs font-medium text-white/40 tracking-wider">Оберіть дні та натисніть кнопку "Розрахувати"</p>
                    </div>
                )}

                {/* RESULTS - HORIZONTAL TAPE + FULL GRID LAYOUT */}
                {isCalculated && !isLoading && (
                    <div className="flex flex-col gap-10 pb-10">
                        {Object.entries(planData.reduce((acc, item) => {
                            (acc[item.p_day] = acc[item.p_day] || []).push(item);
                            return acc;
                        // eslint-disable-next-line @typescript-eslint/no-explicit-any
                        }, {} as Record<number, any[]>))
                            .sort(([dayA], [dayB]) => Number(dayA) - Number(dayB))
                            // eslint-disable-next-line @typescript-eslint/no-explicit-any
                            .map(([day, items]: [string, any]) => (
                                <div key={day} className="flex flex-col gap-4">
                                    {/* DAY HEADER */}
                                    <div className="flex items-center gap-6 px-2 mb-2">
                                        <div className="px-6 py-2 rounded-xl bg-[#00D4FF]/10 border border-[#00D4FF]/30 text-white text-sm font-black uppercase tracking-[0.3em] shadow-[0_0_15px_rgba(0,212,255,0.2)] backdrop-blur-sm">
                                            День <span className="text-[#00D4FF] ml-1 drop-shadow-[0_0_5px_rgba(0,212,255,0.8)]">{day}</span>
                                        </div>
                                        <div className="h-px bg-gradient-to-r from-[#00D4FF]/50 to-transparent flex-1" />
                                        <div className="text-[10px] text-white/30 font-black uppercase tracking-[0.2em]">
                                            {items.length} ПРЕДМЕТІВ
                                        </div>
                                    </div>

                                    {/* HORIZONTAL TAPE OF CARDS */}
                                    <div className="flex gap-4 overflow-x-auto pb-6 px-1 custom-scrollbar snap-x">
                                        // eslint-disable-next-line @typescript-eslint/no-explicit-any
                                        {items.sort((a: any, b: any) => (Number(b.p_avg) || 0) - (Number(a.p_avg) || 0)).map((item: any, idx: number) => {
                                            const isSelected = selectedPizza === item.p_name;
                                            const pStock = Number(item.p_stock);
                                            const pOrder = Number(item.p_order);
                                            const target = pStock + pOrder;
                                            const percentage = target === 0 ? 100 : Math.min(100, (pStock / target) * 100);

                                            const isCritical = percentage < 60;
                                            const isWarning = percentage >= 60 && percentage < 90;

                                            return (
                                                <div
                                                    key={idx}
                                                    onClick={() => setSelectedPizza(prev => prev === item.p_name ? null : item.p_name)}
                                                    className={cn(
                                                        "min-w-[280px] snap-start bg-[#141829]/80 backdrop-blur-md border rounded-2xl transition-all duration-300 cursor-pointer select-none group/card relative overflow-hidden",
                                                        isSelected
                                                            ? "ring-2 ring-[#00D4FF] border-[#00D4FF] shadow-[0_0_30px_rgba(0,212,255,0.3)] scale-[1.02]"
                                                            : "border-white/5 hover:border-white/20 hover:shadow-[0_4px_20px_rgba(0,0,0,0.5)]"
                                                    )}
                                                >
                                                    {isSelected && <div className="absolute inset-0 bg-[#00D4FF]/5 pointer-events-none" />}

                                                    {/* Status Indicator Bar */}
                                                    <div className={cn(
                                                        "h-1 w-full relative",
                                                        isCritical ? "bg-[#FF6B6B]" :
                                                            isWarning ? "bg-[#FFB800]" :
                                                                "bg-emerald-500"
                                                    )}>
                                                        <div className={cn(
                                                            "absolute inset-0 blur-sm",
                                                            isCritical ? "bg-[#FF6B6B]" :
                                                                isWarning ? "bg-[#FFB800]" :
                                                                    "bg-emerald-500"
                                                        )} />
                                                    </div>

                                                    <div className="p-4 relative z-10">
                                                        <div className="flex items-start justify-between gap-3 mb-4">
                                                            <h4 className="text-[11px] font-black text-white/90 leading-tight tracking-tight uppercase group-hover/card:text-[#00D4FF] transition-colors truncate" title={item.p_name}>
                                                                {item.p_name}
                                                            </h4>
                                                            {isCritical && <AlertTriangle size={14} className="text-[#FF6B6B] drop-shadow-[0_0_8px_rgba(255,107,107,0.8)] shrink-0" />}
                                                        </div>

                                                        <div className="flex items-end justify-between mb-4">
                                                            <div className="flex flex-col">
                                                                <span className="text-[8px] font-black text-white/40 uppercase tracking-[0.15em] mb-0.5">ЗАМОВЛЕННЯ</span>
                                                                <div className="flex items-baseline gap-1">
                                                                    <span className={cn(
                                                                        "text-3xl font-black font-mono leading-none tracking-tighter",
                                                                        pOrder > 0 ? "text-[#00D4FF] drop-shadow-[0_0_15px_rgba(0,212,255,0.5)]" : "text-white/20"
                                                                    )}>
                                                                        {pOrder.toFixed(0)}
                                                                    </span>
                                                                    <span className="text-[10px] font-black text-[#00D4FF]/50 uppercase">шт</span>
                                                                </div>
                                                            </div>
                                                            <div className="flex flex-col items-end">
                                                                <span className="text-[8px] font-black text-white/40 uppercase tracking-[0.15em] mb-0.5">ФАКТ</span>
                                                                <span className={cn(
                                                                    "text-lg font-black font-mono leading-none",
                                                                    isCritical ? "text-[#FF6B6B] drop-shadow-[0_0_10px_rgba(255,107,107,0.5)]" :
                                                                        isWarning ? "text-[#FFB800] drop-shadow-[0_0_10px_rgba(255,184,0,0.5)]" :
                                                                            "text-emerald-500 drop-shadow-[0_0_10px_rgba(16,185,129,0.5)]"
                                                                )}>
                                                                    {pStock.toFixed(0)}
                                                                </span>
                                                            </div>
                                                        </div>

                                                        <div className="relative h-1.5 bg-[#0B0E14] rounded-full overflow-hidden mb-3 border border-white/5">
                                                            <div
                                                                className={cn(
                                                                    "h-full rounded-full transition-all duration-1000 relative",
                                                                    isCritical ? "bg-[#FF6B6B]" :
                                                                        isWarning ? "bg-[#FFB800]" :
                                                                            "bg-emerald-500"
                                                                )}
                                                                style={{ width: `${percentage}%` }}
                                                            >
                                                                <div className="absolute inset-0 bg-white/20 w-1/2 skew-x-[-20deg] animate-[shimmer_2s_infinite]" />
                                                            </div>
                                                        </div>

                                                        <div className="flex items-center justify-between text-[9px] font-bold text-white/40 uppercase tracking-widest pt-1 border-t border-white/5">
                                                            <div className="flex gap-3">
                                                                <span>Мін <span className="text-white font-mono ml-0.5">{Number(item.p_min).toFixed(0)}</span></span>
                                                                <span>Сер <span className="text-white font-mono ml-0.5">{Number(item.p_avg).toFixed(1)}</span></span>
                                                            </div>
                                                            <ChevronDown size={12} className={cn("transition-transform duration-500", isSelected && "rotate-180 text-[#00D4FF]")} />
                                                        </div>
                                                    </div>
                                                </div>
                                            );
                                        })}
                                    </div>

                                    {/* FULL GRID ANALYTICS (Appears when a pizza is selected) */}
                                    // eslint-disable-next-line @typescript-eslint/no-explicit-any
                                    {selectedPizza && items.some((i: any) => i.p_name === selectedPizza) && (
                                        <div className="mt-2 bg-[#141829]/50 backdrop-blur-xl border border-[#00D4FF]/20 rounded-3xl p-8 animate-in fade-in slide-in-from-top-4 duration-500 shadow-[0_0_50px_rgba(0,212,255,0.05)] relative overflow-hidden">
                                            {/* Decorative grid pattern */}
                                            <div className="absolute inset-0 bg-[linear-gradient(rgba(0,212,255,0.03)_1px,transparent_1px),linear-gradient(90deg,rgba(0,212,255,0.03)_1px,transparent_1px)] bg-[size:32px_32px] pointer-events-none" />

                                            <div className="flex items-baseline justify-between mb-8 pb-4 border-b border-white/5 relative z-10">
                                                <div className="flex items-center gap-4">
                                                    <div className="w-2 h-8 bg-[#00D4FF] rounded-full shadow-[0_0_15px_rgba(0,212,255,0.8)]" />
                                                    <h3 className="text-xl font-black uppercase tracking-[0.2em] text-white drop-shadow-[0_0_10px_rgba(255,255,255,0.3)]">
                                                        Аналітика: <span className="text-[#00D4FF]">{selectedPizza}</span>
                                                    </h3>
                                                </div>
                                                <div className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em]">
                                                    {shopStats?.length || 0} ТОЧОК ПРОДАЖУ ТА ПРІОРИТЕТІВ
                                                </div>
                                            </div>

                                            {!shopStats ? (
                                                <div className="py-20 flex flex-col items-center gap-6 relative z-10">
                                                    <div className="relative">
                                                        <Activity className="animate-spin text-[#00D4FF] relative z-10 drop-shadow-[0_0_15px_rgba(0,212,255,0.8)]" size={48} />
                                                        <div className="absolute inset-0 bg-[#00D4FF]/20 blur-xl rounded-full animate-pulse" />
                                                    </div>
                                                    <span className="text-xs font-black uppercase tracking-[0.3em] text-[#00D4FF]/60">Отримання даних по магазинах...</span>
                                                </div>
                                            ) : (
                                                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-5 gap-4 relative z-10">
                                                    {[...shopStats]
                                                        .sort((a, b) => (b.avg_sales_day || 0) - (a.avg_sales_day || 0))
                                                        .map((stat, sIdx) => {
                                                            const isDeficit = (stat.stock_now || 0) <= (stat.min_stock || 0);
                                                            const need = Math.max(0, Math.ceil((stat.avg_sales_day * days) + (stat.min_stock || 0) - (stat.stock_now || 0)));

                                                            return (
                                                                <div key={sIdx} className={cn(
                                                                    "rounded-2xl p-5 border transition-all duration-300 flex flex-col justify-between group/shop relative overflow-hidden backdrop-blur-sm",
                                                                    isDeficit
                                                                        ? "bg-[#FF6B6B]/5 border-[#FF6B6B]/20 shadow-[0_0_20px_rgba(255,107,107,0.1)]"
                                                                        : "bg-[#0B0E14]/80 border-white/5 hover:border-white/20 hover:bg-[#141829]"
                                                                )}>
                                                                    {isDeficit && <div className="absolute inset-0 bg-gradient-to-b from-[#FF6B6B]/5 to-transparent pointer-events-none" />}

                                                                    <div className="flex flex-col mb-4 relative z-10">
                                                                        <h5 className="text-xs font-black uppercase tracking-tight text-white/90 group-hover/shop:text-[#00D4FF] transition-colors mb-2 truncate" title={stat.spot_name}>
                                                                            {stat.spot_name}
                                                                        </h5>
                                                                        <div className="flex items-center gap-2">
                                                                            <span className="text-[9px] font-black text-white/40 uppercase tracking-widest">СЕР.ПРОДАЖІ:</span>
                                                                            <span className="text-sm font-mono font-black text-[#00D4FF]">
                                                                                {Number(stat.avg_sales_day || 0).toFixed(1)}
                                                                            </span>
                                                                        </div>
                                                                    </div>

                                                                    <div className="flex items-end justify-between pt-4 border-t border-white/5 relative z-10">
                                                                        <div className="flex flex-col">
                                                                            <span className="text-[8px] font-black text-white/30 uppercase mb-1">ФАКТ</span>
                                                                            <span className={cn("text-xl font-mono font-black leading-none", isDeficit ? "text-[#FF6B6B] drop-shadow-[0_0_8px_rgba(255,107,107,0.5)]" : "text-emerald-500 drop-shadow-[0_0_8px_rgba(16,185,129,0.3)]")}>
                                                                                {stat.stock_now || 0}
                                                                            </span>
                                                                        </div>
                                                                        <div className="flex flex-col items-end">
                                                                            <span className="text-[8px] font-black text-[#00D4FF]/50 uppercase mb-1">ТРЕБА</span>
                                                                            <span className="text-2xl font-mono font-black text-[#00D4FF] leading-none drop-shadow-[0_0_10px_rgba(0,212,255,0.4)]">
                                                                                {need.toFixed(0)}
                                                                            </span>
                                                                        </div>
                                                                    </div>

                                                                    {isDeficit && (
                                                                        <div className="absolute top-2 right-2">
                                                                            <div className="w-2 h-2 bg-[#FF6B6B] rounded-full animate-pulse shadow-[0_0_10px_rgba(255,107,107,0.8)]" />
                                                                        </div>
                                                                    )}
                                                                </div>
                                                            );
                                                        })}
                                                </div>
                                            )}
                                        </div>
                                    )}
                                </div>
                            ))}
                    </div>
                )}
            </div>
        </div>
    );
};

'use client';

import React, { useState, useEffect, useMemo } from 'react';
import { Settings2, TrendingUp, AlertTriangle, Loader2 } from 'lucide-react';
import { createClient } from '@/utils/supabase/client';

interface PlanItem {
    plan_day: number;
    product_name: string;
    quantity: number;
    risk_index: number;
    prod_rank: number;
    plan_metadata: {
        deficit: number;
        avg_sales: number;
        was_inflated: boolean;
    };
}

export default function ProductionSimulator() {
    const [capacity, setCapacity] = useState(320);
    const [days, setDays] = useState<number>(3);
    const [planData, setPlanData] = useState<PlanItem[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    const supabase = createClient();

    useEffect(() => {
        const fetchPlan = async () => {
            setIsLoading(true);
            setError(null);

            try {
                // Виклик RPC-функції Supabase
                const { data, error } = await supabase.rpc('f_plan_production_ndays', {
                    p_days: days,
                    p_capacity: capacity
                });

                if (error) throw error;

                if (data) {
                    setPlanData(data as PlanItem[]);
                }
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            } catch (err: any) {
                console.error('Error fetching plan:', err);
                setError(err.message);
                // У разі помилки можна очистити дані або показати попередні
                setPlanData([]);
            } finally {
                setIsLoading(false);
            }
        };

        // Дебаунс 600мс для зменшення кількості запитів при перетягуванні повзунка
        const timer = setTimeout(() => {
            fetchPlan();
        }, 600);

        return () => clearTimeout(timer);
    }, [capacity, days]);

    // Групування по днях
    const groupedPlan = useMemo(() => {
        return planData.reduce((acc, row) => {
            if (!acc[row.plan_day]) acc[row.plan_day] = [];
            acc[row.plan_day].push(row);
            return acc;
        }, {} as Record<number, PlanItem[]>);
    }, [planData]);

    return (
        <div className="h-full bg-bg-primary p-4 md:p-8 font-sans text-text-primary overflow-y-auto custom-scrollbar">
            <div className="max-w-6xl mx-auto space-y-6">

                {/* Панель управління потужністю */}
                <div className="bg-panel-bg border border-panel-border rounded-2xl shadow-[var(--panel-shadow)] p-6">
                    <div className="flex flex-col md:flex-row md:items-center justify-between mb-6 gap-4">
                        <div>
                            <h2 className="text-xl font-bold text-text-primary flex items-center gap-2 font-[family-name:var(--font-chakra)] uppercase tracking-wide">
                                <Settings2 className="w-6 h-6 text-[#00E0FF]" />
                                Цільова потужність зміни (Capacity)
                            </h2>
                            <p className="text-sm text-text-secondary mt-1 font-[family-name:var(--font-jetbrains)]">
                                Налаштуйте ліміт, щоб побачити перерахунок автозамовлення на 3 дні
                            </p>
                        </div>
                        <div className="text-left md:text-right">
                            <span className="text-4xl font-black text-[#00E0FF] font-[family-name:var(--font-chakra)] drop-shadow-[0_0_10px_rgba(0,224,255,0.3)]">
                                {capacity} <span className="text-lg text-text-secondary font-medium font-sans">шт.</span>
                            </span>
                        </div>
                    </div>

                    <div className="relative pt-2">
                        <input
                            type="range"
                            min="280"
                            max="380"
                            step="10"
                            value={capacity}
                            onChange={(e) => setCapacity(Number(e.target.value))}
                            className="w-full h-2 bg-panel-border rounded-full appearance-none cursor-pointer accent-[#00E0FF] focus:outline-none focus:ring-2 focus:ring-[#00E0FF]"
                        />
                        <div className="flex justify-between text-[11px] text-text-secondary mt-3 font-bold px-1 uppercase tracking-widest font-[family-name:var(--font-jetbrains)]">
                            <span>280 (Мін)</span>
                            <span>300</span>
                            <span className="text-[#00E0FF] font-black drop-shadow-[0_0_5px_rgba(0,224,255,0.5)]">320 (Норма)</span>
                            <span>340</span>
                            <span>360</span>
                            <span>380 (Макс)</span>
                        </div>
                    </div>

                    {/* Horizon Selector */}
                    <div className="flex flex-col sm:flex-row sm:items-center gap-4 pt-5 border-t border-panel-border mt-5">
                        <span className="text-sm font-bold text-text-primary uppercase tracking-wider flex items-center gap-2 font-[family-name:var(--font-jetbrains)]">
                            <TrendingUp size={16} className="text-[#00E0FF]" />
                            Горизонт планування:
                        </span>
                        <div className="flex gap-2">
                            {[1, 2, 3, 4, 5].map(d => (
                                <button
                                    key={d}
                                    onClick={() => setDays(d)}
                                    className={`px-4 py-1.5 text-xs font-black rounded-lg transition-all border tracking-widest font-[family-name:var(--font-jetbrains)] ${days === d
                                        ? 'bg-[#00E0FF]/10 border-[#00E0FF]/50 text-[#00E0FF] shadow-[0_0_10px_rgba(0,224,255,0.2)]'
                                        : 'bg-bg-primary border-panel-border text-text-secondary hover:text-text-primary hover:border-text-muted hover:bg-panel-border/30'
                                        }`}
                                >
                                    {d} {d === 1 ? 'ДЕНЬ' : 'ДНІ'}
                                </button>
                            ))}
                        </div>
                    </div>
                </div>

                {/* Помилка */}
                {error && (
                    <div className="bg-red-500/10 border border-red-500/30 rounded-2xl p-4 flex items-center gap-3 text-red-400 font-[family-name:var(--font-jetbrains)] backdrop-blur-sm">
                        <AlertTriangle className="w-5 h-5 flex-shrink-0" />
                        <span className="font-bold text-sm">Помилка: {error}</span>
                    </div>
                )}

                {/* Результати (Таблиці по днях) */}
                <div className="grid gap-6 lg:grid-cols-3 relative min-h-[400px]">
                    {/* Індикатор завантаження */}
                    {isLoading && (
                        <div className="absolute inset-0 z-10 bg-bg-primary/60 backdrop-blur-[2px] rounded-2xl flex items-center justify-center transition-all duration-300">
                            <div className="flex flex-col items-center gap-3 text-orange-500 bg-panel-bg px-8 py-6 rounded-2xl shadow-[var(--panel-shadow)] border border-panel-border">
                                <Loader2 className="w-8 h-8 animate-spin" />
                                <span className="text-xs font-bold tracking-widest uppercase font-[family-name:var(--font-jetbrains)] text-text-primary">Перерахунок плану...</span>
                            </div>
                        </div>
                    )}

                    {Array.from({ length: days }, (_, i) => i + 1).map((day) => {
                        const dayPlan = groupedPlan[day] || [];
                        const totalForDay = dayPlan.reduce((sum, item) => sum + item.quantity, 0);

                        return (
                            <div key={day} className="bg-panel-bg border border-panel-border rounded-2xl shadow-[var(--panel-shadow)] overflow-hidden flex flex-col">
                                <div className="p-4 border-b border-panel-border bg-[#131B2C]/50 flex items-center justify-between">
                                    <h3 className="font-bold text-text-primary flex items-center gap-2 font-[family-name:var(--font-chakra)] text-lg uppercase tracking-wide">
                                        <div className="w-7 h-7 rounded-lg bg-[#00E0FF]/10 text-[#00E0FF] border border-[#00E0FF]/30 flex items-center justify-center font-bold text-sm shadow-[0_0_8px_rgba(0,224,255,0.15)]">
                                            Д{day}
                                        </div>
                                        Зміна {day}
                                    </h3>
                                    <div className="text-sm font-black text-orange-400 bg-orange-500/10 px-3 py-1 rounded-full border border-orange-500/20 shadow-[0_0_10px_rgba(255,138,0,0.1)] font-[family-name:var(--font-jetbrains)]">
                                        {totalForDay > 0 ? `${totalForDay} шт` : '—'}
                                    </div>
                                </div>

                                <div className="flex-1 p-2 overflow-y-auto max-h-[600px] custom-scrollbar">
                                    {dayPlan.length === 0 && !isLoading ? (
                                        <div className="flex items-center justify-center h-32 text-text-muted text-xs uppercase tracking-widest font-[family-name:var(--font-jetbrains)] font-bold">
                                            Немає даних
                                        </div>
                                    ) : (
                                        <ul className="space-y-1">
                                            {dayPlan.map((row, idx) => (
                                                <li key={idx} className="flex items-center justify-between p-3 rounded-xl hover:bg-bg-primary transition-colors border border-transparent hover:border-panel-border group">
                                                    <div className="flex flex-col">
                                                        <span className="font-bold text-text-primary text-sm group-hover:text-[#00E0FF] transition-colors leading-tight">
                                                            {row.product_name}
                                                        </span>
                                                        <div className="flex items-center gap-2 mt-2 leading-none">
                                                            <span className="text-[10px] text-text-secondary font-mono tracking-wide px-1.5 py-0.5 rounded bg-panel-border/30 border border-panel-border">
                                                                R: {row.risk_index}
                                                            </span>
                                                            {row.plan_metadata?.was_inflated && (
                                                                <span className="inline-flex items-center gap-1 px-1.5 py-0.5 rounded text-[9px] font-black bg-emerald-500/10 text-emerald-400 uppercase tracking-widest border border-emerald-500/20">
                                                                    <TrendingUp className="w-2.5 h-2.5" /> +20
                                                                </span>
                                                            )}
                                                        </div>
                                                    </div>
                                                    <div className="text-right pl-3 flex-shrink-0">
                                                        <span className="text-lg font-black text-orange-400 tabular-nums font-[family-name:var(--font-chakra)] p-2">
                                                            {row.quantity}
                                                        </span>
                                                    </div>
                                                </li>
                                            ))}
                                        </ul>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                </div>

            </div>
        </div>
    );
}

import React from 'react';
import { X, TrendingUp } from 'lucide-react';
import { cn } from '@/lib/utils';

interface DrawerProps {
    isOpen: boolean;
    onClose: () => void;
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    store: any | null; // Store object from PizzaPowerMatrix (storesGrouped context)
}

export function StoreDetailDrawer({ isOpen, onClose, store }: DrawerProps) {
    if (!isOpen || !store) {
        return null; // Don't render if not open or no store
    }

    const { products = [] } = store;

    // Handle closing when clicking outside the panel
    const handleBackdropClick = (e: React.MouseEvent) => {
        if (e.target === e.currentTarget) {
            onClose();
        }
    };

    return (
        <div
            className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-md transition-opacity p-4 lg:p-8"
            onClick={handleBackdropClick}
        >
            <div
                className="w-full max-w-[1400px] h-auto max-h-[90vh] rounded-2xl overflow-hidden bg-[#112240]/95 backdrop-blur-md border border-[#00E0FF]/20 shadow-[0_0_30px_rgba(0,224,255,0.15)] flex flex-col transform transition-transform animate-in zoom-in-95 duration-200"
            >
                {/* HEAD */}
                <div className="flex items-start justify-between p-5 px-8 border-b border-[#00E0FF]/10 shrink-0">
                    <div className="flex items-center gap-12">
                        <div className="flex flex-col justify-center">
                            <div className="text-[10px] text-[#00E0FF] font-bold uppercase tracking-[0.2em] flex items-center gap-2 font-[family-name:var(--font-jetbrains)]">
                                <span>Деталі локації</span>
                            </div>
                            <h2 className="text-3xl font-bold text-white uppercase tracking-wider leading-none mt-2 font-[family-name:var(--font-chakra)]">
                                {store.storeName.replace('Магазин ', '').replace(/"/g, '')}
                            </h2>
                        </div>

                        {/* Summary Metrics Inline with Title */}
                        <div className="flex items-center gap-6 mt-2">
                            <div className="flex flex-col justify-end">
                                <div className="text-[9px] uppercase font-bold text-slate-400 tracking-[0.2em] mb-1 font-[family-name:var(--font-jetbrains)]">Факт Залишок</div>
                                <div className={cn(
                                    "text-3xl font-mono font-black leading-none flex items-baseline gap-1 font-[family-name:var(--font-jetbrains)]",
                                    store.criticalProducts > 0 ? "text-status-critical drop-shadow-[0_0_8px_rgba(255,42,85,0.5)]" : "text-status-success drop-shadow-[0_0_8px_rgba(16,185,129,0.3)]"
                                )}>
                                    {store.totalStock.toFixed(0)} <span className="text-[11px] font-bold text-slate-500 font-[family-name:var(--font-jetbrains)] uppercase tracking-wider">шт</span>
                                </div>
                            </div>
                            <div className="w-px h-10 bg-white/10 hidden md:block"></div>
                            <div className="flex flex-col justify-end">
                                <div className="text-[9px] uppercase font-bold text-slate-400 tracking-[0.2em] mb-1 font-[family-name:var(--font-jetbrains)]">Крит. Дефіцити</div>
                                <div className={cn(
                                    "text-3xl font-mono font-black leading-none flex items-baseline gap-1 font-[family-name:var(--font-jetbrains)]",
                                    store.criticalProducts > 0 ? "text-status-critical drop-shadow-[0_0_8px_rgba(255,42,85,0.5)]" : "text-slate-300"
                                )}>
                                    {store.criticalProducts} <span className="text-[11px] font-bold text-slate-500 font-[family-name:var(--font-jetbrains)] uppercase tracking-wider">позицій</span>
                                </div>
                            </div>
                            <div className="w-px h-10 bg-white/10 hidden md:block"></div>
                            <div className="flex flex-col justify-end">
                                <div className="text-[9px] uppercase font-bold text-[#00E0FF] tracking-[0.2em] mb-1 font-[family-name:var(--font-jetbrains)] flex items-center gap-1">
                                    <TrendingUp size={10} /> Середні продажі
                                </div>
                                <div className="text-3xl font-mono font-black text-[#00E0FF] leading-none flex items-baseline gap-1 font-[family-name:var(--font-jetbrains)] drop-shadow-[0_0_8px_rgba(0,224,255,0.4)]">
                                    {store.totalAvgSales.toFixed(0)} <span className="text-[11px] font-bold text-[#00E0FF]/50 font-[family-name:var(--font-jetbrains)] uppercase tracking-wider">шт/день</span>
                                </div>
                            </div>
                        </div>
                    </div>

                    <button
                        onClick={onClose}
                        className="p-3 rounded-xl bg-panel-border/30 text-text-muted hover:text-text-primary hover:bg-panel-border/50 transition-colors mt-2"
                    >
                        <X size={20} />
                    </button>
                </div>

                {/* PRODUCTS GRID */}
                <div className="flex-1 overflow-y-auto custom-scrollbar p-6">
                    <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-3">
                        // eslint-disable-next-line @typescript-eslint/no-explicit-any
                        {products.sort((a: any, b: any) => b.avg - a.avg).map((prod: any) => {
                            const isLowStock = prod.isUrgent;

                            return (
                                <div
                                    key={prod.productCode}
                                    className={cn(
                                        "rounded-xl p-4 flex flex-col gap-2 transition-all duration-300 relative overflow-hidden group hover:shadow-[0_0_20px_rgba(0,224,255,0.15)]",
                                        isLowStock
                                            ? "bg-status-critical/5 border border-status-critical/30 shadow-[0_0_15px_rgba(255,42,85,0.1)] hover:border-status-critical/50"
                                            : "bg-[#0A1931]/60 border border-[#00E0FF]/10 shadow-[0_0_15px_rgba(16,185,129,0.05)] hover:border-[#00E0FF]/30"
                                    )}
                                >
                                    <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-b from-transparent via-white/20 to-transparent opacity-0 group-hover:opacity-100 animate-scan pointer-events-none"></div>

                                    {/* Product Name */}
                                    <div
                                        className="text-sm font-semibold text-white uppercase tracking-wider text-center font-[family-name:var(--font-chakra)] line-clamp-2 min-h-[2.5em] flex items-center justify-center"
                                        title={prod.productName}
                                    >
                                        {prod.productName}
                                    </div>

                                    {/* Metrics Row */}
                                    <div className="grid grid-cols-3 gap-2 mt-2">
                                        <div className="flex flex-col items-center">
                                            <span className="text-[9px] font-bold tracking-[0.2em] text-slate-400 mb-1 uppercase font-[family-name:var(--font-jetbrains)]">Факт</span>
                                            <span className={cn(
                                                "text-lg font-bold font-[family-name:var(--font-jetbrains)] leading-none",
                                                isLowStock ? "text-status-critical drop-shadow-[0_0_8px_rgba(255,42,85,0.5)]" : "text-status-success drop-shadow-[0_0_8px_rgba(16,185,129,0.3)]"
                                            )}>
                                                {prod.stock.toFixed(0)}
                                            </span>
                                        </div>
                                        <div className="flex flex-col items-center">
                                            <span className="text-[9px] font-bold tracking-[0.2em] text-slate-400 mb-1 uppercase font-[family-name:var(--font-jetbrains)]">Мін</span>
                                            <span className="text-lg font-bold font-[family-name:var(--font-jetbrains)] leading-none text-slate-300">
                                                {prod.minStock.toFixed(0)}
                                            </span>
                                        </div>
                                        <div className="flex flex-col items-center">
                                            <span className="text-[9px] font-bold tracking-[0.2em] text-slate-400 mb-1 uppercase font-[family-name:var(--font-jetbrains)]">Сер</span>
                                            <span className="text-lg font-bold font-[family-name:var(--font-jetbrains)] leading-none text-[#00E0FF]">
                                                {prod.avg.toFixed(1)}
                                            </span>
                                        </div>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>
            </div>
        </div>
    );
}

'use client';

import React from 'react';
import { cn } from '@/lib/utils';

// ===== Base Skeleton =====

interface SkeletonProps {
    className?: string;
    /** Animation style */
    animation?: 'pulse' | 'shimmer' | 'none';
    /** Custom inline styles */
    style?: React.CSSProperties;
}

export const Skeleton = ({ className, animation = 'shimmer', style }: SkeletonProps) => {
    return (
        <div
            className={cn(
                'bg-white/5 rounded-lg',
                animation === 'pulse' && 'animate-pulse',
                animation === 'shimmer' && 'relative overflow-hidden',
                className
            )}
            style={style}
        >
            {animation === 'shimmer' && (
                <div
                    className="absolute inset-0 -translate-x-full"
                    style={{
                        background: 'linear-gradient(90deg, transparent, rgba(255,255,255,0.08), transparent)',
                        animation: 'shimmer 1.5s infinite',
                    }}
                />
            )}
        </div>
    );
};

// ===== Skeleton Text =====

interface SkeletonTextProps {
    lines?: number;
    className?: string;
    lastLineWidth?: string;
}

export const SkeletonText = ({ lines = 3, className, lastLineWidth = '60%' }: SkeletonTextProps) => {
    return (
        <div className={cn('space-y-2', className)}>
            {Array.from({ length: lines }).map((_, i) => (
                <Skeleton
                    key={i}
                    className="h-4"
                    style={{ width: i === lines - 1 ? lastLineWidth : '100%' } as React.CSSProperties}
                />
            ))}
        </div>
    );
};

// ===== Skeleton Card =====

export const SkeletonCard = ({ className }: { className?: string }) => {
    return (
        <div className={cn(
            'bg-white/[0.02] border border-white/5 rounded-xl p-4 space-y-4',
            className
        )}>
            <div className="flex items-center gap-3">
                <Skeleton className="w-10 h-10 rounded-lg" />
                <div className="flex-1 space-y-2">
                    <Skeleton className="h-4 w-3/4" />
                    <Skeleton className="h-3 w-1/2" />
                </div>
            </div>
            <SkeletonText lines={2} />
        </div>
    );
};

// ===== Skeleton Table =====

interface SkeletonTableProps {
    rows?: number;
    columns?: number;
    className?: string;
}

export const SkeletonTable = ({ rows = 5, columns = 4, className }: SkeletonTableProps) => {
    return (
        <div className={cn('bg-white/[0.02] border border-white/5 rounded-xl overflow-hidden', className)}>
            {/* Header */}
            <div className="flex gap-4 p-4 bg-white/[0.02] border-b border-white/5">
                {Array.from({ length: columns }).map((_, i) => (
                    <Skeleton key={i} className="h-4 flex-1" />
                ))}
            </div>
            {/* Rows */}
            <div className="divide-y divide-white/[0.03]">
                {Array.from({ length: rows }).map((_, rowIndex) => (
                    <div key={rowIndex} className="flex gap-4 p-4">
                        {Array.from({ length: columns }).map((_, colIndex) => (
                            <Skeleton
                                key={colIndex}
                                className="h-4 flex-1"
                                style={{ animationDelay: `${(rowIndex * columns + colIndex) * 50}ms` } as React.CSSProperties}
                            />
                        ))}
                    </div>
                ))}
            </div>
        </div>
    );
};

